def _safe_json_body() -> Dict[str, Any]:
    data = request.get_json(silent=True)
    if isinstance(data, dict):
        return data
    if request.form:
        out: Dict[str, Any] = {}
        for k in request.form.keys():
            vals = request.form.getlist(k)
            out[k] = vals if len(vals) > 1 else (vals[0] if vals else "")
        return out
    return {}
def _line_count(text_value: Any) -> int:
    return len([x for x in str(text_value or "").replace(",", "\n").splitlines() if x.strip()])
def _action_summary(path: str, payload: Dict[str, Any]) -> str:
    if not payload:
        return ""
    if path == "/create_campaign":
        return f"이름={str(payload.get('name') or '').strip()}"
    if path == "/create_adgroup_simple":
        return f"이름={str(payload.get('name') or '').strip()} | 캠페인={str(payload.get('campaign_id') or '').strip()}"
    if path == "/create_keywords_simple":
        if isinstance(payload.get('keyword_batches'), list):
            batches = payload.get('keyword_batches') or []
            def _batch_keyword_text(item):
                item = item or {}
                return item.get('keywords') if item.get('keywords') is not None else item.get('keywords_text')
            slot_cnt = sum(1 for x in batches if str((x or {}).get('adgroup_id') or '').strip() and str(_batch_keyword_text(x) or '').strip())
            kw_cnt = sum(_line_count(_batch_keyword_text(x)) for x in batches)
            return f"입력묶음={slot_cnt} | 키워드={kw_cnt}" if slot_cnt > 1 else f"키워드={kw_cnt}"
        keyword_text = payload.get('keywords') if payload.get('keywords') is not None else payload.get('keywords_text')
        return f"키워드={_line_count(keyword_text)}"
    if path in {"/copy_campaigns", "/copy_adgroups_to_target", "/copy_entities_to_adgroups"}:
        src = payload.get('source_ids') or payload.get('entity_ids') or []
        if not isinstance(src, list):
            src = [src] if src else []
        src_campaigns = payload.get('source_campaign_ids') or []
        if not isinstance(src_campaigns, list):
            src_campaigns = [src_campaigns] if src_campaigns else []
        target_adgroups = payload.get('target_adgroup_ids') or []
        if not isinstance(target_adgroups, list):
            target_adgroups = [target_adgroups] if target_adgroups else []
        target_campaigns = payload.get('target_campaign_ids') or []
        if not isinstance(target_campaigns, list):
            target_campaigns = [target_campaigns] if target_campaigns else []
        custom_cnt = _line_count(payload.get('custom_names_text'))
        pieces = [f"대상={len(src)}"]
        if src_campaigns:
            pieces.append(f"원본캠페인={len(src_campaigns)}")
        if target_adgroups:
            pieces.append(f"타겟그룹={len(target_adgroups)}")
        if target_campaigns:
            pieces.append(f"타겟캠페인선택={len(target_campaigns)}")
        if str(payload.get('copy_count') or '').strip():
            pieces.append(f"복사수={payload.get('copy_count')}")
        if custom_cnt:
            pieces.append(f"지정명={custom_cnt}")
        if _boolish(payload.get('exclude_off_assets'), False):
            pieces.append("OFF소재제외=Y")
        tgt = str(payload.get('target_campaign_id') or '').strip()
        if tgt:
            pieces.append(f"타겟캠페인={tgt}")
        return " | ".join(pieces)
    if path == "/rename_adgroups_bulk":
        ids = payload.get('entity_ids') or []
        if not isinstance(ids, list):
            ids = [ids] if ids else []
        return f"그룹={len(ids)} | 새이름={_line_count(payload.get('target_names_text'))}"
    if path == "/set_asset_state_by_ids":
        ids = payload.get('ids') or []
        if not isinstance(ids, list):
            ids = [ids] if ids else []
        if not ids and str(payload.get('raw_text') or '').strip():
            ids = [x for x in re.split(r"[\s,;]+", str(payload.get('raw_text') or '')) if x.strip()]
        enabled_label = "ON" if _boolish(payload.get('enabled'), True) else "OFF"
        entity_label = "확장소재" if str(payload.get('entity_type') or '').strip().lower() in {"ad_extension", "extension", "ext"} else "소재"
        return f"{entity_label} {enabled_label} | ID={len(ids)}"
    if path == "/bulk_delete_asset_ids":
        ids = payload.get('ids') or []
        if not isinstance(ids, list):
            ids = [ids] if ids else []
        if not ids and str(payload.get('raw_text') or '').strip():
            ids = [x for x in re.split(r"[\s,;]+", str(payload.get('raw_text') or '')) if x.strip()]
        entity_label = "확장소재" if str(payload.get('entity_type') or '').strip().lower() in {"ad_extension", "extension", "ext"} else "소재"
        return f"{entity_label} 삭제 | ID={len(ids)}"
    if path == "/update_ad_product_name":
        return f"소재ID={str(payload.get('ad_id') or '').strip()} | 상품명={str(payload.get('product_name') or '').strip()[:40]}"
    if path == "/update_ad_product_names_bulk":
        rows = payload.get("rows") or []
        return f"그룹={len(rows)} | 상품명 대량 변경"
    if path == "/bulk_update_ad_product_names_csv":
        file_names = []
        try:
            file_names = [f.filename for f in request.files.values() if getattr(f, 'filename', '')]
        except Exception:
            file_names = []
        return (f"소재ID 기준 상품명 대량 변경 | 파일={', '.join(file_names[:2])}" if file_names else "소재ID 기준 상품명 대량 변경 | 파일 업로드")
    if path == "/update_shopping_ad_bid":
        return f"소재ID={str(payload.get('ad_id') or '').strip()} | 입찰가={payload.get('bid_amt')}"
    if path in {"/set_ads_state_by_scope", "/set_ad_extensions_state_by_scope", "/set_asset_state_by_ids"}:
        camp_ids = payload.get('campaign_ids') or []
        adg_ids = payload.get('adgroup_ids') or []
        if not isinstance(camp_ids, list):
            camp_ids = [camp_ids] if camp_ids else []
        if not isinstance(adg_ids, list):
            adg_ids = [adg_ids] if adg_ids else []
        enabled_label = "ON" if _boolish(payload.get('enabled'), True) else "OFF"
        type_key = 'ad_types' if path == "/set_ads_state_by_scope" else 'ext_types'
        types = payload.get(type_key) or []
        if not isinstance(types, list):
            types = [types] if types else []
        return f"{enabled_label} | 캠페인={len(camp_ids)} | 그룹={len(adg_ids)} | 유형={','.join([str(x) for x in types[:6]]) or 'ALL'}"
    if path == "/set_keywords_state_by_scope":
        camp_ids = payload.get('campaign_ids') or []
        adg_ids = payload.get('adgroup_ids') or []
        if not isinstance(camp_ids, list):
            camp_ids = [camp_ids] if camp_ids else []
        if not isinstance(adg_ids, list):
            adg_ids = [adg_ids] if adg_ids else []
        enabled_label = "ON" if _boolish(payload.get('enabled'), True) else "OFF"
        return f"{enabled_label} | 캠페인={len(camp_ids)} | 그룹={len(adg_ids)}"
    if path in {"/update_budget", "/set_campaign_state", "/set_adgroup_state_by_scope", "/update_media", "/add_restricted_media_ids", "/copy_restricted_media_settings", "/update_adgroup_options", "/update_adgroup_search_options", "/update_adgroup_bid_amt", "/update_age_targets_bulk", "/update_region_targets_bulk", "/update_schedule", "/update_schedule_campaign_bulk", "/update_non_search_keyword_exclusion", "/update_keyword_bids", "/update_bid_mode_by_scope", "/update_keyword_bids_by_search", "/update_keyword_bid_weights_by_search", "/adjust_keyword_bids_by_threshold", "/update_keyword_bids_avg_position", "/preview_keyword_avg_position_by_search", "/update_keyword_avg_position_by_search", "/update_powerlink_device_bid_weights", "/update_contents_network_bid_amt", "/set_keywords_state_by_scope", "/set_ads_state_by_scope", "/set_ad_extensions_state_by_scope", "/set_asset_state_by_ids"}:
        ids = payload.get('entity_ids') or payload.get('campaign_ids') or payload.get('adgroup_ids') or []
        if not isinstance(ids, list):
            ids = [ids] if ids else []
        label = str(payload.get('entity_type') or payload.get('media_type') or '').strip()
        extra = []
        if label:
            extra.append(label)
        if ids:
            extra.append(f"건수={len(ids)}")
        if str(payload.get('search_text') or '').strip():
            if _boolish(payload.get('exact_match'), False):
                match_label = "완전일치"
            else:
                match_label = "부분일치·지명경계" if _boolish(payload.get('boundary_match', payload.get('korean_boundary_match')), False) else "부분일치"
            extra.append(f"검색={str(payload.get('search_text') or '').strip()} ({match_label})")
        if str(payload.get('bid_amt') or '').strip():
            extra.append(f"입찰가={payload.get('bid_amt')}")
        if str(payload.get('contents_network_bid_amt') or '').strip():
            extra.append(f"콘텐츠입찰가={payload.get('contents_network_bid_amt')}")
        if path == "/update_age_targets_bulk":
            mode_label = "선택제외" if str(payload.get("mode") or "include_selected") == "exclude_selected" else "선택노출"
            age_codes = payload.get("age_codes") or []
            if not isinstance(age_codes, list):
                age_codes = [age_codes] if age_codes else []
            extra.append(f"연령={mode_label}:{len(age_codes)}개")
            if str(payload.get("bid_weight") or "").strip():
                extra.append(f"가중치={payload.get('bid_weight')}%")
        if path == "/update_region_targets_bulk":
            region_mode = str(payload.get("mode") or "include_selected")
            mode_label = {"all": "모든지역", "include_selected": "선택노출", "exclude_selected": "선택제외"}.get(region_mode, region_mode)
            region_codes = payload.get("region_codes") or []
            if not isinstance(region_codes, list):
                region_codes = [region_codes] if region_codes else []
            extra.append(f"지역={mode_label}:{len(region_codes)}개")
        overrides = payload.get('keyword_bid_overrides') or payload.get('bid_overrides') or []
        if isinstance(overrides, list) and overrides:
            extra.append(f"개별입찰가={len(overrides)}건")
        schedule_blocks_for_summary = payload.get('scheduleBlocks') or []
        if isinstance(schedule_blocks_for_summary, list) and schedule_blocks_for_summary:
            block_weights = []
            for block in schedule_blocks_for_summary:
                if not isinstance(block, dict):
                    continue
                raw_weight = str(block.get("bidWeight") or "").strip()
                if raw_weight and raw_weight not in block_weights:
                    block_weights.append(raw_weight)
            if block_weights:
                extra.append(f"구간가중치={','.join(block_weights[:6])}%")
        elif str(payload.get('bid_weight') or payload.get('bidWeight') or '').strip():
            extra.append(f"입찰가중치={payload.get('bid_weight') or payload.get('bidWeight')}%")
        if str(payload.get('pc_bid_weight') or '').strip():
            extra.append(f"PC={payload.get('pc_bid_weight')}%")
        if str(payload.get('mobile_bid_weight') or '').strip():
            extra.append(f"MO={payload.get('mobile_bid_weight')}%")
        return " | ".join(extra)
    if path in {"/bulk_delete", "/delete_selected"}:
        rows = payload.get('rows') or payload.get('ids') or []
        if not isinstance(rows, list):
            rows = [rows] if rows else []
        return f"유형={str(payload.get('entity_type') or '').strip()} | 건수={len(rows)}"
    if path == "/bulk_delete_by_parent":
        parent_ids = payload.get('parent_ids') or []
        if not isinstance(parent_ids, list):
            parent_ids = [parent_ids] if parent_ids else []
        campaign_ids = payload.get('campaign_ids') or []
        adgroup_ids = payload.get('adgroup_ids') or []
        if not isinstance(campaign_ids, list):
            campaign_ids = [campaign_ids] if campaign_ids else []
        if not isinstance(adgroup_ids, list):
            adgroup_ids = [adgroup_ids] if adgroup_ids else []
        if campaign_ids or adgroup_ids:
            return f"대상={str(payload.get('target_entity') or '').strip()} | 캠페인={len(campaign_ids)} | 광고그룹={len(adgroup_ids)}"
        return f"범위={str(payload.get('parent_type') or '').strip()} | 대상={str(payload.get('target_entity') or '').strip()} | 부모={len(parent_ids)}"
    if path == "/bulk_register":
        rows = payload.get('rows') or []
        if not isinstance(rows, list):
            rows = [rows] if rows else []
        return f"유형={str(payload.get('entity_type') or '').strip()} | 건수={len(rows)}"
    if path == "/create_restricted_keywords_simple":
        keyword_text = payload.get('keywords') if payload.get('keywords') is not None else payload.get('keywords_text')
        return f"제외키워드={_line_count(keyword_text)}"
    if path in {"/bulk_upload_text_ads", "/bulk_upload_rsa_ads", "/bulk_upload_shopping_products", "/bulk_upload_powerlink_bundle", "/bulk_update_shopping_ad_bids", "/bulk_update_shopping_product_ad_bids", "/bulk_update_ad_product_names_csv", "/bulk_update_contents_network_bid_amt", "/bulk_upload_headlines", "/bulk_upload_extensions", "/bulk_delete_powerlink_ads_excel", "/bulk_delete_extensions_excel"}:
        file_names = []
        try:
            file_names = [f.filename for f in request.files.values() if getattr(f, 'filename', '')]
        except Exception:
            file_names = []
        if path == "/bulk_upload_shopping_products":
            return (f"쇼핑검색 상품 대량등록 | 파일={', '.join(file_names[:2])}" if file_names else "쇼핑검색 상품 대량등록")
        if path == "/bulk_upload_powerlink_bundle":
            return (f"파워링크 대량등록 | 파일={', '.join(file_names[:2])}" if file_names else "파워링크 대량등록")
        if path == "/bulk_update_shopping_ad_bids":
            return (f"쇼핑 소재 입찰가 대량 변경 | 파일={', '.join(file_names[:2])}" if file_names else "쇼핑 소재 입찰가 대량 변경")
        if path == "/bulk_update_shopping_product_ad_bids":
            return (f"쇼핑 상품 소재 입찰가 대량 변경 | 파일={', '.join(file_names[:2])}" if file_names else "쇼핑 상품 소재 입찰가 대량 변경")
        if path == "/bulk_update_ad_product_names_csv":
            return (f"소재ID 기준 상품명 대량 변경 | 파일={', '.join(file_names[:2])}" if file_names else "소재ID 기준 상품명 대량 변경")
        if path == "/bulk_update_contents_network_bid_amt":
            return (f"추천/콘텐츠 지면 입찰가 대량 변경 | 파일={', '.join(file_names[:2])}" if file_names else "추천/콘텐츠 지면 입찰가 대량 변경")
        if path == "/bulk_delete_powerlink_ads_excel":
            return (f"파워링크 소재ID 삭제 | 파일={', '.join(file_names[:2])}" if file_names else "파워링크 소재ID 삭제 | 파일 업로드")
        if path == "/bulk_delete_extensions_excel":
            return (f"확장소재ID 삭제 | 파일={', '.join(file_names[:2])}" if file_names else "확장소재ID 삭제 | 파일 업로드")
        if path == "/bulk_upload_extensions":
            ext_label = _bulk_upload_ext_type_label(payload.get("ext_type") or payload.get("extension_type") or "")
            return (f"{ext_label} 대량등록 | 파일={', '.join(file_names[:2])}" if file_names else f"{ext_label} 대량등록 | 파일 업로드")
        return f"파일={', '.join(file_names[:2])}" if file_names else "파일 업로드"
    count_keys = ('ids', 'entity_ids', 'source_ids', 'campaign_ids', 'adgroup_ids', 'parent_ids', 'rows')
    for key in count_keys:
        val = payload.get(key)
        if isinstance(val, list) and val:
            return f"건수={len(val)}"
    return ""
def _short_log_text(value: Any, limit: int = _ACTION_LOG_DETAIL_TEXT_LIMIT) -> str:
    text = str(value or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    text = re.sub(r"\s+\n", "\n", text)
    text = re.sub(r"[ \t]{2,}", " ", text)
    if len(text) > limit:
        return text[: max(0, limit - 1)].rstrip() + "…"
    return text


def _response_json_dict(response: Response) -> Dict[str, Any]:
    try:
        if response.is_json:
            data = response.get_json(silent=True) or {}
            if isinstance(data, dict):
                return data
    except Exception:
        pass
    return {}


def _extract_response_message(response: Response, data: Dict[str, Any] | None = None) -> str:
    try:
        payload = data if isinstance(data, dict) else _response_json_dict(response)
        if isinstance(payload, dict):
            value = payload.get("message")
            if value is None:
                value = payload.get("error")
            if value is None:
                value = payload.get("details")
            if isinstance(value, list):
                return "\n".join(_short_log_text(x, 180) for x in value[:10] if str(x or "").strip())
            return _short_log_text(value, 1200)
    except Exception:
        pass
    return ""


def _log_detail_level(ok_value: Any, text: str = "") -> str:
    if isinstance(ok_value, bool):
        return "success" if ok_value else "fail"
    raw = str(text or "")
    lower = raw.lower()
    failure_probe = re.sub(r"실패\s*[:：]?\s*0\s*(건|개)?", "", raw, flags=re.IGNORECASE)
    failure_probe = re.sub(r"fail(?:ed|ure)?s?\s*[:：]?\s*0\b", "", failure_probe, flags=re.IGNORECASE)
    failure_lower = failure_probe.lower()
    if any(token in failure_lower for token in ("실패", "error", "exception", "오류", "에러", "불일치", "not support", "invalid", "fail", "한도 초과", "초과했습니다")):
        return "fail"
    if any(token in lower for token in ("경고", "warning")):
        return "warning"
    if any(token in lower for token in ("완료", "성공", "등록됨", "생성됨", "변경됨", "적용됨")):
        return "success"
    if any(token in lower for token in ("건너", "skip", "없음", "미지원", "유지", "생략", "대상 없음")):
        return "skip"
    if "제외" in lower and not any(token in lower for token in ("완료", "성공", "적용")):
        return "skip"
    return "info"


def _explicit_log_detail_level(item: Dict[str, Any], fallback_text: str = "") -> str:
    raw_level = str((item or {}).get("level") or "").strip().lower()
    if raw_level in {"success", "fail", "skip", "warning", "info"}:
        return raw_level
    return _log_detail_level((item or {}).get("ok"), fallback_text)


def _result_identifier(item: Dict[str, Any]) -> str:
    if not isinstance(item, dict):
        return ""
    candidates = [
        "campaign_name", "adgroup_name", "keyword", "name", "title", "headline",
        "campaign_id", "adgroup_id", "nccCampaignId", "nccAdgroupId",
        "nccKeywordId", "keyword_id", "nccAdId", "ad_id",
        "adExtensionId", "ad_extension_id", "ownerId", "id", "target", "label",
    ]
    row_no = item.get("row_no") or item.get("row") or item.get("line_no")
    for key in candidates:
        value = item.get(key)
        if value is not None and str(value).strip():
            ident = _short_log_text(value, 90)
            return _short_log_text(f"{row_no}행 · {ident}", 120) if row_no else ident
    return _short_log_text(f"{row_no}행", 90) if row_no else ""


def _result_detail_text(item: Dict[str, Any]) -> str:
    if not isinstance(item, dict):
        return _short_log_text(item)
    for key in ("detail", "details", "message", "error", "reason", "result", "statusReason", "step"):
        value = item.get(key)
        if value is None or value == "":
            continue
        if isinstance(value, list):
            return " / ".join(_short_log_text(v, 120) for v in value[:4] if str(v or "").strip())
        if isinstance(value, dict):
            return _short_log_text(json.dumps(value, ensure_ascii=False), 600)
        return _short_log_text(value, 600)
    return ""


def _extract_error_code_from_value(value: Any) -> str:
    if value is None or value == "":
        return ""
    if isinstance(value, dict):
        for key in ("code", "errorCode", "error_code", "statusCode", "status_code"):
            raw = value.get(key)
            if raw is not None and str(raw).strip():
                return _short_log_text(raw, 60)
        for key in ("error", "errors", "detail", "details", "message", "reason"):
            nested = _extract_error_code_from_value(value.get(key))
            if nested:
                return nested
        return ""
    if isinstance(value, list):
        for item in value[:5]:
            nested = _extract_error_code_from_value(item)
            if nested:
                return nested
        return ""
    text = str(value or "").strip()
    if not text:
        return ""
    try:
        parsed = json.loads(text)
        nested = _extract_error_code_from_value(parsed)
        if nested:
            return nested
    except Exception:
        pass
    for pattern in [
        r'"(?:errorCode|error_code|code|statusCode|status_code)"\s*:\s*"?(?P<code>[^",}\]\s]+)',
        r"(?:errorCode|error_code|code|statusCode|status_code)\s*[:=]\s*['\"]?(?P<code>[A-Za-z0-9_.-]+)",
    ]:
        match = re.search(pattern, text, flags=re.IGNORECASE)
        if match:
            return _short_log_text(match.group("code"), 60)
    return ""


def _result_error_code(item: Dict[str, Any], detail_text: str = "") -> str:
    if not isinstance(item, dict):
        return _extract_error_code_from_value(detail_text)
    for key in ("code", "errorCode", "error_code", "statusCode", "status_code"):
        value = item.get(key)
        if value is not None and str(value).strip():
            return _short_log_text(value, 60)
    return _extract_error_code_from_value(detail_text or item)


def _make_log_detail(level: str, target: str, detail: str, source: str = "", code: str = "") -> Dict[str, str]:
    return {
        "level": level if level in {"success", "fail", "skip", "warning", "info"} else "info",
        "target": _short_log_text(target, 120),
        "detail": _short_log_text(detail, _ACTION_LOG_DETAIL_TEXT_LIMIT),
        "source": _short_log_text(source, 40),
        "code": _short_log_text(code, 60),
    }


def _append_log_detail(items: List[Dict[str, str]], seen: set, detail: Dict[str, str]) -> None:
    key = (detail.get("level", ""), detail.get("target", ""), detail.get("detail", ""), detail.get("code", ""))
    if key in seen:
        return
    seen.add(key)
    items.append(detail)


def _extract_count_value(data: Dict[str, Any], *keys: str) -> Optional[int]:
    for key in keys:
        value = data.get(key)
        if value is None:
            continue
        try:
            return int(value)
        except Exception:
            continue
    return None


def _extract_action_log_counts(data: Dict[str, Any], payload: Dict[str, Any]) -> Dict[str, Any]:
    results = data.get("results")
    result_items = results if isinstance(results, list) else []

    success = _extract_count_value(data, "success", "success_count", "updated_count", "created_count", "deleted_count")
    fail = _extract_count_value(data, "fail", "fail_count", "failed_count", "error_count")
    child_fail = _extract_count_value(data, "child_fail", "child_fail_count")
    skipped = _extract_count_value(data, "skipped", "skipped_count", "skip_count", "unchanged", "skipped_non_shopping")
    total = _extract_count_value(data, "total", "total_count", "matched_count", "estimated")

    # 복사 작업은 광고그룹/캠페인 생성 자체는 성공했더라도 하위 키워드가
    # 네이버 파워링크 10만개 한도 등에 걸려 실패할 수 있다. 이 경우 UI 본문에는
    # 세부 실패가 보이지만 작업 이력 status가 success로 남지 않도록 별도 실패 수를 반영한다.
    if child_fail is not None:
        try:
            child_fail_n = int(child_fail or 0)
        except Exception:
            child_fail_n = 0
        try:
            fail_n = int(fail or 0) if fail is not None else 0
        except Exception:
            fail_n = 0
        if child_fail_n > 0 and fail_n <= 0:
            fail = child_fail_n

    if result_items:
        if success is None:
            success = sum(1 for item in result_items if isinstance(item, dict) and item.get("ok") is True)
        if fail is None:
            fail = sum(1 for item in result_items if isinstance(item, dict) and item.get("ok") is False)
        if total is None:
            total = len(result_items)

    if total is None:
        for key in ("rows", "ids", "entity_ids", "source_ids", "campaign_ids", "adgroup_ids", "parent_ids"):
            value = payload.get(key)
            if isinstance(value, list) and value:
                total = len(value)
                break

    return {
        "total": total,
        "success": success,
        "fail": fail,
        "skipped": skipped,
    }


def _iter_message_detail_lines(message: str) -> Iterable[str]:
    for raw_line in str(message or "").splitlines():
        line = raw_line.strip()
        if not line or len(line) < 4:
            continue
        if re.match(r"^(범위|검색어|제외어|대상\s|조회한\s|검색\s*일치|키워드\s*스캔)\s*[:：]", line):
            continue
        if re.search(r"(성공|실패|유지|건너뜀|제외)\s*[:：]?\s*\d+\s*(건|개)", line):
            continue
        # 첫 줄의 성공/실패 요약은 이미 별도 count로 보여주므로 세부항목 후보에서 제외한다.
        if re.search(r"실패\s*[:：]?\s*0\s*(건|개)?", line, flags=re.IGNORECASE) and _log_detail_level(None, line) in {"success", "info"}:
            continue
        if any(token in line for token in ("실패", "오류", "조회 실패", "변경 실패", "생성 실패", "삭제 실패", "건너뜀", "제외", "미지원", "불일치", "Not support")):
            yield line


def _split_log_detail_target(text: Any) -> Tuple[str, str]:
    value = _short_log_text(text)
    if not value:
        return "", ""
    bracket = re.match(r"^\[([^\]]{1,180})\]\s*(.*)$", value)
    if bracket:
        return _short_log_text(bracket.group(1), 120), _short_log_text(bracket.group(2) or value)
    lead = re.match(r"^((?:캠페인|광고그룹|키워드|소재|확장소재|owner)\s+[^:：]{1,120}?)(\s+(?:광고그룹|키워드|소재|확장소재|조회|변경|생성|삭제|등록).*)$", value)
    if lead:
        return _short_log_text(lead.group(1), 120), _short_log_text(lead.group(2).strip())
    return "", value


def _extract_action_log_details(data: Dict[str, Any], message: str, limit: Optional[int] = _ACTION_LOG_DETAIL_LIMIT) -> List[Dict[str, str]]:
    items: List[Dict[str, str]] = []
    seen: set = set()

    result_items = data.get("results")
    if isinstance(result_items, list):
        prioritized: List[Tuple[int, Dict[str, Any]]] = []
        for item in result_items:
            if not isinstance(item, dict):
                continue
            detail_text = _result_detail_text(item)
            target = _result_identifier(item)
            level = _explicit_log_detail_level(item, f"{target} {detail_text}")
            priority = 0 if level == "fail" else (1 if level in {"skip", "warning"} else 2)
            prioritized.append((priority, item))
        for _, item in sorted(prioritized, key=lambda x: x[0]):
            detail_text = _result_detail_text(item)
            target = _result_identifier(item)
            if not detail_text and not target:
                continue
            level = _explicit_log_detail_level(item, f"{target} {detail_text}")
            code = _result_error_code(item, detail_text) if level == "fail" else ""
            _append_log_detail(items, seen, _make_log_detail(level, target, detail_text or ("완료" if level == "success" else ""), "results", code))

    for source_key, default_level in [
        ("details", "info"),
        ("errors", "fail"),
        ("warnings", "warning"),
        ("failed_details", "fail"),
        ("err_details", "fail"),
    ]:
        value = data.get(source_key)
        if isinstance(value, list):
            for raw in value:
                text = _short_log_text(raw)
                if not text:
                    continue
                target, detail_text = _split_log_detail_target(text)
                detected_level = _log_detail_level(None, text)
                level = "fail" if default_level == "fail" else ("fail" if default_level == "warning" and detected_level == "fail" else (detected_level if default_level == "info" else default_level))
                code = _extract_error_code_from_value(text) if level == "fail" else ""
                _append_log_detail(items, seen, _make_log_detail(level, target, detail_text, source_key, code))
        elif isinstance(value, str) and value.strip():
            target, detail_text = _split_log_detail_target(value)
            detected_level = _log_detail_level(None, value)
            level = "fail" if default_level == "fail" else ("fail" if default_level == "warning" and detected_level == "fail" else (detected_level if default_level == "info" else default_level))
            code = _extract_error_code_from_value(value) if level == "fail" else ""
            _append_log_detail(items, seen, _make_log_detail(level, target, detail_text, source_key, code))

    for line in _iter_message_detail_lines(message):
        target, detail_text = _split_log_detail_target(line)
        level = _log_detail_level(None, line)
        code = _extract_error_code_from_value(line) if level == "fail" else ""
        _append_log_detail(items, seen, _make_log_detail(level, target, detail_text, "message", code))

    order = {"fail": 0, "warning": 1, "skip": 2, "info": 3, "success": 4}
    sorted_items = sorted(items, key=lambda x: order.get(x.get("level", "info"), 9))
    if limit is None:
        return sorted_items
    return sorted_items[:limit]


def _synthesize_success_log_details_from_payload(payload: Dict[str, Any], counts: Dict[str, Any]) -> List[Dict[str, str]]:
    try:
        fail_count = int(counts.get("fail") or 0)
    except Exception:
        fail_count = 0
    try:
        success_count = int(counts.get("success") or 0)
    except Exception:
        success_count = 0
    if fail_count > 0 or success_count <= 0:
        return []
    candidates: List[str] = []
    for key in ("ids", "entity_ids", "source_ids", "campaign_ids", "adgroup_ids", "parent_ids"):
        value = payload.get(key)
        if isinstance(value, list):
            candidates.extend(str(x or "").strip() for x in value if str(x or "").strip())
    rows = payload.get("rows")
    if isinstance(rows, list):
        for row in rows:
            if not isinstance(row, dict):
                continue
            ident = _result_identifier(row) or str(row.get("keyword") or row.get("name") or "").strip()
            if ident:
                candidates.append(ident)
    if not candidates:
        return []
    out: List[Dict[str, str]] = []
    for target in _unique_keep_order(candidates)[:_ACTION_LOG_DETAIL_LIMIT]:
        out.append(_make_log_detail("success", target, "완료", "payload"))
    return out


def _resolve_action_log_status(http_status: int, counts: Dict[str, Any]) -> str:
    if not (200 <= int(http_status) < 400):
        return "error"
    fail = counts.get("fail")
    success = counts.get("success")
    skipped = counts.get("skipped")
    try:
        fail_n = int(fail) if fail is not None else 0
    except Exception:
        fail_n = 0
    try:
        success_n = int(success) if success is not None else 0
    except Exception:
        success_n = 0
    try:
        skipped_n = int(skipped) if skipped is not None else 0
    except Exception:
        skipped_n = 0
    if fail_n > 0 and (success_n > 0 or skipped_n > 0):
        return "partial"
    if fail_n > 0 and success_n <= 0:
        return "error"
    if skipped_n > 0:
        return "partial"
    return "success"


def _format_action_log_counts(counts: Dict[str, Any]) -> str:
    pieces = []
    for label, key in [("대상", "total"), ("성공", "success"), ("실패", "fail"), ("건너뜀", "skipped")]:
        value = counts.get(key)
        if value is None:
            continue
        try:
            n = int(value)
        except Exception:
            continue
        pieces.append(f"{label} {n}건")
    return " / ".join(pieces)

def _action_log_level_label(level: str) -> str:
    return {"fail": "실패", "warning": "경고", "skip": "건너뜀", "success": "성공", "info": "정보"}.get(str(level or "info"), "정보")


def _action_log_detail_level_counts(row: Dict[str, Any]) -> Dict[str, int]:
    counts = {"success": 0, "fail": 0, "warning": 0, "skip": 0, "info": 0}
    explicit = row.get("detail_level_counts") if isinstance(row, dict) else None
    if isinstance(explicit, dict):
        for key in counts:
            try:
                counts[key] = int(explicit.get(key) or 0)
            except Exception:
                counts[key] = 0
        return counts
    items = row.get("detail_items") if isinstance(row, dict) else []
    if isinstance(items, list):
        for item in items:
            if not isinstance(item, dict):
                continue
            level = str(item.get("level") or "info")
            counts[level if level in counts else "info"] += 1
    return counts


def _format_action_log_details_for_export(row: Dict[str, Any], limit: int = 120) -> str:
    items = row.get("detail_items") if isinstance(row, dict) else []
    if not isinstance(items, list):
        return ""
    lines = []
    for item in items[:limit]:
        if not isinstance(item, dict):
            continue
        level = _action_log_level_label(str(item.get("level") or "info"))
        target = str(item.get("target") or "").strip()
        detail = str(item.get("detail") or "").strip()
        if target and detail:
            lines.append(f"[{level}] {target} - {detail}")
        elif target:
            lines.append(f"[{level}] {target}")
        elif detail:
            lines.append(f"[{level}] {detail}")
    if row.get("detail_truncated"):
        lines.append("… 세부내역 일부 생략")
    return "\n".join(lines)

def _keyword_search_log_target(row: Dict[str, Any], item: Optional[Dict[str, Any]] = None) -> str:
    row = row if isinstance(row, dict) else {}
    item = item if isinstance(item, dict) else {}
    pieces = [
        str(row.get("campaign_name") or "").strip(),
        str(row.get("adgroup_name") or "").strip(),
        str(row.get("keyword") or item.get("keyword") or item.get("nccKeywordId") or "").strip(),
    ]
    label = " > ".join(piece for piece in pieces if piece)
    matched_terms = str(row.get("matched_terms_text") or "").strip()
    if matched_terms:
        label = f"{label} (매칭: {matched_terms})" if label else f"매칭: {matched_terms}"
    return _short_log_text(label or item.get("nccKeywordId") or "키워드", 160)

def _append_keyword_search_log_result(
    results: List[Dict[str, Any]],
    counters: Dict[str, int],
    level: str,
    row: Dict[str, Any],
    item: Optional[Dict[str, Any]],
    detail: str,
) -> None:
    normalized_level = level if level in {"success", "fail", "skip", "warning", "info"} else "info"
    limits = {"fail": 120, "warning": 80, "skip": 80, "success": 80, "info": 40}
    if counters.get(normalized_level, 0) >= limits.get(normalized_level, 40):
        return
    counters[normalized_level] = counters.get(normalized_level, 0) + 1
    results.append({
        "level": normalized_level,
        "target": _keyword_search_log_target(row, item),
        "detail": _short_log_text(detail, 260),
    })

def _prune_action_log_file():
    try:
        if not os.path.exists(ACTION_LOG_PATH):
            return
        with open(ACTION_LOG_PATH, 'r', encoding='utf-8') as fp:
            lines = fp.readlines()
        if len(lines) <= _ACTION_LOG_MAX_LINES:
            return
        keep = lines[-_ACTION_LOG_MAX_LINES:]
        with open(ACTION_LOG_PATH, 'w', encoding='utf-8') as fp:
            fp.writelines(keep)
    except Exception:
        pass
def _append_action_log(entry: Dict[str, Any]):
    line = json.dumps(entry, ensure_ascii=False)
    with _ACTION_LOG_LOCK:
        with open(ACTION_LOG_PATH, 'a', encoding='utf-8') as fp:
            fp.write(line + "\n")
        _prune_action_log_file()
def _read_action_logs(limit: int = 150) -> List[Dict[str, Any]]:
    if limit <= 0:
        return []
    with _ACTION_LOG_LOCK:
        if not os.path.exists(ACTION_LOG_PATH):
            return []
        with open(ACTION_LOG_PATH, 'r', encoding='utf-8') as fp:
            lines = fp.readlines()[-limit:]
    out: List[Dict[str, Any]] = []
    for line in reversed(lines):
        try:
            item = json.loads(line)
            if isinstance(item, dict):
                out.append(item)
        except Exception:
            continue
    return out

def _action_log_sanitized_body(value: Any) -> Any:
    if isinstance(value, dict):
        return {
            k: _action_log_sanitized_body(v)
            for k, v in value.items()
            if str(k) not in {"api_key", "secret_key", "apiKey", "secretKey"}
        }
    if isinstance(value, list):
        return [_action_log_sanitized_body(v) for v in value]
    return value

def _sanitize_undo_operation_for_log(undo_operation: Any) -> Dict[str, Any] | None:
    if not isinstance(undo_operation, dict):
        return None
    url = str(undo_operation.get("url") or "").strip()
    body = undo_operation.get("body")
    if not url or not isinstance(body, dict):
        return None
    out = {
        "kind": str(undo_operation.get("kind") or "").strip(),
        "url": url,
        "label": str(undo_operation.get("label") or "작업 되돌리기").strip() or "작업 되돌리기",
        "body": _action_log_sanitized_body(body),
    }
    return out

def _copy_payload_for_log_undo(payload: Dict[str, Any]) -> Dict[str, Any]:
    return _action_log_sanitized_body(copy.deepcopy(payload or {}))

def _collect_created_ids_for_log_undo(value: Any, entity_type: str, out: Optional[List[str]] = None, seen: Optional[set] = None) -> List[str]:
    if out is None:
        out = []
    if seen is None:
        seen = set()
    if value is None:
        return out
    if isinstance(value, list):
        for item in value:
            _collect_created_ids_for_log_undo(item, entity_type, out, seen)
        return out
    if not isinstance(value, dict):
        return out
    if value.get("ok") is False or value.get("success") is False or value.get("exists") is True:
        return out
    key_map = {
        "campaign": ["nccCampaignId", "campaignId", "campaign_id", "id"],
        "adgroup": ["nccAdgroupId", "adgroupId", "adgroup_id", "id"],
        "keyword": ["nccKeywordId", "keywordId", "keyword_id", "id"],
        "ad": ["nccAdId", "adId", "ad_id", "id"],
        "ad_extension": ["adExtensionId", "nccAdExtensionId", "extensionId", "ad_extension_id", "id"],
    }
    for key in key_map.get(entity_type, []):
        raw = value.get(key)
        if raw is None or isinstance(raw, (dict, list)):
            continue
        entity_id = str(raw or "").strip()
        if entity_id and entity_id not in seen:
            seen.add(entity_id)
            out.append(entity_id)
    for key in ("item", "items", "result", "results", "data"):
        if key in value:
            _collect_created_ids_for_log_undo(value.get(key), entity_type, out, seen)
    return out

def _registration_entity_for_log_undo(path: str, payload: Dict[str, Any], response_data: Dict[str, Any]) -> str:
    if path == "/bulk_register":
        return str(response_data.get("entity_type") or payload.get("entity_type") or "").strip().lower()
    return {
        "/create_campaign": "campaign",
        "/create_adgroup_simple": "adgroup",
        "/create_keywords_simple": "keyword",
        "/create_text_ad_simple": "ad",
        "/create_ad_advanced": "ad",
        "/create_shopping_ad_simple": "ad",
        "/create_extension_simple": "ad_extension",
        "/create_extension_raw": "ad_extension",
    }.get(path, "")

def _infer_action_log_undo_operation(path: str, payload: Dict[str, Any], response_data: Dict[str, Any], status: str) -> Dict[str, Any] | None:
    if status not in {"success", "partial"}:
        return None
    existing = _sanitize_undo_operation_for_log(response_data.get("undo_operation"))
    if existing:
        return existing
    if path in {
        "/set_campaign_state",
        "/set_adgroup_state_by_scope",
        "/set_ads_state_by_scope",
        "/set_ad_extensions_state_by_scope",
        "/set_asset_state_by_ids",
        "/set_searched_powerlink_keyword_state",
    } and "enabled" in payload:
        body = _copy_payload_for_log_undo(payload)
        body["enabled"] = not _boolish(payload.get("enabled"), True)
        return {"kind": path.strip("/"), "url": path, "label": "상태 변경 전으로 되돌리기", "body": body}
    entity_type = _registration_entity_for_log_undo(path, payload, response_data)
    if entity_type in {"campaign", "adgroup", "keyword", "ad", "ad_extension"}:
        ids = _collect_created_ids_for_log_undo(response_data, entity_type)
        if ids:
            return {
                "kind": "delete_selected",
                "url": "/delete_selected",
                "label": "등록 항목 삭제로 되돌리기",
                "body": {"entity_type": entity_type, "ids": ids},
            }
    return None

def _write_action_log_from_request(response: Response) -> None:
    path = request.path or ''
    if request.method != 'POST' or path in ACTION_LOG_EXCLUDED_PATHS:
        return
    try:
        payload = _safe_json_body()
        response_data = _response_json_dict(response)
        counts = _extract_action_log_counts(response_data, payload)
        status = _resolve_action_log_status(int(response.status_code), counts)
        customer_id = str(payload.get('customer_id') or payload.get('customerId') or '').strip()
        message = _extract_response_message(response, response_data)
        count_summary = _format_action_log_counts(counts)
        base_summary = _action_summary(path, payload)
        summary = " | ".join([x for x in [base_summary, count_summary] if x])
        all_detail_items = _extract_action_log_details(response_data, message, limit=None)
        if not any(str(item.get("level") or "") == "success" for item in all_detail_items):
            all_detail_items.extend(_synthesize_success_log_details_from_payload(payload, counts))
        detail_items = all_detail_items[:_ACTION_LOG_DETAIL_LIMIT]
        detail_level_counts: Dict[str, int] = {}
        for item in all_detail_items:
            if isinstance(item, dict):
                detail_level_counts[str(item.get("level") or "info")] = detail_level_counts.get(str(item.get("level") or "info"), 0) + 1
        entry = {
            'ts': time.strftime('%Y-%m-%d %H:%M:%S'),
            'path': path,
            'action': LOG_ACTION_LABELS.get(path, path.strip('/') or '요청'),
            'status': status,
            'http_status': int(response.status_code),
            'customer_id': customer_id,
            'summary': summary,
            'message': message,
            'total': counts.get('total'),
            'success': counts.get('success'),
            'fail': counts.get('fail'),
            'skipped': counts.get('skipped'),
            'detail_items': detail_items,
            'detail_count': len(all_detail_items),
            'detail_level_counts': detail_level_counts,
            'detail_truncated': len(all_detail_items) > len(detail_items),
        }
        undo_operation = _infer_action_log_undo_operation(path, payload, response_data, status)
        if undo_operation:
            entry["undo_operation"] = undo_operation
        _append_action_log(entry)
    except Exception:
        pass
