def _extract_pc_mobile_flags(detail_obj: Dict[str, Any] | None, pm_target_obj: Dict[str, Any] | None = None) -> Tuple[Optional[bool], Optional[bool]]:
    return extract_pc_mobile_flags(detail_obj, pm_target_obj)
