def _contents_bid_row_value(row: Dict[str, Any], field: str) -> str:
    aliases = {_normalize_table_header_key(x) for x in _CONTENTS_BID_HEADER_ALIASES.get(field, set())}
    for key, value in (row or {}).items():
        if _normalize_table_header_key(key) in aliases:
            return str(value or "").strip()
    return ""

def _parse_contents_bid_mode(value: Any, bid_value: Any = "") -> Tuple[Optional[bool], str]:
    raw = str(value or "").strip()
    norm = _normalize_table_header_key(raw)
    on_values = {
        "on", "1", "true", "y", "yes", "use", "사용", "사용함", "전용입찰가사용",
        "콘텐츠입찰가", "콘텐츠입찰가금액", "콘텐츠입찰가사용", "금액", "amount", "amt",
    }
    off_values = {
        "off", "0", "false", "n", "no", "none", "설정안함", "설정안",
        "미사용", "사용안함", "해제", "disable", "disabled",
    }
    if norm in {_normalize_table_header_key(x) for x in on_values}:
        return True, ""
    if norm in {_normalize_table_header_key(x) for x in off_values}:
        return False, ""
    if not raw and str(bid_value or "").strip():
        bid_norm = _normalize_table_header_key(str(bid_value or "").strip())
        if bid_norm in {_normalize_table_header_key(x) for x in off_values}:
            return False, ""
        return True, ""
    return None, "변경할 설정은 '금액' 또는 '설정 안함'으로 입력해주세요."

def bulk_update_contents_network_bid_amt():
    api_key = request.form.get("api_key")
    secret_key = request.form.get("secret_key")
    cid = request.form.get("customer_id")
    upload = request.files.get("file")
    if not api_key or not secret_key or not cid:
        return jsonify({"error": "API Key / Secret Key / Customer ID가 필요합니다."}), 400
    if upload is None or not getattr(upload, "filename", ""):
        return jsonify({"error": "업로드 파일을 선택해주세요."}), 400
    try:
        raw_rows = _read_contents_bid_change_upload(upload)
    except Exception as exc:
        return jsonify({"error": str(exc)}), 400
    if not raw_rows:
        return jsonify({"error": "업로드 파일에서 데이터 행을 찾지 못했습니다."}), 400

    targets: Dict[str, Dict[str, Any]] = {}
    invalid_results: List[Dict[str, Any]] = []
    duplicate_count = 0
    duplicate_conflicts = 0

    for idx, row in enumerate(raw_rows, start=2):
        if not any(str(v or "").strip() for v in (row or {}).values()):
            continue
        adgroup_id = _contents_bid_row_value(row, "adgroup_id")
        raw_mode = _contents_bid_row_value(row, "mode")
        raw_bid = _contents_bid_row_value(row, "bid_amt")
        missing = []
        if not adgroup_id:
            missing.append("광고그룹ID")
        if not raw_mode and not raw_bid:
            missing.append("콘텐츠 입찰가")
        if missing:
            invalid_results.append({"row_no": idx, "ok": False, "name": adgroup_id or f"{idx}행", "detail": f"필수 열 누락: {', '.join(missing)}"})
            continue
        use_contents_bid, mode_error = _parse_contents_bid_mode(raw_mode, raw_bid)
        if mode_error:
            invalid_results.append({"row_no": idx, "ok": False, "name": adgroup_id, "detail": f"{idx}행 {mode_error}"})
            continue
        target_bid: Optional[int] = None
        if use_contents_bid:
            target_bid, bid_error = _parse_strict_bid_amt(raw_bid, f"{idx}행 콘텐츠 입찰가(금액)", min_bid=50)
            if bid_error:
                invalid_results.append({"row_no": idx, "ok": False, "name": adgroup_id, "detail": bid_error})
                continue
        key = _bid_change_name_key(adgroup_id)
        previous = targets.get(key)
        if previous is not None:
            duplicate_count += 1
            if previous.get("use_contents_bid") != bool(use_contents_bid) or previous.get("target_bid") != target_bid:
                duplicate_conflicts += 1
        targets[key] = {
            "row_no": idx,
            "adgroup_id": adgroup_id,
            "use_contents_bid": bool(use_contents_bid),
            "target_bid": target_bid,
        }

    if not targets and invalid_results:
        return jsonify({"ok": False, "error": "유효한 변경 대상이 없습니다.", "results": invalid_results[:100], "total": len(raw_rows), "fail": len(invalid_results)}), 400

    results: List[Dict[str, Any]] = list(invalid_results)
    success = unchanged = target_fail = skipped = 0
    preferred_fields: Optional[str] = None

    for spec in targets.values():
        adgroup_id = str(spec.get("adgroup_id") or "").strip()
        row_name = adgroup_id
        ok, detail, obj, meta = _update_contents_network_bid_amt_for_adgroup(
            api_key, secret_key, cid, adgroup_id, spec["target_bid"], bool(spec["use_contents_bid"]), preferred_fields=preferred_fields
        )
        resolved_name = str((obj or {}).get("name") or adgroup_id)
        if ok is None:
            skipped += 1
            results.append({"row_no": spec["row_no"], "ok": None, "level": "skip", "name": row_name, "adgroupName": resolved_name, "detail": detail})
            continue
        if ok:
            strategy = str((meta or {}).get("strategy") or "")
            if strategy and strategy != "unchanged":
                preferred_fields = None if strategy == "__FULL__" else strategy
            if strategy == "unchanged" or str(detail or "").startswith("이미 동일값"):
                unchanged += 1
                results.append({"row_no": spec["row_no"], "ok": None, "level": "skip", "name": row_name, "adgroupName": resolved_name, "detail": detail})
            else:
                success += 1
                results.append({
                    "row_no": spec["row_no"],
                    "ok": True,
                    "level": "success",
                    "name": row_name,
                    "adgroupId": adgroup_id,
                    "adgroupName": resolved_name,
                    "mode": "금액" if spec["use_contents_bid"] else "설정 안함",
                    "contentsNetworkBidAmt": spec["target_bid"],
                    "detail": detail,
                })
            continue
        target_fail += 1
        results.append({"row_no": spec["row_no"], "ok": False, "level": "fail", "name": row_name, "adgroupName": resolved_name, "detail": detail, "code": _extract_error_code_from_value(detail)})

    if success > 0:
        _cache_invalidate(api_key, secret_key, cid)

    warnings: List[str] = []
    if duplicate_count:
        warnings.append(f"같은 광고그룹ID가 중복된 행 {duplicate_count}건은 마지막 행 기준으로 적용했습니다.")
    if duplicate_conflicts:
        warnings.append(f"중복 행 중 설정이 서로 다른 그룹 {duplicate_conflicts}건이 있어 마지막 행의 설정이 최종값입니다.")
    if invalid_results:
        warnings.append(f"필수값/설정/입찰가 오류로 제외된 행 {len(invalid_results)}건이 있습니다.")
    total_fail = target_fail + len(invalid_results)
    message = (
        f"추천/콘텐츠 지면 입찰가 대량 변경 완료: 변경 {success}개 / 유지 {unchanged}개 / "
        f"실패 {target_fail}개 / 건너뜀 {skipped}개"
        + (f" / 제외 행 {len(invalid_results)}건" if invalid_results else "")
    )
    ok_response = total_fail == 0
    return jsonify({
        "ok": ok_response,
        "message": message,
        "total": len(raw_rows),
        "targets": len(targets),
        "success": success,
        "unchanged": unchanged,
        "fail": total_fail,
        "target_fail": target_fail,
        "skipped": skipped,
        "invalid_rows": len(invalid_results),
        "duplicate_rows": duplicate_count,
        "duplicate_conflicts": duplicate_conflicts,
        "warnings": warnings,
        "results": results[:300],
    }), (200 if ok_response else 207 if success > 0 or unchanged > 0 else 400)
def _resolve_shopping_extra_owner_ids(api_key: str, secret_key: str, cid: str, campaign_ids: List[str] | None = None, adgroup_ids: List[str] | None = None):
    campaign_ids = [str(x).strip() for x in (campaign_ids or []) if str(x).strip()]
    adgroup_ids = [str(x).strip() for x in (adgroup_ids or []) if str(x).strip()]
    candidate_adgroup_ids: List[str] = []
    seen_adgroups: set[str] = set()
    warnings: List[str] = []
    for adgroup_id in adgroup_ids:
        if adgroup_id and adgroup_id not in seen_adgroups:
            candidate_adgroup_ids.append(adgroup_id)
            seen_adgroups.add(adgroup_id)
    for campaign_id in campaign_ids:
        res_adg, rows = _fetch_adgroups(api_key, secret_key, cid, campaign_id)
        if res_adg.status_code != 200:
            warnings.append(f"캠페인 {campaign_id} 광고그룹 조회 실패: {res_adg.text}")
            continue
        for row in rows:
            raw = row.get("raw") if isinstance(row, dict) else {}
            adg_type = str((raw or {}).get("adgroupType") or row.get("adgroupType") or "").upper()
            if adg_type != "SHOPPING":
                continue
            adg_id = str(row.get("id") or row.get("nccAdgroupId") or "").strip()
            if adg_id and adg_id not in seen_adgroups:
                candidate_adgroup_ids.append(adg_id)
                seen_adgroups.add(adg_id)
    owner_ids: List[str] = []
    seen_owner_ids: set[str] = set()
    for adgroup_id in candidate_adgroup_ids:
        res_ads, ads = _fetch_ads(api_key, secret_key, cid, adgroup_id)
        if res_ads.status_code != 200:
            warnings.append(f"광고그룹 {adgroup_id} 소재 조회 실패: {res_ads.text}")
            continue
        for ad in (ads or []):
            if not isinstance(ad, dict):
                continue
            ad_type = str(ad.get("type") or ad.get("adType") or "").upper()
            if ad_type not in SHOPPING_EXTRA_AD_TYPES:
                continue
            owner_id = str(ad.get("nccAdId") or ad.get("id") or "").strip()
            if owner_id and owner_id not in seen_owner_ids:
                owner_ids.append(owner_id)
                seen_owner_ids.add(owner_id)
    return owner_ids, warnings

def _looks_like_naver_adgroup_id(value: Any) -> bool:
    return str(value or "").strip().lower().startswith("grp-")


def _looks_like_naver_campaign_id(value: Any) -> bool:
    return str(value or "").strip().lower().startswith("cmp-")


def _looks_like_naver_ad_id(value: Any) -> bool:
    return str(value or "").strip().lower().startswith(("nad-", "ad-"))


def _adgroup_type_from_row(row: Dict[str, Any] | None) -> str:
    if not isinstance(row, dict):
        return ""
    raw = row.get("raw") if isinstance(row.get("raw"), dict) else {}
    return str(_first_non_empty(
        row.get("adgroupType"),
        row.get("adgroupTp"),
        raw.get("adgroupType"),
        raw.get("adgroupTp"),
    ) or "").strip().upper()


def _campaign_type_bucket(value: Any) -> str:
    s = str(value or "").strip().upper()
    if not s or s == "ALL":
        return ""
    if s in {"WEB", "WEB_SITE", "POWERLINK", "POWER_LINK", "파워링크"}:
        return "WEB_SITE"
    if s in {"쇼핑", "쇼핑검색", "쇼검"} or _is_shopping_campaign_type(s):
        return "SHOPPING"
    if s in {"PLACE", "PLACE_AD", "PLACE_SEARCH", "플레이스"} or "PLACE" in s or "플레이스" in s:
        return "PLACE"
    if s in {"POWER_CONTENT", "POWER_CONTENTS", "POWERCONTENTS", "POWERCONTENT", "파워컨텐츠", "파워콘텐츠"}:
        return "POWER_CONTENTS"
    return s


def _campaign_type_from_row(row: Dict[str, Any] | None) -> str:
    if not isinstance(row, dict):
        return ""
    raw = row.get("raw") if isinstance(row.get("raw"), dict) else {}
    return _campaign_type_bucket(_first_non_empty(
        row.get("campaignTp"),
        row.get("campaignType"),
        row.get("campaignTpNm"),
        row.get("campaignTypeName"),
        row.get("type"),
        row.get("label"),
        raw.get("campaignTp"),
        raw.get("campaignType"),
        raw.get("campaignTpNm"),
        raw.get("campaignTypeName"),
        raw.get("type"),
        raw.get("label"),
    ))


def _is_powerlink_adgroup_row(row: Dict[str, Any] | None) -> bool:
    return _adgroup_type_from_row(row) == "WEB_SITE"


def _extract_campaign_id_from_adgroup_row(row: Dict[str, Any] | None) -> str:
    if not isinstance(row, dict):
        return ""
    for key in ("nccCampaignId", "campaignId", "ownerCampaignId"):
        value = str(row.get(key) or "").strip()
        if value:
            return value
    raw = row.get("raw") if isinstance(row.get("raw"), dict) else {}
    for key in ("nccCampaignId", "campaignId", "ownerCampaignId"):
        value = str(raw.get(key) or "").strip()
        if value:
            return value
    return ""


def _ad_type_from_ad_row(ad: Dict[str, Any] | None) -> str:
    if not isinstance(ad, dict):
        return ""
    nested = ad.get("ad") if isinstance(ad.get("ad"), dict) else {}
    return _normalize_ad_type(_first_non_empty(
        ad.get("type"),
        ad.get("adType"),
        nested.get("type"),
        nested.get("adType"),
    ))


def _ad_row_has_shopping_signal(ad: Dict[str, Any] | None) -> bool:
    if not isinstance(ad, dict):
        return False
    nested = ad.get("ad") if isinstance(ad.get("ad"), dict) else {}
    ad_type = _ad_type_from_ad_row(ad)
    if ad_type in SHOPPING_AD_TYPES or "SHOPPING" in ad_type or "CATALOG" in ad_type:
        return True
    if _first_non_empty(
        ad.get("referenceKey"),
        ad.get("referenceData"),
        ad.get("referenceKeyData"),
        nested.get("referenceKey"),
        nested.get("referenceData"),
        nested.get("referenceKeyData"),
    ):
        return True
    return bool(_first_non_empty(
        ad.get("productName"),
        ad.get("mallProductName"),
        ad.get("productId"),
        nested.get("productName"),
        nested.get("mallProductName"),
        nested.get("productId"),
    ))


def _ad_row_has_text_ad_signal(ad: Dict[str, Any] | None) -> bool:
    if not isinstance(ad, dict):
        return False
    nested = ad.get("ad") if isinstance(ad.get("ad"), dict) else {}
    pc = nested.get("pc") if isinstance(nested.get("pc"), dict) else {}
    mobile = nested.get("mobile") if isinstance(nested.get("mobile"), dict) else {}
    return bool(_first_non_empty(
        ad.get("headline"),
        ad.get("title"),
        ad.get("description"),
        ad.get("desc"),
        nested.get("headline"),
        nested.get("title"),
        nested.get("description"),
        nested.get("desc"),
        pc.get("final"),
        pc.get("finalUrl"),
        mobile.get("final"),
        mobile.get("finalUrl"),
    ))


def _extract_adgroup_id_from_ad_row(ad: Dict[str, Any] | None) -> str:
    if not isinstance(ad, dict):
        return ""
    for key in ("nccAdgroupId", "adgroupId", "ownerAdgroupId"):
        value = str(ad.get(key) or "").strip()
        if value:
            return value
    nested = ad.get("ad")
    if isinstance(nested, dict):
        for key in ("nccAdgroupId", "adgroupId", "ownerAdgroupId"):
            value = str(nested.get(key) or "").strip()
            if value:
                return value
    return ""


def _extract_owner_ad_id_from_ad_row(ad: Dict[str, Any] | None) -> str:
    if not isinstance(ad, dict):
        return ""
    for key in ("nccAdId", "adId", "id", "ownerId"):
        value = str(ad.get(key) or "").strip()
        if value:
            return value
    nested = ad.get("ad")
    if isinstance(nested, dict):
        for key in ("nccAdId", "adId", "id", "ownerId"):
            value = str(nested.get(key) or "").strip()
            if value:
                return value
    return ""


def _is_powerlink_text_ad_row(ad: Dict[str, Any] | None) -> bool:
    if not isinstance(ad, dict):
        return False
    if _ad_row_has_shopping_signal(ad):
        return False
    raw_type = _ad_type_from_ad_row(ad)
    if not raw_type:
        # 일부 응답은 type 없이 ad body만 내려온다. 이때는 쇼핑 단서가 없고
        # 텍스트 소재 본문 신호가 있을 때만 추가설명 대상 후보로 둔다.
        return _ad_row_has_text_ad_signal(ad)
    return raw_type in {"TEXT_45", "RSA_AD", "RESPONSIVE_SEARCH_AD"} or raw_type.startswith("TEXT") or "RSA" in raw_type


def _resolve_powerlink_text_ad_owner_ids(
    api_key: str,
    secret_key: str,
    cid: str,
    campaign_ids: List[str] | None = None,
    adgroup_ids: List[str] | None = None,
    owner_ids: List[str] | None = None,
) -> Tuple[List[str], List[str]]:
    """Deprecated ad-owner resolver kept for compatibility with older data paths.

    The active DESCRIPTION_EXTRA create path uses adgroup owners via
    _resolve_powerlink_adgroup_extension_owner_ids().
    """
    warnings: List[str] = []
    direct_owner_ids: List[str] = []
    candidate_adgroup_ids: List[str] = []
    candidate_adgroup_types: Dict[str, str] = {}
    candidate_adgroup_campaign_types: Dict[str, str] = {}
    campaign_type_cache: Dict[str, str] = {}
    seen_adgroups: set[str] = set()

    def campaign_type_for(campaign_id: Any) -> str:
        campaign_id = str(campaign_id or "").strip()
        if not campaign_id:
            return ""
        if campaign_id in campaign_type_cache:
            return campaign_type_cache[campaign_id]
        campaign_detail = _fetch_campaign_detail(api_key, secret_key, cid, campaign_id)
        res_campaign = None
        campaign_obj = campaign_detail
        if isinstance(campaign_detail, tuple):
            res_campaign = campaign_detail[0] if len(campaign_detail) > 0 else None
            campaign_obj = campaign_detail[1] if len(campaign_detail) > 1 else None
        if not isinstance(campaign_obj, dict):
            detail = getattr(res_campaign, "text", "") if res_campaign is not None else ""
            warnings.append(f"캠페인 {campaign_id} 유형 확인 실패{(': ' + detail) if detail else ''}")
            campaign_type_cache[campaign_id] = ""
            return ""
        campaign_type = _campaign_type_from_row(campaign_obj)
        campaign_type_cache[campaign_id] = campaign_type
        return campaign_type

    def add_adgroup_id(value: Any, adgroup_type: Any = "", campaign_type: Any = ""):
        adgroup_id = str(value or "").strip()
        if adgroup_id and adgroup_id not in seen_adgroups:
            seen_adgroups.add(adgroup_id)
            candidate_adgroup_ids.append(adgroup_id)
        normalized_type = str(adgroup_type or "").strip().upper()
        if adgroup_id and normalized_type and adgroup_id not in candidate_adgroup_types:
            candidate_adgroup_types[adgroup_id] = normalized_type
        normalized_campaign_type = _campaign_type_bucket(campaign_type)
        if adgroup_id and normalized_campaign_type and adgroup_id not in candidate_adgroup_campaign_types:
            candidate_adgroup_campaign_types[adgroup_id] = normalized_campaign_type

    for owner_id in (owner_ids or []):
        owner_id = str(owner_id or "").strip()
        if not owner_id:
            continue
        if _looks_like_naver_adgroup_id(owner_id):
            add_adgroup_id(owner_id)
        elif _looks_like_naver_campaign_id(owner_id):
            campaign_ids = [*(campaign_ids or []), owner_id]
        else:
            # 소재ID를 직접 넣은 경우 그대로 사용한다. prefix가 낯설어도 기존 호환성을 위해 direct 처리.
            if owner_id not in direct_owner_ids:
                direct_owner_ids.append(owner_id)

    for adgroup_id in (adgroup_ids or []):
        add_adgroup_id(adgroup_id)

    for campaign_id in [str(x).strip() for x in (campaign_ids or []) if str(x).strip()]:
        campaign_type = campaign_type_for(campaign_id)
        if campaign_type and campaign_type != "WEB_SITE":
            warnings.append(f"캠페인 {campaign_id}은 파워링크 캠페인이 아니어서 추가설명 대상에서 제외했습니다.")
            continue
        res_adg, rows = _fetch_adgroups(api_key, secret_key, cid, campaign_id)
        if res_adg.status_code != 200:
            warnings.append(f"캠페인 {campaign_id} 광고그룹 조회 실패: {res_adg.text}")
            continue
        for row in rows or []:
            if not isinstance(row, dict):
                continue
            adg_type = _adgroup_type_from_row(row)
            if adg_type and adg_type != "WEB_SITE":
                continue
            adgroup_id = str(row.get("id") or row.get("nccAdgroupId") or "").strip()
            add_adgroup_id(adgroup_id, adg_type, campaign_type)

    resolved: List[str] = []
    seen_owner_ids: set[str] = set()
    for owner_id in direct_owner_ids:
        if not owner_id or owner_id in seen_owner_ids:
            continue
        if _looks_like_naver_ad_id(owner_id):
            res_ad, ad_obj = _fetch_entity_detail(api_key, secret_key, cid, "ad", owner_id)
            if res_ad.status_code != 200 or not isinstance(ad_obj, dict):
                warnings.append(f"소재 {owner_id} 확인 실패: {res_ad.text}")
                continue
            adgroup_id = _extract_adgroup_id_from_ad_row(ad_obj)
            if adgroup_id:
                res_adg, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, adgroup_id)
                if res_adg.status_code == 200 and isinstance(adgroup_obj, dict):
                    adg_type = _adgroup_type_from_row(adgroup_obj)
                    if adg_type and adg_type != "WEB_SITE":
                        warnings.append(f"소재 {owner_id}는 파워링크 광고그룹 소재가 아니어서 추가설명 대상에서 제외했습니다.")
                        continue
                    campaign_type = campaign_type_for(_extract_campaign_id_from_adgroup_row(adgroup_obj))
                    if campaign_type and campaign_type != "WEB_SITE":
                        warnings.append(f"소재 {owner_id}는 파워링크 캠페인 소재가 아니어서 추가설명 대상에서 제외했습니다.")
                        continue
            if not _is_powerlink_text_ad_row(ad_obj):
                warnings.append(f"소재 {owner_id}는 파워링크 텍스트 소재가 아니어서 추가설명 대상에서 제외했습니다.")
                continue
        resolved.append(owner_id)
        seen_owner_ids.add(owner_id)

    for adgroup_id in candidate_adgroup_ids:
        adg_type = candidate_adgroup_types.get(adgroup_id, "")
        adg_campaign_type = candidate_adgroup_campaign_types.get(adgroup_id, "")
        if not adg_type or not adg_campaign_type:
            res_adg, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, adgroup_id)
            if res_adg.status_code != 200:
                warnings.append(f"광고그룹 {adgroup_id} 확인 실패: {res_adg.text}")
                continue
            if not adg_type:
                adg_type = _adgroup_type_from_row(adgroup_obj)
            if not adg_campaign_type:
                adg_campaign_type = campaign_type_for(_extract_campaign_id_from_adgroup_row(adgroup_obj))
        if adg_campaign_type and adg_campaign_type != "WEB_SITE":
            continue
        if adg_type and adg_type != "WEB_SITE":
            continue
        res_ads, ads = _fetch_ads(api_key, secret_key, cid, adgroup_id)
        if res_ads.status_code != 200:
            warnings.append(f"광고그룹 {adgroup_id} 소재 조회 실패: {res_ads.text}")
            continue
        added = 0
        for ad in (ads or []):
            if not isinstance(ad, dict) or not _is_powerlink_text_ad_row(ad):
                continue
            owner_id = _extract_owner_ad_id_from_ad_row(ad)
            if owner_id and owner_id not in seen_owner_ids:
                resolved.append(owner_id)
                seen_owner_ids.add(owner_id)
                added += 1
        if added <= 0:
            warnings.append(f"광고그룹 {adgroup_id}에서 추가설명을 연결할 파워링크 소재ID를 찾지 못했습니다.")
    return resolved, warnings


def _resolve_powerlink_adgroup_extension_owner_ids(
    api_key: str,
    secret_key: str,
    cid: str,
    campaign_ids: List[str] | None = None,
    adgroup_ids: List[str] | None = None,
    owner_ids: List[str] | None = None,
) -> Tuple[List[str], List[str]]:
    """Resolve WEB_SITE adgroup owner ids for PowerLink ad extensions.

    DESCRIPTION_EXTRA is a WEB_SITE adgroup extension. Older code expanded
    adgroups to text-ad ids, but Naver returns 4003 for DESCRIPTION_EXTRA when
    it is posted to ad owners in current accounts.
    """
    warnings: List[str] = []
    resolved: List[str] = []
    seen_adgroups: set[str] = set()
    candidate_adgroup_types: Dict[str, str] = {}
    candidate_adgroup_campaign_types: Dict[str, str] = {}
    campaign_type_cache: Dict[str, str] = {}

    def campaign_type_for(campaign_id: Any) -> str:
        campaign_id = str(campaign_id or "").strip()
        if not campaign_id:
            return ""
        if campaign_id in campaign_type_cache:
            return campaign_type_cache[campaign_id]
        campaign_detail = _fetch_campaign_detail(api_key, secret_key, cid, campaign_id)
        res_campaign = None
        campaign_obj = campaign_detail
        if isinstance(campaign_detail, tuple):
            res_campaign = campaign_detail[0] if len(campaign_detail) > 0 else None
            campaign_obj = campaign_detail[1] if len(campaign_detail) > 1 else None
        if not isinstance(campaign_obj, dict):
            detail = getattr(res_campaign, "text", "") if res_campaign is not None else ""
            warnings.append(f"캠페인 {campaign_id} 유형 확인 실패{(': ' + detail) if detail else ''}")
            campaign_type_cache[campaign_id] = ""
            return ""
        campaign_type = _campaign_type_from_row(campaign_obj)
        campaign_type_cache[campaign_id] = campaign_type
        return campaign_type

    def add_adgroup_id(value: Any, adgroup_type: Any = "", campaign_type: Any = ""):
        adgroup_id = str(value or "").strip()
        if not adgroup_id:
            return
        if adgroup_id not in seen_adgroups:
            seen_adgroups.add(adgroup_id)
            resolved.append(adgroup_id)
        normalized_type = str(adgroup_type or "").strip().upper()
        if normalized_type and adgroup_id not in candidate_adgroup_types:
            candidate_adgroup_types[adgroup_id] = normalized_type
        normalized_campaign_type = _campaign_type_bucket(campaign_type)
        if normalized_campaign_type and adgroup_id not in candidate_adgroup_campaign_types:
            candidate_adgroup_campaign_types[adgroup_id] = normalized_campaign_type

    for owner_id in (owner_ids or []):
        owner_id = str(owner_id or "").strip()
        if not owner_id:
            continue
        if _looks_like_naver_campaign_id(owner_id):
            campaign_ids = [*(campaign_ids or []), owner_id]
        elif _looks_like_naver_adgroup_id(owner_id):
            add_adgroup_id(owner_id)
        elif _looks_like_naver_ad_id(owner_id):
            res_ad, ad_obj = _fetch_entity_detail(api_key, secret_key, cid, "ad", owner_id)
            if res_ad.status_code != 200 or not isinstance(ad_obj, dict):
                warnings.append(f"소재 {owner_id} 확인 실패: {res_ad.text}")
                continue
            if not _is_powerlink_text_ad_row(ad_obj):
                warnings.append(f"소재 {owner_id}는 파워링크 텍스트 소재가 아니어서 추가설명 대상에서 제외했습니다.")
                continue
            adgroup_id = _extract_adgroup_id_from_ad_row(ad_obj)
            if adgroup_id:
                add_adgroup_id(adgroup_id)
            else:
                warnings.append(f"소재 {owner_id}의 광고그룹 ID를 확인하지 못했습니다.")
        else:
            add_adgroup_id(owner_id)

    for adgroup_id in (adgroup_ids or []):
        add_adgroup_id(adgroup_id)

    for campaign_id in [str(x).strip() for x in (campaign_ids or []) if str(x).strip()]:
        campaign_type = campaign_type_for(campaign_id)
        if campaign_type and campaign_type != "WEB_SITE":
            warnings.append(f"캠페인 {campaign_id}은 파워링크 캠페인이 아니어서 추가설명 대상에서 제외했습니다.")
            continue
        res_adg, rows = _fetch_adgroups(api_key, secret_key, cid, campaign_id)
        if res_adg.status_code != 200:
            warnings.append(f"캠페인 {campaign_id} 광고그룹 조회 실패: {res_adg.text}")
            continue
        for row in rows or []:
            if not isinstance(row, dict):
                continue
            adg_type = _adgroup_type_from_row(row)
            if adg_type and adg_type != "WEB_SITE":
                continue
            adgroup_id = str(row.get("id") or row.get("nccAdgroupId") or "").strip()
            add_adgroup_id(adgroup_id, adg_type, campaign_type)

    final_ids: List[str] = []
    for adgroup_id in resolved:
        adg_type = candidate_adgroup_types.get(adgroup_id, "")
        adg_campaign_type = candidate_adgroup_campaign_types.get(adgroup_id, "")
        if not adg_type or not adg_campaign_type:
            res_adg, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, adgroup_id)
            if res_adg.status_code != 200:
                warnings.append(f"광고그룹 {adgroup_id} 확인 실패: {res_adg.text}")
                continue
            if not adg_type:
                adg_type = _adgroup_type_from_row(adgroup_obj)
            if not adg_campaign_type:
                adg_campaign_type = campaign_type_for(_extract_campaign_id_from_adgroup_row(adgroup_obj))
        if adg_campaign_type and adg_campaign_type != "WEB_SITE":
            continue
        if adg_type and adg_type != "WEB_SITE":
            continue
        final_ids.append(adgroup_id)
    return final_ids, warnings


def _extension_match_data_from_payload(payload: Dict[str, Any] | None) -> Dict[str, Any]:
    payload = payload if isinstance(payload, dict) else {}
    ext_type = _normalize_extension_type(payload.get("type"))
    ext = payload.get("adExtension")
    if ext_type == "HEADLINE":
        ext = ext if isinstance(ext, dict) else {}
        return {"headline": str(ext.get("headline") or payload.get("headline") or "").strip()}
    if ext_type == "DESCRIPTION_EXTRA":
        ext = ext if isinstance(ext, dict) else {}
        return {"description": str(ext.get("description") or payload.get("description") or "").strip()}
    if ext_type == "DESCRIPTION":
        ext = ext if isinstance(ext, dict) else {}
        return {
            "description": str(ext.get("description") or payload.get("description") or "").strip(),
            "heading": str(ext.get("heading") or payload.get("heading") or "").strip(),
        }
    if ext_type == "PROMOTION":
        ext = ext if isinstance(ext, dict) else {}
        return {
            "basicText": str(ext.get("basicText") or payload.get("basicText") or "").strip(),
            "additionalText": str(ext.get("additionalText") or payload.get("additionalText") or "").strip(),
        }
    if ext_type == "WEBSITE_INFO":
        ext = ext if isinstance(ext, dict) else {}
        return {
            "businessName": str(ext.get("businessName") or payload.get("businessName") or "").strip(),
            "siteUrl": str(ext.get("siteUrl") or ext.get("siteURL") or payload.get("siteUrl") or "").strip(),
            "website": str(ext.get("website") or payload.get("website") or "").strip(),
        }
    if ext_type == "SUB_LINKS":
        return {"links": ext if isinstance(ext, list) else []}
    return {}


def _fetch_extensions(api_key: str, secret_key: str, cid: str, owner_id: str):
    res = _do_req("GET", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": owner_id})
    if res.status_code != 200:
        return res, []
    return res, res.json() or []

def _extract_ad_extension_id(ext_item: Dict[str, Any] | None) -> str:
    """Return the real Naver ad-extension id from all known response shapes.

    Some API responses use `adExtensionId`; others use `nccAdExtensionId`.
    Export/delete/copy should not leave the extension ID blank because of alias differences.
    """
    if not isinstance(ext_item, dict):
        return ""
    candidates = [
        ext_item.get("adExtensionId"),
        ext_item.get("nccAdExtensionId"),
        ext_item.get("nccAdExtId"),
        ext_item.get("adExtId"),
        ext_item.get("id"),
    ]
    nested = ext_item.get("adExtension")
    if isinstance(nested, dict):
        candidates.extend([
            nested.get("adExtensionId"),
            nested.get("nccAdExtensionId"),
            nested.get("nccAdExtId"),
            nested.get("id"),
        ])
    for value in candidates:
        text = str(value or "").strip()
        if text:
            return text
    return ""

def _extract_ad_extension_owner_id(ext_item: Dict[str, Any] | None) -> str:
    if not isinstance(ext_item, dict):
        return ""
    candidates = [
        ext_item.get("ownerId"),
        ext_item.get("nccAdgroupId"),
        ext_item.get("nccAdId"),
        ext_item.get("adId"),
    ]
    nested = ext_item.get("adExtension")
    if isinstance(nested, dict):
        candidates.extend([
            nested.get("ownerId"),
            nested.get("nccAdgroupId"),
            nested.get("nccAdId"),
            nested.get("adId"),
        ])
    for value in candidates:
        text = str(value or "").strip()
        if text:
            return text
    return ""

def _fetch_ad_extension_state_candidates(
    api_key: str,
    secret_key: str,
    cid: str,
    ext_item: Dict[str, Any] | None,
    ext_id: str | None = None,
) -> List[Dict[str, Any]]:
    """Fetch owner-scoped extension rows for OFF filtering.

    Some accounts do not expose the mutable ON/OFF state on the plain
    /ncc/ad-extensions/{id} detail response. Re-reading by ownerId and matching
    the extension id gives the same shape as the list/detail UI uses.
    """
    ext_id = str(ext_id or _extract_ad_extension_id(ext_item) or "").strip()
    owner_id = _extract_ad_extension_owner_id(ext_item)
    if not ext_id or not owner_id:
        return []
    candidates: List[Dict[str, Any]] = []
    try:
        res_detail = _do_req("GET", api_key, secret_key, cid, f"/ncc/ad-extensions/{ext_id}", params={"ownerId": owner_id})
        if res_detail.status_code == 200:
            obj = res_detail.json()
            if isinstance(obj, dict):
                candidates.append(obj)
            elif isinstance(obj, list):
                candidates.extend([x for x in obj if isinstance(x, dict)])
    except Exception:
        pass
    try:
        res_list = _do_req("GET", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": owner_id})
        if res_list.status_code == 200:
            rows = res_list.json() or []
            for row in rows if isinstance(rows, list) else []:
                if isinstance(row, dict) and _extract_ad_extension_id(row) == ext_id:
                    candidates.append(row)
    except Exception:
        pass
    return candidates
def _extract_extension_image_ids(ext_item: Dict[str, Any] | None) -> str:
    """Extract image identifiers from image-type ad-extension responses.

    IMAGE_SUB_LINKS can return image identifiers in different nested shapes
    depending on the response/detail shape. Scan image-related id keys inside
    adExtension/sub-link items so the export does not leave the image ID blank.
    """
    if not isinstance(ext_item, dict):
        return ""
    raw_type = str(ext_item.get("type") or ext_item.get("adExtensionType") or "").strip()
    normalized_type = _normalize_extension_type(raw_type)
    if normalized_type not in {"IMAGE_SUB_LINKS", "POWER_LINK_IMAGE"} and "IMAGE" not in raw_type.upper():
        nested_ext = ext_item.get("adExtension")
        if not ("SUB" in raw_type.upper() and isinstance(nested_ext, list)):
            return ""

    exact_compact_keys = {
        "imageid", "nccimageid", "imageassetid", "imagefileid", "imageresourceid",
        "creativeimageid", "pcimageid", "mobileimageid", "imgid", "imgno",
        "imageno", "imageuid", "imageurl", "imagepath", "image", "imgurl",
        "fileid", "assetid", "id",
    }
    generic_compact_keys = {"fileid", "assetid", "id"}
    found: List[str] = []
    seen: set[str] = set()

    def add_value(value: Any):
        if isinstance(value, bool) or value is None:
            return
        if isinstance(value, (dict, list, tuple)):
            walk(value, "")
            return
        text = str(value).strip()
        if not text or text.lower() in {"none", "null", "undefined"}:
            return
        if text.startswith("http://") or text.startswith("https://"):
            return
        if len(text) > 160:
            return
        if text not in seen:
            seen.add(text)
            found.append(text)

    def is_image_id_key(key: Any, path: str = "") -> bool:
        k_raw = str(key or "").strip()
        k = k_raw.lower()
        compact = re.sub(r"[^a-z0-9]", "", k)
        path_l = str(path or "").lower()
        if compact in exact_compact_keys:
            if compact in generic_compact_keys:
                return "image" in path_l or "img" in path_l
            return True
        return (("image" in k or "img" in k) and ("id" in k or compact.endswith("no")))

    def maybe_parse_json_string(value: str) -> Any:
        text = str(value or "").strip()
        if not text or text[0] not in "[{":
            return None
        try:
            return json.loads(text)
        except Exception:
            return None

    def walk(obj: Any, path: str = ""):
        if isinstance(obj, dict):
            for key, value in obj.items():
                next_path = f"{path}.{key}" if path else str(key)
                if is_image_id_key(key, path):
                    add_value(value)
                else:
                    walk(value, next_path)
        elif isinstance(obj, (list, tuple)):
            for idx, item in enumerate(obj):
                walk(item, f"{path}[{idx}]")
        elif isinstance(obj, str):
            parsed = maybe_parse_json_string(obj)
            if parsed is not None:
                walk(parsed, path)

    walk(ext_item)
    return ", ".join(found)

def _extract_extension_link_items(ext_item: Dict[str, Any] | None) -> List[Dict[str, Any]]:
    """Return SUB_LINKS / IMAGE_SUB_LINKS items from common response shapes."""
    if not isinstance(ext_item, dict):
        return []
    ad_ext = ext_item.get("adExtension")
    candidates: List[Any] = []
    if isinstance(ad_ext, list):
        candidates.append(ad_ext)
    elif isinstance(ad_ext, dict):
        for key in (
            "subLinks", "subLink", "subLinksExtension", "subLinkExtension",
            "links", "linkList", "items", "imageSubLinks", "imageSubLink",
        ):
            value = ad_ext.get(key)
            if isinstance(value, list):
                candidates.append(value)
        candidates.append(ad_ext)
    for key in ("subLinks", "links", "items", "imageSubLinks"):
        value = ext_item.get(key)
        if isinstance(value, list):
            candidates.append(value)

    def compact_key(key: Any) -> str:
        return re.sub(r"[^a-z0-9]", "", str(key or "").lower())

    def pick(item: Dict[str, Any], keys: set[str]) -> str:
        for key, value in item.items():
            if isinstance(value, (dict, list, tuple)) or value is None or isinstance(value, bool):
                continue
            if compact_key(key) in keys:
                text = str(value).strip()
                if text and text.lower() not in {"none", "null", "undefined"}:
                    return text
        return _extension_first_deep_text(item, keys)

    image_keys = {"imageid", "nccimageid", "imageassetid", "imagefileid", "imageresourceid", "imageurl", "imagepath", "image", "imgurl", "imgid", "imgno", "imageno"}
    name_keys = {"name", "title", "linkname", "linktitle", "headline", "text", "label"}
    url_keys = {"final", "finalurl", "url", "linkurl", "pcurl", "pcfinalurl", "landingurl", "mobileurl", "mobilefinalurl"}

    links: List[Dict[str, Any]] = []
    seen: set[Tuple[str, str, str]] = set()
    for candidate in candidates:
        iterable = candidate if isinstance(candidate, list) else [candidate]
        for item in iterable:
            if not isinstance(item, dict):
                continue
            name = pick(item, name_keys)
            final_url = pick(item, url_keys)
            image_id = pick(item, image_keys)
            if not image_id:
                for key, value in item.items():
                    if compact_key(key) in {"image", "imageinfo", "imageasset", "img"} and isinstance(value, dict):
                        image_id = _extension_first_deep_text(value, {"imageid", "nccimageid", "id", "url", "path", "imageurl", "imagepath"})
                        if image_id:
                            break
            if not (name or final_url or image_id):
                continue
            key = (image_id, name, final_url)
            if key in seen:
                continue
            seen.add(key)
            links.append({"imageId": image_id, "name": name, "url": final_url})
    return links

def _extension_first_deep_text(value: Any, keys: set[str]) -> str:
    def compact_key(key: Any) -> str:
        return re.sub(r"[^a-z0-9]", "", str(key or "").lower())
    if isinstance(value, dict):
        for key, raw in value.items():
            if compact_key(key) in keys and raw is not None and not isinstance(raw, (dict, list, tuple, bool)):
                text = str(raw).strip()
                if text and text.lower() not in {"none", "null", "undefined"}:
                    return text
        for nested in value.values():
            found = _extension_first_deep_text(nested, keys)
            if found:
                return found
    elif isinstance(value, list):
        for item in value:
            found = _extension_first_deep_text(item, keys)
            if found:
                return found
    return ""

def _flatten_image_sublink_export_fields(ext_item: Dict[str, Any] | None) -> Dict[str, Any]:
    links = _extract_extension_link_items(ext_item)
    fields: Dict[str, Any] = {"linkCount": len(links)}
    for idx in range(1, 4):
        item = links[idx - 1] if idx <= len(links) else {}
        fields[f"link{idx}ImageId"] = str(item.get("imageId") or "").strip()
        fields[f"link{idx}Name"] = str(item.get("name") or "").strip()
        fields[f"link{idx}Url"] = str(item.get("url") or "").strip()
    image_ids = [str(item.get("imageId") or "").strip() for item in links if str(item.get("imageId") or "").strip()]
    if image_ids:
        fields["imageId"] = ", ".join(dict.fromkeys(image_ids))
    start = _extension_first_deep_text(ext_item, {"periodstartdate", "periodstartdt", "startdate", "startdt", "begindate", "begindt"})
    end = _extension_first_deep_text(ext_item, {"periodenddate", "periodenddt", "enddate", "enddt", "finishdate", "finishdt"})
    fields["periodSetting"] = "설정" if (start or end) else "설정안함"
    fields["periodStartDate"] = start
    fields["periodEndDate"] = end
    return fields

def _normalize_lookup_scope(value: Any) -> str:
    scope = str(value or "account").strip().lower()
    if scope in {"selected_campaigns", "campaigns", "campaign_only"}:
        return "campaign"
    if scope in {"selected_adgroups", "adgroups", "adgroup_only", "ad_group", "ad_group_only"}:
        return "adgroup"
    if scope == "adgroup":
        return "adgroup"
    return "campaign" if scope == "campaign" else "account"
def _collect_asset_scope_adgroups(api_key: str, secret_key: str, cid: str, scope: str, campaign_ids: List[str] | None = None, adgroup_ids: List[str] | None = None):
    scope = _normalize_lookup_scope(scope)
    selected_campaign_ids = _unique_keep_order([str(x or "").strip() for x in (campaign_ids or []) if str(x or "").strip()])
    selected_adgroup_ids = _unique_keep_order([str(x or "").strip() for x in (adgroup_ids or []) if str(x or "").strip()])
    selected_adgroup_set = set(selected_adgroup_ids)
    if scope == "adgroup" and not selected_adgroup_ids:
        return _make_fake_response(400, "선택 광고그룹 조회를 사용하려면 좌측에서 광고그룹을 체크해주세요."), [], [], []
    res_camp, all_campaigns = _fetch_campaigns(api_key, secret_key, cid)
    if res_camp.status_code != 200:
        return res_camp, [], [], []
    campaign_map = {str((row or {}).get("id") or "").strip(): row for row in (all_campaigns or []) if str((row or {}).get("id") or "").strip()}
    if scope == "campaign":
        if not selected_campaign_ids:
            return _make_fake_response(400, "선택 캠페인 조회를 사용하려면 좌측에서 캠페인을 체크해주세요."), [], [], []
        target_campaigns = []
        missing_campaign_ids: List[str] = []
        for campaign_id in selected_campaign_ids:
            row = campaign_map.get(campaign_id)
            if row:
                target_campaigns.append(row)
            else:
                missing_campaign_ids.append(campaign_id)
        if missing_campaign_ids:
            for campaign_id in missing_campaign_ids:
                target_campaigns.append({"id": campaign_id, "name": campaign_id, "campaignTp": "", "label": "캠페인"})
    else:
        target_campaigns = list(all_campaigns or [])
        missing_campaign_ids = []
    contexts: List[Dict[str, Any]] = []
    warnings: List[str] = []
    found_adgroup_ids: set[str] = set()
    if not target_campaigns:
        return _make_fake_response(200, "대상 캠페인 없음"), [], warnings, target_campaigns
    max_workers = min(FAST_IO_WORKERS, max(1, len(target_campaigns)))
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        future_map = {ex.submit(_fetch_adgroups, api_key, secret_key, cid, str(camp.get("id") or ""), False): camp for camp in target_campaigns}
        for fut in as_completed(future_map):
            camp = future_map[fut]
            camp_id = str((camp or {}).get("id") or "").strip()
            camp_name = str((camp or {}).get("name") or camp_id)
            camp_type = str((camp or {}).get("campaignTp") or "")
            try:
                res_adg, adg_rows = fut.result()
            except Exception as e:
                warnings.append(f"캠페인 {camp_name} 광고그룹 조회 실패: {e}")
                continue
            if res_adg.status_code != 200:
                warnings.append(f"캠페인 {camp_name} 광고그룹 조회 실패: {res_adg.text}")
                continue
            for adg in (adg_rows or []):
                adg_id = str((adg or {}).get("id") or (adg or {}).get("nccAdgroupId") or "").strip()
                if not adg_id:
                    continue
                if scope == "adgroup":
                    if adg_id not in selected_adgroup_set:
                        continue
                    found_adgroup_ids.add(adg_id)
                contexts.append({
                    "campaign_id": camp_id,
                    "campaign_name": camp_name,
                    "campaign_type": camp_type,
                    "adgroup_id": adg_id,
                    "adgroup_name": str((adg or {}).get("name") or adg_id),
                    "adgroup_type": str((adg or {}).get("adgroupType") or ""),
                    "adgroup_bid": ((adg or {}).get("raw") if isinstance((adg or {}).get("raw"), dict) else (adg or {})).get("bidAmt"),
                    "contents_network_bid": ((adg or {}).get("raw") if isinstance((adg or {}).get("raw"), dict) else (adg or {})).get("contentsNetworkBidAmt"),
                })
    if scope == "adgroup":
        missing_adgroup_ids = [adgroup_id for adgroup_id in selected_adgroup_ids if adgroup_id not in found_adgroup_ids]
        if missing_adgroup_ids:
            warnings.append(f"선택 광고그룹 {len(missing_adgroup_ids)}개를 찾지 못했거나 조회 대상 캠페인에 포함되지 않습니다.")
    if not contexts and warnings:
        return _make_fake_response(400, "\n".join(warnings[:10])), [], warnings, target_campaigns
    return _make_fake_response(200, "OK"), contexts, warnings, target_campaigns
def _deep_first_text_by_keys(obj: Any, keys: List[str], *, max_depth: int = 5) -> str:
    targets = {str(k or "").strip().lower() for k in keys if str(k or "").strip()}
    if not targets:
        return ""
    queue: List[Tuple[Any, int]] = [(obj, 0)]
    seen: set[int] = set()
    while queue:
        cur, depth = queue.pop(0)
        if cur is None:
            continue
        cur_id = id(cur)
        if isinstance(cur, (dict, list)):
            if cur_id in seen:
                continue
            seen.add(cur_id)
        if isinstance(cur, dict):
            for key, value in cur.items():
                key_norm = str(key or "").strip().lower()
                if key_norm in targets:
                    if isinstance(value, (str, int, float)):
                        text = str(value or "").strip()
                        if text:
                            return text
                    if isinstance(value, dict):
                        for nested_key in ("text", "value", "title", "name", "label"):
                            text = str(value.get(nested_key) or "").strip()
                            if text:
                                return text
            if depth < max_depth:
                for value in cur.values():
                    if isinstance(value, (dict, list)):
                        queue.append((value, depth + 1))
                    elif isinstance(value, str):
                        maybe = _parse_json_obj_if_needed(value)
                        if maybe:
                            queue.append((maybe, depth + 1))
        elif isinstance(cur, list) and depth < max_depth:
            for value in cur:
                if isinstance(value, (dict, list)):
                    queue.append((value, depth + 1))
                elif isinstance(value, str):
                    maybe = _parse_json_obj_if_needed(value)
                    if maybe:
                        queue.append((maybe, depth + 1))
    return ""


LOOKUP_STATUS_TEXT_KEYS = [
    "statusReason", "statusDetail", "statusMessage", "statusDescription",
    "inspectStatus", "reason", "reasonCode",
    "servingStatus", "servingState", "servingReason",
    "deliveryStatus", "deliveryState", "deliveryReason",
    "displayStatus", "displayState", "displayReason",
    "rejectReason", "reviewStatus", "reviewState", "reviewReason",
    "restrictionReason", "restrictedReason", "issueDetail", "issueReason",
    "systemReason", "adStatus", "adStatusReason", "operationStatus",
]


def _lookup_status_text(ad_item: Dict[str, Any] | None, keys: List[str]) -> str:
    item = ad_item or {}
    for key in keys:
        value = item.get(key)
        if isinstance(value, (str, int, float)) and str(value).strip():
            return str(value).strip()
    return _deep_first_text_by_keys(item, keys)


def _lookup_issue_detail_text(ad_item: Dict[str, Any] | None) -> str:
    item = ad_item or {}
    values: List[str] = []
    for key in LOOKUP_STATUS_TEXT_KEYS:
        text = _lookup_status_text(item, [key])
        normalized = re.sub(r"\s+", " ", str(text or "")).strip()
        if not normalized:
            continue
        if normalized.lower() in {"on", "ok", "normal", "none", "true", "active", "enabled", "approved", "eligible", "serving", "running"}:
            continue
        if normalized not in values:
            values.append(normalized)
    return " / ".join(values[:6])


def _lookup_is_shopping_ad(ctx: Dict[str, Any] | None, ad_item: Dict[str, Any] | None) -> bool:
    haystack = " ".join([
        str((ctx or {}).get("campaign_type") or ""),
        str((ctx or {}).get("adgroup_type") or ""),
        str((ad_item or {}).get("type") or ""),
        str((ad_item or {}).get("adType") or ""),
    ]).upper()
    return any(token in haystack for token in ("SHOPPING", "CATALOG", "PRODUCT"))


def _merge_lookup_ad_detail(base: Dict[str, Any], detail: Dict[str, Any] | None) -> Dict[str, Any]:
    if not isinstance(detail, dict) or not detail:
        return base
    merged = {**(base or {}), **detail}
    base_ad = (base or {}).get("ad")
    detail_ad = detail.get("ad")
    if isinstance(base_ad, dict) and isinstance(detail_ad, dict):
        merged["ad"] = {**base_ad, **detail_ad}
    return merged


def _extract_lookup_ad_text_fields(ad_item: Dict[str, Any] | None) -> Dict[str, Any]:
    """Extract title/description/url fields for ad lookup preview and Excel export."""
    item = ad_item or {}
    ad_obj = item.get("ad") if isinstance(item.get("ad"), dict) else _parse_json_obj_if_needed(item.get("ad"))
    pc_obj = ad_obj.get("pc") if isinstance(ad_obj.get("pc"), dict) else _parse_json_obj_if_needed(ad_obj.get("pc"))
    mobile_obj = ad_obj.get("mobile") if isinstance(ad_obj.get("mobile"), dict) else _parse_json_obj_if_needed(ad_obj.get("mobile"))
    headline = str(_first_non_empty(
        ad_obj.get("headline"), ad_obj.get("title"), ad_obj.get("productName"), ad_obj.get("name"),
        pc_obj.get("headline"), pc_obj.get("title"), mobile_obj.get("headline"), mobile_obj.get("title"),
        item.get("headline"), item.get("title"), item.get("productName"), item.get("name"), item.get("adName"),
    ) or "").strip()
    if not headline:
        headline = _deep_first_text_by_keys(item, ["headline", "title", "productName", "adName", "name"])

    description = str(_first_non_empty(
        ad_obj.get("description"), ad_obj.get("desc"), ad_obj.get("description1"), ad_obj.get("description2"), ad_obj.get("longDescription"),
        pc_obj.get("description"), pc_obj.get("desc"), pc_obj.get("description1"), pc_obj.get("description2"),
        mobile_obj.get("description"), mobile_obj.get("desc"), mobile_obj.get("description1"), mobile_obj.get("description2"),
        item.get("description"), item.get("desc"), item.get("description1"), item.get("description2"), item.get("longDescription"),
    ) or "").strip()
    if not description:
        description = _deep_first_text_by_keys(item, ["description", "desc", "description1", "description2", "longDescription", "adDescription"])

    product_name = str(_first_non_empty(ad_obj.get("productName"), item.get("productName"), item.get("mallProductName")) or "").strip()
    if not product_name:
        product_name = _deep_first_text_by_keys(item, ["productName", "mallProductName"])

    pc_final_url = str(_first_non_empty(
        pc_obj.get("final"), pc_obj.get("finalUrl"), pc_obj.get("pcFinalUrl"),
        ad_obj.get("pcFinalUrl"), ad_obj.get("finalUrl"), item.get("pcFinalUrl"), item.get("finalUrl"),
    ) or "").strip()
    if not pc_final_url:
        pc_final_url = _deep_first_text_by_keys(item, ["pcFinalUrl", "finalUrl", "landingUrl", "url"])

    mobile_final_url = str(_first_non_empty(
        mobile_obj.get("final"), mobile_obj.get("finalUrl"), mobile_obj.get("mobileFinalUrl"),
        ad_obj.get("mobileFinalUrl"), item.get("mobileFinalUrl"), item.get("mobileUrl"), pc_final_url,
    ) or "").strip()
    if not mobile_final_url:
        mobile_final_url = _deep_first_text_by_keys(item, ["mobileFinalUrl", "mobileUrl", "mobileLandingUrl"]) or pc_final_url

    reference_key = str(_first_non_empty(item.get("referenceKey"), ad_obj.get("referenceKey"), item.get("referenceData")) or "").strip()
    return {
        "headline": headline,
        "description": description,
        "productName": product_name,
        "pcFinalUrl": pc_final_url,
        "mobileFinalUrl": mobile_final_url,
        "referenceKey": reference_key,
    }


def _summarize_lookup_ad(ad_item: Dict[str, Any] | None) -> str:
    ad_item = ad_item or {}
    text_fields = _extract_lookup_ad_text_fields(ad_item)
    headline = str(text_fields.get("headline") or text_fields.get("productName") or "").strip()
    description = str(text_fields.get("description") or "").strip()
    if headline and description:
        return f"{headline} / {description}"
    if headline:
        return headline
    if description:
        return description
    ad_obj = ad_item.get("ad") if isinstance(ad_item.get("ad"), dict) else _parse_json_obj_if_needed(ad_item.get("ad"))
    pieces = [
        str(ad_obj.get("productName") or "").strip(),
        str(ad_obj.get("name") or "").strip(),
        str(ad_obj.get("title") or "").strip(),
        str(ad_item.get("name") or "").strip(),
        str(ad_item.get("type") or "").strip(),
    ]
    for value in pieces:
        if value:
            return value
    return json.dumps(ad_item, ensure_ascii=False)[:120]


def _lookup_bid_display_value(value: Any) -> Any:
    try:
        bid = int(float(value))
    except Exception:
        return ""
    return bid if bid > 0 else ""

def _lookup_ad_bid_fields(ad_item: Dict[str, Any] | None, adgroup_bid: Any = None) -> Dict[str, Any]:
    ad_item = ad_item or {}
    ad_attr = _extract_ad_attr(ad_item)
    raw_ad_bid = _first_non_empty(ad_attr.get("bidAmt"), ad_attr.get("adBidAmt"), ad_attr.get("bid_amt"), ad_attr.get("ad_bid_amt"))
    use_group_raw = _first_non_empty(ad_attr.get("useGroupBidAmt"), ad_attr.get("adUseGroupBidAmt"), ad_attr.get("use_group_bid_amt"), ad_attr.get("ad_use_group_bid_amt"))
    parsed_use_group = _bool_or_none(use_group_raw)
    group_bid_display = _lookup_bid_display_value(adgroup_bid)
    has_raw_ad_bid = _normalize_bid_amt(raw_ad_bid) is not None
    # If the ad response has no ad-level bid fields, it is effectively using the
    # adgroup bid. Show that explicitly instead of leaving every bid column blank.
    use_group = parsed_use_group if parsed_use_group is not None else (not has_raw_ad_bid)
    effective_bid = _resolve_effective_bid(raw_ad_bid, use_group, adgroup_bid, min_bid=50)
    if effective_bid is None and group_bid_display:
        effective_bid = _normalize_bid_amt(adgroup_bid)
    return {
        "adBidAmt": _lookup_bid_display_value(raw_ad_bid),
        "adUseGroupBidAmt": "Y" if use_group else "N",
        "adgroupBidAmt": group_bid_display,
        "effectiveBidAmt": _lookup_bid_display_value(effective_bid),
    }

def _summarize_lookup_extension(ext_item: Dict[str, Any] | None) -> str:
    ext_item = ext_item or {}
    ad_ext = ext_item.get("adExtension") if isinstance(ext_item.get("adExtension"), dict) else _parse_json_obj_if_needed(ext_item.get("adExtension"))
    promo_basic, promo_additional = _lookup_extension_promo_texts(ext_item)
    if promo_basic or promo_additional:
        return " / ".join([value for value in [promo_basic, promo_additional] if value])
    candidates = [
        str(ad_ext.get("headline") or "").strip(),
        str(ad_ext.get("description") or "").strip(),
        str(ad_ext.get("additionalDescription") or "").strip(),
        str(ad_ext.get("promotionTitle") or "").strip(),
        str(ad_ext.get("sellerName") or "").strip(),
        str(ad_ext.get("price") or "").strip(),
        str(ext_item.get("type") or "").strip(),
    ]
    for value in candidates:
        if value:
            return value
    links = ad_ext.get("subLinks") or ad_ext.get("subLinksExtension") or []
    if isinstance(links, list) and links:
        titles = []
        for item in links[:3]:
            if isinstance(item, dict):
                title = str(item.get("title") or item.get("name") or item.get("headline") or "").strip()
                if title:
                    titles.append(title)
        if titles:
            return " / ".join(titles)
    return json.dumps(ext_item, ensure_ascii=False)[:120]

def _lookup_extension_promo_texts(ext_item: Dict[str, Any] | None) -> Tuple[str, str]:
    ext_item = ext_item or {}
    ad_ext = ext_item.get("adExtension") if isinstance(ext_item.get("adExtension"), dict) else _parse_json_obj_if_needed(ext_item.get("adExtension"))
    basic_text = str(_first_non_empty(
        ad_ext.get("basicText"),
        ad_ext.get("basic_text"),
        ad_ext.get("text1"),
        ad_ext.get("promotionText1"),
        ad_ext.get("promoText1"),
        ext_item.get("basicText"),
        ext_item.get("basic_text"),
        ext_item.get("text1"),
        ext_item.get("promotionText1"),
        ext_item.get("promoText1"),
    ) or "").strip()
    additional_text = str(_first_non_empty(
        ad_ext.get("additionalText"),
        ad_ext.get("additional_text"),
        ad_ext.get("text2"),
        ad_ext.get("promotionText2"),
        ad_ext.get("promoText2"),
        ext_item.get("additionalText"),
        ext_item.get("additional_text"),
        ext_item.get("text2"),
        ext_item.get("promotionText2"),
        ext_item.get("promoText2"),
    ) or "").strip()
    return basic_text, additional_text

def _collect_lookup_ads_for_contexts(api_key: str, secret_key: str, cid: str, contexts: List[Dict[str, Any]], include_issue_detail: bool = False):
    rows: List[Dict[str, Any]] = []
    warnings: List[str] = []
    if not contexts:
        return rows, warnings
    max_workers = min(FAST_IO_WORKERS, max(1, len(contexts)))
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        future_map = {ex.submit(_fetch_ads, api_key, secret_key, cid, str(ctx.get("adgroup_id") or "")): ctx for ctx in contexts}
        for fut in as_completed(future_map):
            ctx = future_map[fut]
            adgroup_id = str(ctx.get("adgroup_id") or "")
            try:
                res_ads, ads = fut.result()
            except Exception as e:
                warnings.append(f"광고그룹 {adgroup_id} 소재 조회 실패: {e}")
                continue
            if res_ads.status_code != 200:
                warnings.append(f"광고그룹 {adgroup_id} 소재 조회 실패: {res_ads.text}")
                continue
            for ad in (ads or []):
                ad = ad if isinstance(ad, dict) else {}
                ad_id = str(ad.get("nccAdId") or ad.get("id") or "").strip()
                source_ad = ad
                if include_issue_detail and ad_id and _lookup_is_shopping_ad(ctx, ad):
                    try:
                        res_detail = _do_req("GET", api_key, secret_key, cid, f"/ncc/ads/{ad_id}")
                        if res_detail.status_code == 200:
                            detail_obj = res_detail.json()
                            if isinstance(detail_obj, dict):
                                source_ad = _merge_lookup_ad_detail(ad, detail_obj)
                        else:
                            warnings.append(f"소재 {ad_id} 상세 상태 조회 실패: {res_detail.text}")
                    except Exception as e:
                        warnings.append(f"소재 {ad_id} 상세 상태 조회 실패: {e}")
                bid_fields = _lookup_ad_bid_fields(source_ad, ctx.get("adgroup_bid"))
                text_fields = _extract_lookup_ad_text_fields(source_ad)
                issue_detail = _lookup_issue_detail_text(source_ad)
                rows.append({
                    "campaignId": str(ctx.get("campaign_id") or ""),
                    "campaignName": str(ctx.get("campaign_name") or ""),
                    "campaignType": str(ctx.get("campaign_type") or ""),
                    "adgroupId": adgroup_id,
                    "adgroupName": str(ctx.get("adgroup_name") or ""),
                    "adgroupType": str(ctx.get("adgroup_type") or ""),
                    "adId": ad_id,
                    "type": str(source_ad.get("type") or source_ad.get("adType") or ""),
                    "status": "ON" if _extract_enabled_from_entity(source_ad) is not False else "OFF",
                    "rawStatus": str(source_ad.get("status") or ""),
                    "statusReason": source_ad.get("statusReason") or _lookup_status_text(source_ad, ["statusReason", "statusDetail", "statusMessage", "statusDescription"]),
                    "inspectStatus": source_ad.get("inspectStatus") or _lookup_status_text(source_ad, ["inspectStatus"]),
                    "servingStatus": _lookup_status_text(source_ad, ["servingStatus", "servingState"]),
                    "servingReason": _lookup_status_text(source_ad, ["servingReason"]),
                    "deliveryStatus": _lookup_status_text(source_ad, ["deliveryStatus", "deliveryState"]),
                    "deliveryReason": _lookup_status_text(source_ad, ["deliveryReason"]),
                    "displayStatus": _lookup_status_text(source_ad, ["displayStatus", "displayState"]),
                    "displayReason": _lookup_status_text(source_ad, ["displayReason"]),
                    "reviewStatus": _lookup_status_text(source_ad, ["reviewStatus", "reviewState"]),
                    "reviewReason": _lookup_status_text(source_ad, ["reviewReason"]),
                    "rejectReason": _lookup_status_text(source_ad, ["rejectReason"]),
                    "restrictionReason": _lookup_status_text(source_ad, ["restrictionReason", "restrictedReason"]),
                    "adStatus": _lookup_status_text(source_ad, ["adStatus", "operationStatus"]),
                    "adStatusReason": _lookup_status_text(source_ad, ["adStatusReason", "systemReason", "issueReason"]),
                    "issueDetail": issue_detail,
                    "userLock": source_ad.get("userLock"),
                    "enable": source_ad.get("enable"),
                    "delFlag": source_ad.get("delFlag"),
                    "contentsNetworkBidAmt": ctx.get("contents_network_bid"),
                    "headline": text_fields.get("headline") or "",
                    "description": text_fields.get("description") or "",
                    "productName": text_fields.get("productName") or "",
                    "pcFinalUrl": text_fields.get("pcFinalUrl") or "",
                    "mobileFinalUrl": text_fields.get("mobileFinalUrl") or "",
                    "referenceKey": text_fields.get("referenceKey") or "",
                    "summary": _summarize_lookup_ad(ad),
                    **bid_fields,
                })
    rows.sort(key=lambda x: (x.get("campaignName") or "", x.get("adgroupName") or "", x.get("type") or "", x.get("summary") or ""))
    return rows, warnings

def _collect_lookup_keywords_for_contexts(api_key: str, secret_key: str, cid: str, contexts: List[Dict[str, Any]], include_ad_relevance: bool = False):
    rows: List[Dict[str, Any]] = []
    warnings: List[str] = []
    if not contexts:
        return rows, warnings
    max_workers = min(FAST_IO_WORKERS, max(1, len(contexts)))
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        future_map = {ex.submit(_fetch_keywords, api_key, secret_key, cid, str(ctx.get("adgroup_id") or "")): ctx for ctx in contexts}
        for fut in as_completed(future_map):
            ctx = future_map[fut]
            adgroup_id = str(ctx.get("adgroup_id") or "")
            try:
                res_kw, kw_rows = fut.result()
            except Exception as e:
                warnings.append(f"광고그룹 {adgroup_id} 키워드 조회 실패: {e}")
                continue
            if res_kw.status_code != 200:
                warnings.append(f"광고그룹 {adgroup_id} 키워드 조회 실패: {res_kw.text}")
                continue
            for kw in (kw_rows or []):
                kw = kw if isinstance(kw, dict) else {}
                rows.append({
                    "campaignId": str(ctx.get("campaign_id") or ""),
                    "campaignName": str(ctx.get("campaign_name") or ""),
                    "campaignType": str(ctx.get("campaign_type") or ""),
                    "adgroupId": adgroup_id,
                    "adgroupName": str(ctx.get("adgroup_name") or ""),
                    "adgroupType": str(ctx.get("adgroup_type") or ""),
                    "keywordId": str(kw.get("nccKeywordId") or kw.get("id") or "").strip(),
                    "keyword": str(kw.get("keyword") or "").strip(),
                    "status": "ON" if _extract_enabled_from_entity(kw) is not False else "OFF",
                    "rawStatus": str(kw.get("status") or ""),
                    "statusReason": kw.get("statusReason"),
                    "inspectStatus": kw.get("inspectStatus"),
                    "managedKeyword": kw.get("managedKeyword"),
                    "adRelevanceIndex": _extract_ad_relevance_index(kw),
                    "contentsNetworkBidAmt": ctx.get("contents_network_bid"),
                    "userLock": kw.get("userLock"),
                    "enable": kw.get("enable"),
                    "delFlag": kw.get("delFlag"),
                    "bidAmt": kw.get("bidAmt"),
                    "useGroupBidAmt": bool(kw.get("useGroupBidAmt")),
                    "matchType": str(kw.get("matchType") or kw.get("type") or "").strip(),
                })
    if include_ad_relevance and rows:
        relevance_warnings = _enrich_keyword_rows_with_ad_relevance(
            api_key,
            secret_key,
            cid,
            rows,
            id_key="keywordId",
            value_key="adRelevanceIndex",
        )
        if relevance_warnings:
            warnings.append(f"광고연관지수 상세 조회 일부 실패: {' / '.join(relevance_warnings[:3])}")
    rows.sort(key=lambda x: (x.get("campaignName") or "", x.get("adgroupName") or "", x.get("keyword") or ""))
    return rows, warnings
def _collect_lookup_extensions_for_contexts(api_key: str, secret_key: str, cid: str, contexts: List[Dict[str, Any]], ad_rows: List[Dict[str, Any]] | None = None):
    rows: List[Dict[str, Any]] = []
    warnings: List[str] = []
    owner_jobs: List[Tuple[str, Dict[str, Any], str]] = []
    seen_jobs: set[Tuple[str, str]] = set()
    for ctx in contexts or []:
        owner_id = str(ctx.get("adgroup_id") or "").strip()
        if owner_id and (owner_id, "ADGROUP") not in seen_jobs:
            owner_jobs.append((owner_id, ctx, "ADGROUP"))
            seen_jobs.add((owner_id, "ADGROUP"))
    for ad_row in (ad_rows or []):
        owner_id = str(ad_row.get("adId") or "").strip()
        if not owner_id or (owner_id, "AD") in seen_jobs:
            continue
        ctx = {
            "campaign_id": ad_row.get("campaignId"),
            "campaign_name": ad_row.get("campaignName"),
            "campaign_type": ad_row.get("campaignType"),
            "adgroup_id": ad_row.get("adgroupId"),
            "adgroup_name": ad_row.get("adgroupName"),
            "adgroup_type": ad_row.get("adgroupType"),
        }
        owner_jobs.append((owner_id, ctx, "AD"))
        seen_jobs.add((owner_id, "AD"))
    if not owner_jobs:
        return rows, warnings
    max_workers = min(FAST_IO_WORKERS, max(1, len(owner_jobs)))
    with ThreadPoolExecutor(max_workers=max_workers) as ex:
        future_map = {ex.submit(_fetch_extensions, api_key, secret_key, cid, owner_id): (owner_id, ctx, owner_scope) for owner_id, ctx, owner_scope in owner_jobs}
        for fut in as_completed(future_map):
            owner_id, ctx, owner_scope = future_map[fut]
            try:
                res_ext, ext_rows = fut.result()
            except Exception as e:
                warnings.append(f"owner {owner_id} 확장소재 조회 실패: {e}")
                continue
            if res_ext.status_code != 200:
                warnings.append(f"owner {owner_id} 확장소재 조회 실패: {res_ext.text}")
                continue
            for ext in (ext_rows or []):
                ext = ext if isinstance(ext, dict) else {}
                link_fields = _flatten_image_sublink_export_fields(ext)
                image_id_value = link_fields.get("imageId") or _extract_extension_image_ids(ext)
                promo_basic_text, promo_additional_text = _lookup_extension_promo_texts(ext)
                rows.append({
                    "campaignId": str(ctx.get("campaign_id") or ""),
                    "campaignName": str(ctx.get("campaign_name") or ""),
                    "campaignType": str(ctx.get("campaign_type") or ""),
                    "adgroupId": str(ctx.get("adgroup_id") or ""),
                    "adgroupName": str(ctx.get("adgroup_name") or ""),
                    "adgroupType": str(ctx.get("adgroup_type") or ""),
                    "ownerId": owner_id,
                    "ownerScope": "소재" if owner_scope == "AD" else "광고그룹",
                    "adExtensionId": _extract_ad_extension_id(ext),
                    "imageId": image_id_value,
                    "type": str(ext.get("type") or ext.get("adExtensionType") or ""),
                    "status": "ON" if _extract_enabled_from_entity(ext) is not False else "OFF",
                    "summary": _summarize_lookup_extension(ext),
                    "basicText": promo_basic_text,
                    "additionalText": promo_additional_text,
                    "promotionText1": promo_basic_text,
                    "promotionText2": promo_additional_text,
                    "extensionContent": " / ".join([value for value in [promo_basic_text, promo_additional_text] if value]),
                    **link_fields,
                })
    rows.sort(key=lambda x: (x.get("campaignName") or "", x.get("adgroupName") or "", x.get("ownerScope") or "", x.get("type") or "", x.get("summary") or ""))
    return rows, warnings

def _split_lookup_ad_export_summary(summary: Any) -> Tuple[str, str]:
    text = str(summary or "").strip()
    if not text:
        return "", ""
    for sep in [" / ", "\n", " | ", " - "]:
        if sep in text:
            left, right = text.split(sep, 1)
            return left.strip(), right.strip()
    return text, ""


def _prepare_asset_lookup_ad_export_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    prepared: List[Dict[str, Any]] = []
    extractor = globals().get("_extract_lookup_ad_text_fields")
    for row in rows or []:
        item = dict(row or {})
        nested_ad = item.get("ad") if isinstance(item.get("ad"), dict) else None
        nested_fields: Dict[str, Any] = {}
        if callable(extractor) and nested_ad:
            try:
                nested_fields = extractor(nested_ad) or {}
            except Exception:
                nested_fields = {}
        fallback_title, fallback_desc = _split_lookup_ad_export_summary(item.get("summary"))
        headline = str(
            item.get("headline")
            or item.get("title")
            or item.get("productName")
            or nested_fields.get("headline")
            or nested_fields.get("productName")
            or fallback_title
            or ""
        ).strip()
        description = str(
            item.get("description")
            or item.get("desc")
            or item.get("description1")
            or item.get("description2")
            or item.get("longDescription")
            or nested_fields.get("description")
            or fallback_desc
            or ""
        ).strip()
        item["headline"] = headline
        item["description"] = description
        item["productName"] = str(item.get("productName") or nested_fields.get("productName") or "").strip()
        item["pcFinalUrl"] = str(item.get("pcFinalUrl") or nested_fields.get("pcFinalUrl") or "").strip()
        item["mobileFinalUrl"] = str(item.get("mobileFinalUrl") or nested_fields.get("mobileFinalUrl") or "").strip()
        item["referenceKey"] = str(item.get("referenceKey") or nested_fields.get("referenceKey") or "").strip()
        if not item.get("summary"):
            item["summary"] = " / ".join([v for v in [headline, description] if v])
        prepared.append(item)
    return prepared


def _ensure_asset_lookup_ad_export_columns(columns: List[Tuple[str, str]]) -> List[Tuple[str, str]]:
    normalized = list(columns or [])
    labels = [label for _, label in normalized]
    keys = [key for key, _ in normalized]
    looks_like_ad_export = "소재 ID" in labels or "adId" in keys
    if not looks_like_ad_export:
        return normalized
    extra = []
    if "headline" not in keys and "소재 제목" not in labels:
        extra.append(("headline", "소재 제목"))
    if "description" not in keys and "소재 설명" not in labels:
        extra.append(("description", "소재 설명"))
    if "productName" not in keys and "상품명" not in labels:
        extra.append(("productName", "상품명"))
    if "pcFinalUrl" not in keys and "PC 연결 URL" not in labels:
        extra.append(("pcFinalUrl", "PC 연결 URL"))
    if "mobileFinalUrl" not in keys and "모바일 연결 URL" not in labels:
        extra.append(("mobileFinalUrl", "모바일 연결 URL"))
    if not extra:
        return normalized
    insert_at = None
    for idx, (key, label) in enumerate(normalized):
        if key == "summary" or label == "요약":
            insert_at = idx
            break
    if insert_at is None:
        insert_at = min(len(normalized), 6)
    return normalized[:insert_at] + extra + normalized[insert_at:]

def _build_asset_lookup_workbook(rows: List[Dict[str, Any]], title: str, scope_label: str, columns: List[Tuple[str, str]]):
    title_text = str(title or "")
    is_ad_export = "소재" in title_text and "확장소재" not in title_text
    if is_ad_export:
        rows = _prepare_asset_lookup_ad_export_rows(rows)
        columns = _ensure_asset_lookup_ad_export_columns(columns)

    def _format_lookup_excel_value(key: str, label: str, value: Any) -> Any:
        return format_asset_lookup_excel_value(
            key,
            label,
            value,
            normalize_ad_type=_normalize_ad_type,
            normalize_extension_type=_normalize_extension_type,
        )

    generated_at = time.strftime("%Y-%m-%d %H:%M:%S")
    headers = [label for _, label in columns]
    data_rows = []
    for row in rows:
        data_rows.append([
            _format_lookup_excel_value(key, label, row.get(key))
            for key, label in columns
        ])
    width_by_key = {
        "campaignType": 14, "campaignName": 22, "adgroupType": 16, "adgroupName": 22,
        "headline": 30, "description": 46, "productName": 30, "summary": 42, "type": 18, "status": 10,
        "pcFinalUrl": 42, "mobileFinalUrl": 42, "referenceKey": 28,
        "effectiveBidAmt": 14, "adBidAmt": 14, "adUseGroupBidAmt": 16, "adgroupBidAmt": 16, "contentsNetworkBidAmt": 18, "adId": 24,
        "adExtensionId": 24, "imageId": 34, "imageIdCount": 12, "imageIdDetail": 36,
        "periodSetting": 12, "periodStartDate": 14, "periodEndDate": 14,
        "link1ImageId": 46, "link1Name": 22, "link1Url": 52,
        "link2ImageId": 46, "link2Name": 22, "link2Url": 52,
        "link3ImageId": 46, "link3Name": 22, "link3Url": 52,
        "extensionTypeLabel": 18, "resolvedExtensionType": 18, "ownerId": 24, "campaignId": 20, "adgroupId": 22, "ownerScope": 12,
    }
    widths = {
        idx: width_by_key.get(key, max(12, min(40, len(label) + 4)))
        for idx, (key, label) in enumerate(columns, start=1)
    }
    return build_report_workbook(
        title=title,
        sheet_title=title[:31],
        metadata=[
            f"생성시각: {generated_at}",
            f"조회범위: {scope_label}",
            *( ["컬럼버전: ad-export-title-description-v3"] if is_ad_export else [] ),
        ],
        headers=headers,
        rows=data_rows,
        start_row=5,
        widths=widths,
        freeze_panes="A6",
    )
def _fetch_target_restrict_object(api_key: str, secret_key: str, cid: str, owner_id: str):
    res = _do_req("GET", api_key, secret_key, cid, "/ncc/targets", params={"ownerId": owner_id, "types": "RESTRICT_KEYWORD_TARGET"})
    if res.status_code != 200:
        return res, None
    data = res.json() or []
    if isinstance(data, dict):
        data = [data]
    for item in data:
        if isinstance(item, dict) and item.get("targetTp") == "RESTRICT_KEYWORD_TARGET":
            return res, item
    return res, None
def _fetch_target_object(api_key: str, secret_key: str, cid: str, owner_id: str, target_type: str):
    res = _do_req("GET", api_key, secret_key, cid, "/ncc/targets", params={"ownerId": owner_id, "types": target_type})
    if res.status_code != 200:
        return res, None
    data = res.json() or []
    if isinstance(data, dict):
        data = [data]
    for item in data:
        if isinstance(item, dict) and str(item.get("targetTp") or "").upper() == str(target_type or "").upper():
            return res, item
    return res, None
def _fetch_non_search_keyword_target(api_key: str, secret_key: str, cid: str, owner_id: str):
    return _fetch_target_object(api_key, secret_key, cid, owner_id, "NON_SEARCH_KEYWORD_TARGET")
def _get_pc_mobile_tuple(media_type: Any) -> Tuple[bool, bool]:
    media = str(media_type or "ALL").strip().upper()
    if media == "PC":
        return True, False
    if media == "MOBILE":
        return False, True
    return True, True
def _normalize_media_detail(media_detail: Any) -> Dict[str, bool]:
    raw = media_detail if isinstance(media_detail, dict) else {}
    return {
        "search_naver": _boolish(raw.get("search_naver"), True),
        "search_partner": _boolish(raw.get("search_partner"), True),
        "contents_naver": _boolish(raw.get("contents_naver"), True),
        "contents_partner": _boolish(raw.get("contents_partner"), True),
    }
def _media_target_block_has_values(block: Any) -> bool:
    if not isinstance(block, dict):
        return False
    for key in ("media", "mediaGroup"):
        value = block.get(key)
        if value is None:
            continue
        if isinstance(value, list):
            if any(str(x or "").strip() for x in value):
                return True
            continue
        if str(value or "").strip():
            return True
    return False

def _copy_media_target_block(block: Any, *, media_default: Any = None, media_group_default: Any = None) -> Dict[str, Any]:
    source = copy.deepcopy(block) if isinstance(block, dict) else {}
    if "media" not in source:
        source["media"] = copy.deepcopy(media_default)
    if "mediaGroup" not in source:
        source["mediaGroup"] = copy.deepcopy(media_group_default)
    return source

def _build_media_target_payload(media_detail: Any, existing_target: Any = None) -> Dict[str, Any]:
    detail = _normalize_media_detail(media_detail)
    search: List[str] = []
    contents: List[str] = []
    if detail["search_naver"]:
        search.append("naver")
    if detail["search_partner"]:
        search.append("partner")
    if detail["contents_naver"]:
        contents.append("naver")
    if detail["contents_partner"]:
        contents.append("partner")
    existing = copy.deepcopy(existing_target) if isinstance(existing_target, dict) else {}
    existing_black = existing.get("black") if isinstance(existing.get("black"), dict) else {}
    existing_white = existing.get("white") if isinstance(existing.get("white"), dict) else {}
    has_restricted_media = _media_target_block_has_values(existing_black) or _media_target_block_has_values(existing_white)
    if len(search) == 2 and len(contents) == 2 and not has_restricted_media:
        return {
            "type": 1,
            "search": [],
            "contents": [],
            "white": {"media": None, "mediaGroup": None},
            "black": {"media": None, "mediaGroup": None},
        }
    if not search and not contents:
        raise ValueError("세부 매체는 최소 1개 이상 선택해야 합니다.")
    return {
        "type": 2,
        "search": search,
        "contents": contents,
        "black": _copy_media_target_block(existing_black, media_default=[], media_group_default=[]),
        "white": _copy_media_target_block(existing_white, media_default=None, media_group_default=None),
    }
def _update_pc_mobile_target(api_key: str, secret_key: str, cid: str, owner_id: str, media_type: Any):
    pc, mobile = _get_pc_mobile_tuple(media_type)
    res_target, target_obj = _fetch_target_object(api_key, secret_key, cid, owner_id, "PC_MOBILE_TARGET")
    if res_target.status_code == 200 and target_obj and target_obj.get("nccTargetId"):
        payload = {
            "nccTargetId": target_obj.get("nccTargetId"),
            "ownerId": owner_id,
            "targetTp": "PC_MOBILE_TARGET",
            "target": {"pc": pc, "mobile": mobile},
            "delFlag": False,
        }
        res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)
        if res_put.status_code in [200, 201]:
            return True, "PC_MOBILE_TARGET 업데이트 완료"
        fallback_detail = res_put.text
    else:
        fallback_detail = res_target.text if res_target is not None else "PC_MOBILE_TARGET 조회 실패"
    # 하위 호환용 fallback
    res_get = _do_req("GET", api_key, secret_key, cid, f"/ncc/adgroups/{owner_id}")
    if res_get.status_code != 200:
        return False, f"타겟/광고그룹 조회 실패: {fallback_detail}"
    obj = res_get.json() or {}
    obj["pcDevice"], obj["mobileDevice"] = pc, mobile
    res_put2 = _do_req("PUT", api_key, secret_key, cid, f"/ncc/adgroups/{owner_id}", params={"fields": "pcDevice,mobileDevice"}, json_body=obj)
    if res_put2.status_code in [200, 201]:
        return True, "pcDevice/mobileDevice fallback 업데이트 완료"
    return False, f"타겟/광고그룹 업데이트 실패: {fallback_detail} | {res_put2.text}"
def _update_media_target(api_key: str, secret_key: str, cid: str, owner_id: str, media_detail: Any):
    res_target, target_obj = _fetch_target_object(api_key, secret_key, cid, owner_id, "MEDIA_TARGET")
    if res_target.status_code == 200 and target_obj and target_obj.get("nccTargetId"):
        try:
            target_payload = _build_media_target_payload(media_detail, target_obj.get("target"))
        except ValueError as e:
            return False, str(e)
        payload = {
            "nccTargetId": target_obj.get("nccTargetId"),
            "ownerId": owner_id,
            "targetTp": "MEDIA_TARGET",
            "target": target_payload,
            "delFlag": False,
        }
        res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)
        if res_put.status_code in [200, 201, 204]:
            restricted_count = len(_extract_restricted_media_ids_from_target(target_payload))
            restricted_group_count = len(_extract_restricted_media_groups_from_target(target_payload))
            preserve_bits = []
            if restricted_count:
                preserve_bits.append(f"제한 매체 {restricted_count}개 보존")
            if restricted_group_count:
                preserve_bits.append(f"제한 매체그룹 {restricted_group_count}개 보존")
            suffix = f" ({', '.join(preserve_bits)})" if preserve_bits else ""
            return True, "MEDIA_TARGET 업데이트 완료" + suffix
        return False, res_put.text
    fallback_detail = res_target.text if res_target is not None else "MEDIA_TARGET 조회 실패"
    return False, f"MEDIA_TARGET 조회 실패: {fallback_detail}"

def _media_id_key(value: Any) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    if re.fullmatch(r"\d+(?:\.0+)?", text):
        try:
            return str(int(float(text)))
        except Exception:
            return text
    return text

def _media_id_api_value(value: Any) -> Any:
    key = _media_id_key(value)
    if re.fullmatch(r"\d+", key):
        return int(key)
    return key

def _parse_restricted_media_ids(value: Any) -> List[Any]:
    """Parse selected/pasted media IDs into unique API-ready media identifiers."""
    raw_items: List[Any] = []
    if isinstance(value, (list, tuple, set)):
        raw_items.extend(list(value))
    else:
        text = str(value or "").replace("\r\n", "\n").replace("\r", "\n").strip()
        if text:
            for line in text.split("\n"):
                line = str(line or "").strip()
                if not line:
                    continue
                cells = [c.strip().strip('"\'') for c in re.split(r"[\t,;]+", line) if str(c or "").strip()]
                if not cells:
                    continue
                digit_cells = [c for c in cells if re.fullmatch(r"\d+", c)]
                if digit_cells and len(digit_cells) == len(cells):
                    raw_items.extend(digit_cells)
                    continue
                if re.fullmatch(r"\d+", cells[0]):
                    # 엑셀 행 전체를 붙여넣은 경우 첫 번째 열(매체ID)만 사용한다.
                    raw_items.append(cells[0])
                    continue
                if re.fullmatch(r"[\d\s]+", line):
                    raw_items.extend(re.findall(r"\d+", line))
    out: List[Any] = []
    seen: set[str] = set()
    for item in raw_items:
        key = _media_id_key(item)
        if not key or not re.fullmatch(r"\d+", key) or key in seen:
            continue
        seen.add(key)
        out.append(_media_id_api_value(key))
    return out

def _default_media_target_payload_for_restriction(media_ids: List[Any]) -> Dict[str, Any]:
    return {
        "type": 2,
        "search": ["naver", "partner"],
        "contents": ["naver", "partner"],
        "black": {"media": list(media_ids or []), "mediaGroup": []},
        "white": {"media": None, "mediaGroup": None},
    }

def _merge_restricted_media_ids_into_target(target: Any, media_ids: List[Any]) -> Tuple[Dict[str, Any], int, int]:
    media_ids = list(media_ids or [])
    target_payload = copy.deepcopy(target) if isinstance(target, dict) else {}
    original_type = target_payload.get("type")
    if not target_payload:
        return _default_media_target_payload_for_restriction(media_ids), len(media_ids), len(media_ids)

    # MEDIA_TARGET은 black.media가 있으면 부분 매체 설정(type=2)으로 저장되는 케이스가 많다.
    # 기존 검색/콘텐츠 지면 선택은 보존하되, type=1(전체)에서 최초 제한을 추가할 때만 전체 지면을 명시한다.
    target_payload["type"] = 2
    if str(original_type) == "1" or not isinstance(target_payload.get("search"), list):
        target_payload["search"] = ["naver", "partner"]
    if str(original_type) == "1" or not isinstance(target_payload.get("contents"), list):
        target_payload["contents"] = ["naver", "partner"]

    black = target_payload.get("black") if isinstance(target_payload.get("black"), dict) else {}
    black_media = black.get("media")
    if black_media is None:
        existing_media: List[Any] = []
    elif isinstance(black_media, list):
        existing_media = list(black_media)
    else:
        existing_media = [black_media]

    existing_keys = {_media_id_key(x) for x in existing_media if _media_id_key(x)}
    added: List[Any] = []
    for mid in media_ids:
        key = _media_id_key(mid)
        if not key or key in existing_keys:
            continue
        existing_keys.add(key)
        added.append(_media_id_api_value(mid))
    black["media"] = existing_media + added
    if not isinstance(black.get("mediaGroup"), list):
        black["mediaGroup"] = []
    target_payload["black"] = black

    # 동일 매체가 whitelist에도 있으면 제한 설정과 충돌할 수 있어 제거한다.
    white = target_payload.get("white") if isinstance(target_payload.get("white"), dict) else {"media": None, "mediaGroup": None}
    if isinstance(white.get("media"), list):
        blocked_keys = {_media_id_key(x) for x in black["media"] if _media_id_key(x)}
        white["media"] = [x for x in white.get("media") if _media_id_key(x) not in blocked_keys]
    if "mediaGroup" not in white:
        white["mediaGroup"] = None
    if "media" not in white:
        white["media"] = None
    target_payload["white"] = white
    return target_payload, len(added), len(black["media"])

def _add_restricted_media_ids_to_adgroup(api_key: str, secret_key: str, cid: str, owner_id: str, media_ids: List[Any]):
    media_ids = list(media_ids or [])
    if not media_ids:
        return False, "추가할 매체가 없습니다.", False, 0, 0
    res_target, target_obj = _fetch_target_object(api_key, secret_key, cid, owner_id, "MEDIA_TARGET")
    if res_target.status_code != 200:
        return False, f"MEDIA_TARGET 조회 실패: {res_target.text}", False, 0, 0

    if target_obj and target_obj.get("nccTargetId"):
        target_payload, added_count, total_count = _merge_restricted_media_ids_into_target(target_obj.get("target"), media_ids)
        if added_count <= 0:
            return True, f"이미 제한 매체에 포함됨 (현재 {total_count}개)", False, 0, total_count
        payload = {
            "customerId": int(cid),
            "nccTargetId": target_obj.get("nccTargetId"),
            "ownerId": str(owner_id),
            "targetTp": "MEDIA_TARGET",
            "target": target_payload,
            "delFlag": False,
        }
        res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)
        if res_put.status_code in [200, 201, 204]:
            return True, f"제한 매체 {added_count}개 추가 완료 (현재 {total_count}개)", True, added_count, total_count
        return False, f"MEDIA_TARGET 업데이트 실패: {res_put.text}", False, 0, total_count

    target_payload = _default_media_target_payload_for_restriction(media_ids)
    payload = {
        "customerId": int(cid),
        "ownerId": str(owner_id),
        "targetTp": "MEDIA_TARGET",
        "target": target_payload,
        "delFlag": False,
    }
    res_post = _do_req("POST", api_key, secret_key, cid, "/ncc/targets", json_body=payload)
    if res_post.status_code in [200, 201, 204]:
        return True, f"MEDIA_TARGET 생성 후 제한 매체 {len(media_ids)}개 추가 완료", True, len(media_ids), len(media_ids)
    return False, f"MEDIA_TARGET 생성 실패: {res_post.text}", False, 0, 0


def _extract_restricted_media_ids_from_target(target: Any) -> List[Any]:
    """Return unique black.media IDs from a MEDIA_TARGET payload without touching other media settings."""
    if not isinstance(target, dict):
        return []
    black = target.get("black") if isinstance(target.get("black"), dict) else {}
    black_media = black.get("media")
    if black_media is None:
        raw_items: List[Any] = []
    elif isinstance(black_media, list):
        raw_items = list(black_media)
    else:
        raw_items = [black_media]
    out: List[Any] = []
    seen: set[str] = set()
    for item in raw_items:
        key = _media_id_key(item)
        if not key or key in seen:
            continue
        seen.add(key)
        out.append(_media_id_api_value(item))
    return out


def _extract_restricted_media_groups_from_target(target: Any) -> List[Any]:
    """Return unique black.mediaGroup values from a MEDIA_TARGET payload."""
    if not isinstance(target, dict):
        return []
    black = target.get("black") if isinstance(target.get("black"), dict) else {}
    black_groups = black.get("mediaGroup")
    if black_groups is None:
        raw_items: List[Any] = []
    elif isinstance(black_groups, list):
        raw_items = list(black_groups)
    else:
        raw_items = [black_groups]
    out: List[Any] = []
    seen: set[str] = set()
    for item in raw_items:
        key = _media_id_key(item)
        if not key or key in seen:
            continue
        seen.add(key)
        out.append(_media_id_api_value(item))
    return out


def _restricted_media_keys(media_ids: List[Any]) -> List[str]:
    keys: List[str] = []
    seen: set[str] = set()
    for item in media_ids or []:
        key = _media_id_key(item)
        if not key or key in seen:
            continue
        seen.add(key)
        keys.append(key)
    return keys


def _replace_restricted_media_ids_only(target: Any, source_media_ids: List[Any], source_media_groups: List[Any] | None = None) -> Tuple[Dict[str, Any], bool, int, int]:
    """Overwrite MEDIA_TARGET black restriction fields and preserve allowed placement settings."""
    normalized_media_ids = [_media_id_api_value(x) for x in (source_media_ids or []) if _media_id_key(x)]
    normalized_media_groups = [_media_id_api_value(x) for x in (source_media_groups or []) if _media_id_key(x)]
    new_keys = _restricted_media_keys(normalized_media_ids)
    new_group_keys = _restricted_media_keys(normalized_media_groups)
    target_payload = copy.deepcopy(target) if isinstance(target, dict) else {}
    if not target_payload:
        payload = _default_media_target_payload_for_restriction(normalized_media_ids)
        payload["black"]["mediaGroup"] = list(normalized_media_groups)
        return payload, bool(new_keys or new_group_keys), len(new_keys), len(new_group_keys)

    # black.media/black.mediaGroup을 저장하려면 API상 세부 매체 payload(type=2)가 필요한 케이스가 있다.
    # 다만 기존 search/contents/white/mediaGroup 값은 그대로 유지해서 PC/MO 및 세부 매체 선택은 건드리지 않는다.
    if (new_keys or new_group_keys) and str(target_payload.get("type") or "") == "1":
        target_payload["type"] = 2
        if not isinstance(target_payload.get("search"), list) or not target_payload.get("search"):
            target_payload["search"] = ["naver", "partner"]
        if not isinstance(target_payload.get("contents"), list) or not target_payload.get("contents"):
            target_payload["contents"] = ["naver", "partner"]

    black = target_payload.get("black") if isinstance(target_payload.get("black"), dict) else {}
    old_media = black.get("media")
    if old_media is None:
        old_items: List[Any] = []
    elif isinstance(old_media, list):
        old_items = list(old_media)
    else:
        old_items = [old_media]
    old_keys = _restricted_media_keys(old_items)
    old_groups = black.get("mediaGroup")
    if old_groups is None:
        old_group_items: List[Any] = []
    elif isinstance(old_groups, list):
        old_group_items = list(old_groups)
    else:
        old_group_items = [old_groups]
    old_group_keys = _restricted_media_keys(old_group_items)
    black["media"] = list(normalized_media_ids)
    black["mediaGroup"] = list(normalized_media_groups)
    target_payload["black"] = black

    # 덮어쓰기 기능은 노출 제한 block(black.media/mediaGroup)만 바꾼다.
    # white/search/contents/PC_MOBILE_TARGET 등 기존 허용 지면 설정은 그대로 보존한다.
    if not isinstance(target_payload.get("white"), dict):
        target_payload["white"] = {"media": None, "mediaGroup": None}
    return target_payload, (old_keys != new_keys or old_group_keys != new_group_keys), len(new_keys), len(new_group_keys)


def _fetch_source_restricted_media_ids(api_key: str, secret_key: str, cid: str, source_owner_id: str):
    res_src, src_target_obj = _fetch_target_object(api_key, secret_key, cid, source_owner_id, "MEDIA_TARGET")
    if res_src.status_code != 200:
        return False, [], [], f"원본 MEDIA_TARGET 조회 실패: {res_src.text}"
    if not src_target_obj or not src_target_obj.get("target"):
        return True, [], [], "원본 제한 매체 없음"
    media_ids = _extract_restricted_media_ids_from_target(src_target_obj.get("target"))
    media_groups = _extract_restricted_media_groups_from_target(src_target_obj.get("target"))
    group_msg = f", 매체그룹 {len(media_groups)}개" if media_groups else ""
    return True, media_ids, media_groups, f"원본 제한 매체 {len(media_ids)}개{group_msg} 확인"


def _copy_restricted_media_only_to_adgroup(api_key: str, secret_key: str, cid: str, target_owner_id: str, source_media_ids: List[Any], source_media_groups: List[Any] | None = None):
    source_media_ids = list(source_media_ids or [])
    source_media_groups = list(source_media_groups or [])
    res_dst, dst_target_obj = _fetch_target_object(api_key, secret_key, cid, target_owner_id, "MEDIA_TARGET")
    if res_dst.status_code != 200:
        return False, f"대상 MEDIA_TARGET 조회 실패: {res_dst.text}", False, 0

    if dst_target_obj and dst_target_obj.get("nccTargetId"):
        target_payload, changed, total_count, group_count = _replace_restricted_media_ids_only(dst_target_obj.get("target"), source_media_ids, source_media_groups)
        group_suffix = f", 매체그룹 {group_count}개" if group_count else ""
        if not changed:
            return True, f"동일하여 유지 (제한 매체 {total_count}개{group_suffix})", False, total_count
        payload = {
            "customerId": int(cid),
            "nccTargetId": dst_target_obj.get("nccTargetId"),
            "ownerId": str(target_owner_id),
            "targetTp": "MEDIA_TARGET",
            "target": target_payload,
            "delFlag": False,
        }
        res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{dst_target_obj.get('nccTargetId')}", json_body=payload)
        if res_put.status_code in [200, 201, 204]:
            return True, f"노출 제한 매체만 덮어쓰기 완료 (제한 매체 {total_count}개{group_suffix})", True, total_count
        return False, f"MEDIA_TARGET 업데이트 실패: {res_put.text}", False, total_count

    if not source_media_ids and not source_media_groups:
        return True, "원본 제한 매체가 없어 생성 생략", False, 0

    target_payload = _default_media_target_payload_for_restriction(source_media_ids)
    target_payload["black"]["mediaGroup"] = list(source_media_groups)
    payload = {
        "customerId": int(cid),
        "ownerId": str(target_owner_id),
        "targetTp": "MEDIA_TARGET",
        "target": target_payload,
        "delFlag": False,
    }
    res_post = _do_req("POST", api_key, secret_key, cid, "/ncc/targets", json_body=payload)
    if res_post.status_code in [200, 201, 204]:
        group_suffix = f", 매체그룹 {len(source_media_groups)}개" if source_media_groups else ""
        return True, f"MEDIA_TARGET 생성 후 노출 제한 매체 복사 완료 (제한 매체 {len(source_media_ids)}개{group_suffix})", True, len(source_media_ids)
    return False, f"MEDIA_TARGET 생성 실패: {res_post.text}", False, 0

def _update_non_search_keyword_target(api_key: str, secret_key: str, cid: str, owner_id: str, excluded: bool):
    res_target, target_obj = _fetch_non_search_keyword_target(api_key, secret_key, cid, owner_id)
    if res_target.status_code != 200:
        return False, f"NON_SEARCH_KEYWORD_TARGET 조회 실패: {res_target.text}"
    if not target_obj or not target_obj.get("nccTargetId"):
        return False, "NON_SEARCH_KEYWORD_TARGET 정보를 찾지 못했습니다. 광고센터에서 해당 쇼핑 광고그룹의 제외키워드 탭을 한 번 저장한 뒤 다시 시도해주세요."
    payload = {
        "nccTargetId": target_obj.get("nccTargetId"),
        "ownerId": owner_id,
        "targetTp": "NON_SEARCH_KEYWORD_TARGET",
        "target": {"excluded": bool(excluded)},
        "delFlag": False,
    }
    res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)
    if res_put.status_code in [200, 201]:
        return True, "검색어 없는 경우 광고 노출 제외 설정 완료"
    return False, res_put.text
def _copy_target_payload_from_source_obj(api_key: str, secret_key: str, cid: str, src_target_obj: Dict[str, Any], target_owner_id: str):
    target_type = _normalize_target_type_name((src_target_obj or {}).get("targetTp"))
    if not target_type:
        return False, "타겟 유형 확인 실패"
    src_target = copy.deepcopy((src_target_obj or {}).get("target"))
    if src_target is None:
        return False, f"{target_type} 원본 target 비어 있음"

    res_dst, dst_target_obj = _fetch_target_object(api_key, secret_key, cid, target_owner_id, target_type)
    if res_dst.status_code == 200 and dst_target_obj and dst_target_obj.get("nccTargetId"):
        payload = {
            "customerId": int(cid),
            "nccTargetId": dst_target_obj.get("nccTargetId"),
            "ownerId": str(target_owner_id),
            "targetTp": target_type,
            "target": src_target,
            "delFlag": False,
        }
        res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{dst_target_obj.get('nccTargetId')}", json_body=payload)
        if res_put.status_code in [200, 201, 204]:
            return True, f"{target_type} 복사 완료"
        return False, f"{target_type} 적용 실패: {res_put.text}"

    if target_type == "PC_MOBILE_TARGET" and isinstance(src_target, dict):
        pc = bool(src_target.get("pc", True))
        mobile = bool(src_target.get("mobile", True))
        if pc and mobile:
            media_type = "ALL"
        elif pc:
            media_type = "PC"
        elif mobile:
            media_type = "MOBILE"
        else:
            return False, "PC_MOBILE_TARGET 원본이 모두 비활성화 상태입니다."
        return _update_pc_mobile_target(api_key, secret_key, cid, target_owner_id, media_type)

    create_payload = {
        "customerId": int(cid),
        "ownerId": str(target_owner_id),
        "targetTp": str(target_type),
        "target": src_target,
        "delFlag": False,
    }
    res_post = _do_req("POST", api_key, secret_key, cid, "/ncc/targets", json_body=create_payload)
    if res_post.status_code in [200, 201, 204]:
        return True, f"{target_type} 복사 완료"
    detail = res_dst.text if res_dst is not None else '알 수 없는 오류'
    return False, f"{target_type} 생성/적용 실패: {res_post.text if res_post is not None else detail}"


def _copy_target_payload_exact(api_key: str, secret_key: str, cid: str, source_owner_id: str, target_owner_id: str, target_type: str):
    target_type = _normalize_target_type_name(target_type)
    res_src, src_target_obj = _fetch_target_object(api_key, secret_key, cid, source_owner_id, target_type)
    if res_src.status_code != 200:
        return False, f"{target_type} 원본 조회 실패: {res_src.text}"
    if not src_target_obj:
        return False, f"{target_type} 원본 설정 없음"
    return _copy_target_payload_from_source_obj(api_key, secret_key, cid, src_target_obj, target_owner_id)
def _fetch_all_target_objects(api_key: str, secret_key: str, cid: str, owner_id: str):
    res = _do_req("GET", api_key, secret_key, cid, "/ncc/targets", params={"ownerId": owner_id})
    if res.status_code != 200:
        return res, []
    data = res.json() or []
    if isinstance(data, dict):
        data = [data]
    return res, [item for item in data if isinstance(item, dict)]
def _normalize_target_type_name(target_type: Any) -> str:
    return str(target_type or "").strip().upper()
def _is_extra_copy_target_type(target_type: Any) -> bool:
    tp = _normalize_target_type_name(target_type)
    if not tp:
        return False
    if tp in {"PC_MOBILE_TARGET", "MEDIA_TARGET", "RESTRICT_KEYWORD_TARGET", "NON_SEARCH_KEYWORD_TARGET"}:
        return False
    return True

# 광고그룹 복사 시 누락되기 쉬운 타겟 타입을 명시적으로 재조회한다.
# /ncc/targets?ownerId=... 전체 조회가 계정/상품/타겟 탭 상태에 따라 일부 타입을 빠뜨리는 케이스가 있어,
# 원본 광고그룹 상세 targets와 타입별 조회를 같이 병합한다.
ADGROUP_PROFILE_TARGET_TYPES = [
    # v11: 타입 후보를 추측해서 /ncc/targets?types=... 로 찌르면
    # 계정/상품에 따라 4406(The type of Target is invalid) 경고가 반복된다.
    # 따라서 명시 타입 재조회는 하지 않고, 실제 API가 내려준
    # 1) /ncc/targets?ownerId=... 전체 목록
    # 2) /ncc/adgroups/{id} 상세의 targets 배열
    # 안에 존재하는 targetTp만 복사 대상으로 삼는다.
]

TARGET_TYPE_KO_LABELS = {
    "REGIONAL_TARGET": "지역",
    "LOCATION_TARGET": "지역",
    "AREA_TARGET": "지역",
    "GENDER_TARGET": "성별",
    "AGE_TARGET": "연령대",
    "AGE_GROUP_TARGET": "연령대",
    "AGE_BAND_TARGET": "연령대",
    "DEMOGRAPHIC_TARGET": "연령/성별",
    "AGE_GENDER_TARGET": "연령/성별",
    "USER_SEGMENT_TARGET": "이용자 세그먼트",
    "TIME_WEEKLY_TARGET": "요일/시간",
    "PERIOD_TARGET": "기간",
    "MEDIA_TARGET": "매체",
    "PC_MOBILE_TARGET": "PC/Mobile",
}


def _target_type_label(target_type: Any) -> str:
    tp = _normalize_target_type_name(target_type)
    return TARGET_TYPE_KO_LABELS.get(tp, tp or "타겟")


def _compact_json_for_message(value: Any, max_len: int = 260) -> str:
    try:
        txt = json.dumps(value, ensure_ascii=False, sort_keys=True)
    except Exception:
        txt = str(value or "")
    txt = re.sub(r"\s+", " ", txt).strip()
    return txt[:max_len] + ("..." if len(txt) > max_len else "")


def _normalize_attr_json_value(value: Any) -> str:
    """Return a stable representation for adgroupAttrJson comparisons.

    Some PowerLink targeting/profile settings are returned only inside
    adgroupAttrJson on newer adgroup objects. The API may return it either as
    a JSON string or as an object depending on account/API version, so compare
    it in a normalized form.
    """
    if value is None:
        return ""
    if isinstance(value, str):
        raw = value.strip()
        if not raw:
            return ""
        try:
            parsed = json.loads(raw)
            return json.dumps(parsed, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        except Exception:
            return raw
    try:
        return json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except Exception:
        return str(value).strip()


def _copy_adgroup_attr_json_settings(api_key: str, secret_key: str, cid: str, source_adgroup_id: str, target_adgroup_id: str):
    """Copy adgroupAttrJson after creating/copying an adgroup.

    지역/성별/연령대처럼 UI에서는 그룹 설정으로 보이지만 /ncc/targets
    목록에 별도 target row가 내려오지 않는 값이 adgroupAttrJson에 들어오는
    계정이 있다. 복사 직후 이 값을 보정 복사하고 재조회로 확인한다.
    """
    res_src, src_obj = _fetch_adgroup_detail(api_key, secret_key, cid, source_adgroup_id)
    if res_src is not None and res_src.status_code != 200:
        return False, f"adgroupAttrJson 원본 조회 실패: {res_src.text}"
    if not isinstance(src_obj, dict) or src_obj.get("adgroupAttrJson") in (None, ""):
        return True, "adgroupAttrJson 원본 설정 없음"
    res_dst, dst_obj = _fetch_adgroup_detail(api_key, secret_key, cid, target_adgroup_id)
    if res_dst is not None and res_dst.status_code != 200:
        return False, f"adgroupAttrJson 대상 조회 실패: {res_dst.text}"
    if not isinstance(dst_obj, dict):
        return False, "adgroupAttrJson 대상 광고그룹 응답 없음"

    src_attr = src_obj.get("adgroupAttrJson")
    src_norm = _normalize_attr_json_value(src_attr)
    if not src_norm:
        return True, "adgroupAttrJson 원본 설정 없음"
    if _normalize_attr_json_value(dst_obj.get("adgroupAttrJson")) == src_norm:
        return True, "adgroupAttrJson 이미 동일"

    attempts = []
    payload = _prepare_adgroup_full_update_obj_for_search_options(dst_obj, cid, {"adgroupAttrJson": src_attr}, sanitized=True)
    res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/adgroups/{target_adgroup_id}", json_body=payload)
    attempts.append(f"full/no-fields: {res_put.status_code} {str(res_put.text or '')[:160]}")
    if res_put.status_code in [200, 201, 204]:
        res_verify, verify_obj = _fetch_adgroup_detail(api_key, secret_key, cid, target_adgroup_id)
        if res_verify is not None and res_verify.status_code == 200 and isinstance(verify_obj, dict):
            if _normalize_attr_json_value(verify_obj.get("adgroupAttrJson")) == src_norm:
                return True, "adgroupAttrJson 복사 완료"
            attempts.append("full/no-fields: 응답 성공이나 재조회값 불일치")

    minimal_payload = {"adgroupAttrJson": src_attr}
    res_put2 = _do_req(
        "PUT", api_key, secret_key, cid, f"/ncc/adgroups/{target_adgroup_id}",
        params={"fields": "adgroupAttrJson"}, json_body=minimal_payload,
    )
    attempts.append(f"fields/adgroupAttrJson: {res_put2.status_code} {str(res_put2.text or '')[:160]}")
    if res_put2.status_code in [200, 201, 204]:
        res_verify, verify_obj = _fetch_adgroup_detail(api_key, secret_key, cid, target_adgroup_id)
        if res_verify is not None and res_verify.status_code == 200 and isinstance(verify_obj, dict):
            if _normalize_attr_json_value(verify_obj.get("adgroupAttrJson")) == src_norm:
                return True, "adgroupAttrJson 복사 완료"
            attempts.append("fields/adgroupAttrJson: 응답 성공이나 재조회값 불일치")
    return False, "adgroupAttrJson 복사 실패/미반영: " + " / ".join(attempts[:4])


def _adgroup_target_diagnostic(adgroup_obj: Dict[str, Any] | None) -> str:
    if not isinstance(adgroup_obj, dict):
        return "광고그룹 상세 응답 없음"
    keys = ", ".join([str(k) for k in list(adgroup_obj.keys())[:40]])
    target_summary = adgroup_obj.get("targetSummary")
    targets = adgroup_obj.get("targets")
    pieces = [f"광고그룹 응답 key: {keys}"]
    if target_summary:
        pieces.append("targetSummary=" + _compact_json_for_message(target_summary, 220))
    if targets:
        pieces.append("targets=" + _compact_json_for_message(targets, 220))
    return " / ".join(pieces)


def _should_surface_target_copy_message(msg: Any) -> bool:
    s = str(msg or "").strip()
    if not s:
        return False
    tokens = [
        "복사 완료", "원본 설정 없음", "원본 타겟 없음", "원본 프로필 타겟 없음", "실패", "미반영",
        "조회", "생성/적용", "비어", "지원", "타겟 확인", "원본 프로필 타겟 확인", "경고", "adgroupAttrJson", "Criterion",
    ]
    return any(tok in s for tok in tokens)



def _target_type_from_obj(row: Dict[str, Any] | None) -> str:
    if not isinstance(row, dict):
        return ""
    for key in ("targetTp", "targetType", "type"):
        value = row.get(key)
        if isinstance(value, str) and value.strip().upper().endswith("_TARGET"):
            return value.strip().upper()
    nested = row.get("target")
    if isinstance(nested, dict):
        for key in ("targetTp", "targetType"):
            value = nested.get(key)
            if isinstance(value, str) and value.strip().upper().endswith("_TARGET"):
                return value.strip().upper()
    return _normalize_target_type_name(row.get("targetTp"))


def _detail_target_type_labels(rows: List[Dict[str, Any]]) -> List[str]:
    labels: List[str] = []
    for row in rows or []:
        tp = _target_type_from_obj(row)
        if tp:
            labels.append(_target_type_label(tp))
    return _unique_keep_order(labels)


def _profile_target_absence_message(adg_obj: Dict[str, Any] | None, detail_rows: List[Dict[str, Any]] | None) -> str:
    labels = _detail_target_type_labels(detail_rows or [])
    diag = _adgroup_target_diagnostic(adg_obj)
    if labels:
        return "원본 프로필 타겟 없음: 상세 targets에는 " + ", ".join(labels) + "만 확인됨. 지역·성별·연령대 targetTp는 응답에 없습니다. " + diag
    return "원본 프로필 타겟 없음/확인 실패: /ncc/targets와 광고그룹 상세 targets에서 지역·성별·연령대 타겟을 찾지 못했습니다. " + diag


def _target_fetch_notice(msg: str) -> bool:
    return "The type of Target is invalid" not in str(msg or "") and '"code":4406' not in str(msg or "")

def _dedupe_target_objects_by_type(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    seen = set()
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        target_type = _target_type_from_obj(row)
        if not _is_extra_copy_target_type(target_type):
            continue
        if row.get("target") is None:
            continue
        key = target_type
        if key in seen:
            continue
        seen.add(key)
        if not row.get("targetTp") and target_type:
            row = dict(row)
            row["targetTp"] = target_type
        out.append(row)
    return out


def _fetch_copyable_adgroup_target_objects(api_key: str, secret_key: str, cid: str, owner_id: str):
    rows: List[Dict[str, Any]] = []
    detail_rows: List[Dict[str, Any]] = []
    messages: List[str] = []
    primary_res = _make_fake_response(200, "OK")
    adg_obj: Dict[str, Any] | None = None

    # 1) 공식 Target API 전체 조회. 타입 후보를 붙이지 않는다.
    res_all, all_targets = _fetch_all_target_objects(api_key, secret_key, cid, owner_id)
    primary_res = res_all
    if res_all.status_code == 200:
        rows.extend([row for row in (all_targets or []) if isinstance(row, dict)])
    elif res_all.status_code != 404:
        messages.append(f"전체 타겟 조회 실패: {res_all.text}")

    # 2) 광고그룹 상세 응답의 targets 배열 fallback.
    try:
        res_adg, adg_obj = _fetch_adgroup_detail(api_key, secret_key, cid, owner_id)
        if res_adg.status_code == 200 and isinstance(adg_obj, dict):
            raw_detail_targets = adg_obj.get("targets")
            if isinstance(raw_detail_targets, list):
                detail_rows = [row for row in raw_detail_targets if isinstance(row, dict)]
            elif isinstance(raw_detail_targets, dict):
                detail_rows = [raw_detail_targets]
            rows.extend(detail_rows)
        elif res_adg.status_code not in {200, 404}:
            messages.append(f"광고그룹 상세 조회 참고: {res_adg.text[:180]}")
    except Exception as e:
        messages.append(f"광고그룹 상세 targets 조회 예외: {e}")

    # 3) 실제 응답에서 발견된 프로필 targetTp만 보강 조회한다.
    seen_profile_types = _unique_keep_order([
        _target_type_from_obj(row) for row in rows
        if _is_extra_copy_target_type(_target_type_from_obj(row))
    ])
    for target_type in seen_profile_types:
        try:
            res_one, target_obj = _fetch_target_object(api_key, secret_key, cid, owner_id, target_type)
        except Exception as e:
            messages.append(f"{_target_type_label(target_type)} 타겟 조회 예외: {e}")
            continue
        if res_one.status_code == 200 and target_obj:
            rows.append(target_obj)
        elif res_one.status_code not in {200, 404}:
            txt = str(res_one.text or "").strip()
            if txt and len(messages) < 6 and _target_fetch_notice(txt):
                messages.append(f"{_target_type_label(target_type)} 타겟 조회 참고: {txt[:180]}")

    copyable = _dedupe_target_objects_by_type(rows)
    if res_all.status_code != 200 and copyable:
        primary_res = _make_fake_response(200, "상세 fallback으로 타겟 확인")
    if not copyable:
        messages.append(_profile_target_absence_message(adg_obj, detail_rows))
    else:
        labels = [_target_type_label(_target_type_from_obj(row)) for row in copyable]
        messages.append("원본 프로필 타겟 확인: " + ", ".join(_unique_keep_order(labels)))
    return primary_res, copyable, messages

def _copy_profile_targets_exact(api_key: str, secret_key: str, cid: str, source_owner_id: str, target_owner_id: str):
    messages: List[str] = []
    overall_ok = True
    res_src, src_targets, fetch_messages = _fetch_copyable_adgroup_target_objects(api_key, secret_key, cid, source_owner_id)
    if fetch_messages:
        messages.extend([m for m in fetch_messages if m][:8])
    if res_src.status_code != 200 and not src_targets:
        return False, messages + [f"추가 타겟 조회 실패: {res_src.text}"]
    if not src_targets:
        # 이전에는 여기서 True, [] 로 끝나 복사 화면에서 조용히 누락됐다.
        # 복사/일괄적용 모두 원본 타겟을 못 잡은 사실을 반드시 표시한다.
        return False, messages or ["추가 타겟 원본 설정 없음"]
    copied_types: List[str] = []
    for src_target in src_targets:
        target_type = _target_type_from_obj(src_target)
        if not _is_extra_copy_target_type(target_type):
            continue
        ok, msg = _copy_target_payload_from_source_obj(api_key, secret_key, cid, src_target, target_owner_id)
        if ok:
            copied_types.append(target_type)
        else:
            overall_ok = False
            messages.append(msg)
    if copied_types:
        copied_labels = [_target_type_label(tp) for tp in copied_types]
        messages.append("추가 타겟 복사 완료: " + ", ".join(_unique_keep_order(copied_labels)))
    elif overall_ok:
        overall_ok = False
        messages.append("추가 타겟 원본 설정 없음")
    return overall_ok, messages
def _extract_schedule_codes_from_payload(payload: Any) -> List[str]:
    found: List[str] = []
    seen = set()
    day_token_to_num = {
        "MON": 1, "MONDAY": 1, "MO": 1, "월": 1,
        "TUE": 2, "TUESDAY": 2, "TU": 2, "화": 2,
        "WED": 3, "WEDNESDAY": 3, "WE": 3, "수": 3,
        "THU": 4, "THURSDAY": 4, "TH": 4, "목": 4,
        "FRI": 5, "FRIDAY": 5, "FR": 5, "금": 5,
        "SAT": 6, "SATURDAY": 6, "SA": 6, "토": 6,
        "SUN": 7, "SUNDAY": 7, "SU": 7, "일": 7,
    }

    def _append_code(code: Any):
        value = str(code or "").strip().upper()
        if re.fullmatch(r"SD[A-Z]{2,3}\d{4}", value) and value not in seen:
            seen.add(value)
            found.append(value)

    def _coerce_hour(value: Any):
        if value is None:
            return None
        if isinstance(value, str):
            m = re.search(r"(\d{1,2})", value)
            if not m:
                return None
            value = m.group(1)
        try:
            n = int(value)
        except Exception:
            return None
        return n if 0 <= n <= 24 else None

    def _coerce_day_num(value: Any):
        if value is None:
            return None
        if isinstance(value, (int, float)):
            n = int(value)
            return n if n in DAY_NUM_TO_CODE else None
        token = str(value or "").strip().upper()
        if not token:
            return None
        if token.isdigit():
            n = int(token)
            return n if n in DAY_NUM_TO_CODE else None
        return day_token_to_num.get(token)

    def visit(node: Any):
        if isinstance(node, dict):
            for k in ("dictionaryCode", "code"):
                if k in node:
                    _append_code(node.get(k))
            day_num = None
            for dk in ("day", "dayOfWeek", "weekDay", "weekday", "dayCode"):
                if dk in node:
                    day_num = _coerce_day_num(node.get(dk))
                    if day_num:
                        break
            start_h = None
            for sk in ("start", "startHour", "startTm", "startTime", "beginHour"):
                if sk in node:
                    start_h = _coerce_hour(node.get(sk))
                    if start_h is not None:
                        break
            end_h = None
            for ek in ("end", "endHour", "endTm", "endTime", "finishHour"):
                if ek in node:
                    end_h = _coerce_hour(node.get(ek))
                    if end_h is not None:
                        break
            if day_num and start_h is not None and end_h is not None and 0 <= start_h <= 23 and 1 <= end_h <= 24 and end_h != start_h:
                day_code = DAY_NUM_TO_CODE.get(day_num)
                if day_code:
                    for hour in _schedule_block_hours(start_h, end_h):
                        _append_code(f"SD{day_code}{hour:02d}{hour + 1:02d}")
            for value in node.values():
                visit(value)
            return
        if isinstance(node, list):
            for item in node:
                visit(item)
            return
        if isinstance(node, str):
            _append_code(node)

    visit(payload)
    return found

def _fetch_schedule_entries(api_key: str, secret_key: str, cid: str, owner_id: str):
    owner_id = str(owner_id or "").strip()
    if not owner_id:
        return _make_fake_response(400, "ownerId가 없습니다."), []

    # v14: /ncc/criterion/{ownerId}/SD 단일 GET은 계정/환경에 따라 405가 날 수 있다.
    # AG/GN/RL 조회에 성공한 criterion fallback과 동일하게 여러 조회 경로를 순차 시도한다.
    attempts: List[str] = []
    request_variants = [
        (f"/ncc/criterion/{owner_id}/SD", None),
        (f"/ncc/criterion/{owner_id}", {"type": "SD"}),
        ("/ncc/criterion", {"ownerId": owner_id, "type": "SD"}),
        (f"/ncc/criteria/{owner_id}/SD", None),
        ("/ncc/criteria", {"ownerId": owner_id, "type": "SD"}),
    ]
    first_res = None
    saw_not_found = False
    for uri, params in request_variants:
        res = _do_req("GET", api_key, secret_key, cid, uri, params=params)
        if first_res is None:
            first_res = res
        attempts.append(f"GET {uri}{'?' + urlencode(params) if params else ''} -> {res.status_code}")
        if res.status_code in {404, 204}:
            saw_not_found = True
            continue
        if res.status_code != 200:
            continue
        try:
            data = res.json() or []
        except Exception:
            data = []
        if isinstance(data, dict):
            for list_key in ("data", "items", "rows", "contents"):
                if isinstance(data.get(list_key), list):
                    data = data.get(list_key)
                    break
            else:
                data = [data]
        rows = [item for item in data if isinstance(item, dict)]
        fake = _make_fake_response(200, "OK")
        try:
            setattr(fake, "debug_attempts", attempts)
        except Exception:
            pass
        return fake, rows

    # 마지막 fallback: 광고그룹 상세/속성 안에 SD 코드가 노출되는 경우만 보정한다.
    res_adg, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, owner_id)
    if res_adg.status_code == 200 and isinstance(adgroup_obj, dict):
        fallback_codes = _extract_schedule_codes_from_payload(adgroup_obj)
        if fallback_codes:
            fallback_rows = [{"dictionaryCode": code, "bidWeight": 100} for code in fallback_codes]
            fake = _make_fake_response(200, "SCHEDULE adgroup fallback")
            try:
                setattr(fake, "debug_attempts", attempts + ["adgroup detail fallback -> codes"])
            except Exception:
                pass
            return fake, fallback_rows

    if saw_not_found:
        fallback = _make_fake_response(404, "SCHEDULE 원본 설정 없음")
    else:
        fallback = first_res or _make_fake_response(404, "SCHEDULE criterion 조회 결과 없음")
    try:
        setattr(fallback, "debug_attempts", attempts)
        if getattr(fallback, "status_code", None) not in {200, 404} and attempts:
            fallback._content = ("SCHEDULE 조회 실패: " + " / ".join(attempts[:5])).encode("utf-8")
    except Exception:
        pass
    return fallback, []

def _copy_schedule_criterion_exact(api_key: str, secret_key: str, cid: str, source_owner_id: str, target_owner_id: str):
    res_src, src_rows = _fetch_schedule_entries(api_key, secret_key, cid, source_owner_id)
    if res_src.status_code == 404:
        return False, "SCHEDULE 원본 설정 없음"
    if res_src.status_code != 200:
        return False, f"SCHEDULE 원본 조회 실패: {res_src.text}"
    codes: List[str] = []
    bid_weight_map: Dict[str, int] = {}
    for row in (src_rows or []):
        code = str(row.get("dictionaryCode") or row.get("code") or "").strip()
        if not code:
            continue
        codes.append(code)
        try:
            bid_weight = int(row.get("bidWeight") or 100)
        except Exception:
            bid_weight = 100
        bid_weight_map[code] = bid_weight
    codes = _unique_keep_order(codes)
    if not codes:
        return False, "SCHEDULE 원본 설정 없음"
    body = [{"customerId": int(cid), "ownerId": str(target_owner_id), "dictionaryCode": code, "type": "SD"} for code in codes]
    res_put = _do_req("PUT", api_key, secret_key, cid, f"/ncc/criterion/{target_owner_id}/SD", json_body=body)
    if res_put.status_code != 200:
        return False, f"SCHEDULE 적용 실패: {res_put.text}"
    weight_groups: Dict[int, List[str]] = defaultdict(list)
    for code in codes:
        try:
            weight = int(bid_weight_map.get(code, 100) or 100)
        except Exception:
            weight = 100
        weight_groups[weight].append(code)
    for bid_weight, group_codes in weight_groups.items():
        if int(bid_weight) == 100 or not group_codes:
            continue
        for i in range(0, len(group_codes), 50):
            chunk = group_codes[i:i + 50]
            res_bw = _do_req(
                "PUT",
                api_key,
                secret_key,
                cid,
                f"/ncc/criterion/{target_owner_id}/bidWeight",
                params={"codes": ",".join(chunk), "bidWeight": int(bid_weight)},
            )
            if res_bw.status_code != 200:
                return False, f"SCHEDULE 입찰가중치 적용 실패: {res_bw.text}"
    # 적용 후 같은 조회 경로로 재조회해 실제 코드가 들어갔는지 확인한다.
    res_check, check_rows = _fetch_schedule_entries(api_key, secret_key, cid, target_owner_id)
    if res_check.status_code == 200:
        check_codes = _unique_keep_order([str((row or {}).get("dictionaryCode") or (row or {}).get("code") or "").strip() for row in (check_rows or [])])
        missing = [code for code in codes if code not in check_codes]
        if missing:
            return False, f"SCHEDULE 적용 후 미반영: 누락 {len(missing)}개 / 예: {', '.join(missing[:5])}"
    return True, f"SCHEDULE 복사 완료: 요일/시간 {len(codes)}개"

PROFILE_CRITERION_TYPE_CANDIDATES: List[Tuple[str, str]] = [
    # 네이버 Criterion Master 실제 type 기준: SD, AG, GN, RL, RP, AD.
    # v12에서는 지역을 RG/RT로 추측해서 원본 없음으로 빠질 수 있었다.
    # 지역 타겟은 RL/RP, 성별은 GN, 연령은 AG를 우선 사용하고, AD는
    # 잠재고객/이용자 세그먼트류 후보로 함께 보정 복사한다.
    ("AG", "연령대"),
    ("GN", "성별"),
    ("RL", "지역"),
    ("RP", "반경/지역"),
    ("AD", "이용자 세그먼트"),
]

PROFILE_CRITERION_CATEGORY_TYPES: Dict[str, List[str]] = {
    "age": ["AG"],
    "gender": ["GN"],
    "region": ["RL", "RP"],
    "segment": ["AD"],
}

AGE_CRITERION_OPTIONS: List[Dict[str, str]] = [
    {"code": "AG0013", "label": "14세 미만"},
    {"code": "AG1418", "label": "14세 ~ 18세"},
    {"code": "AG1924", "label": "19세 ~ 24세"},
    {"code": "AG2529", "label": "25세 ~ 29세"},
    {"code": "AG3034", "label": "30세 ~ 34세"},
    {"code": "AG3539", "label": "35세 ~ 39세"},
    {"code": "AG4044", "label": "40세 ~ 44세"},
    {"code": "AG4549", "label": "45세 ~ 49세"},
    {"code": "AG5054", "label": "50세 ~ 54세"},
    {"code": "AG5559", "label": "55세 ~ 59세"},
    {"code": "AG6099", "label": "60세 이상"},
    {"code": "AGXXXX", "label": "연령 알 수 없음"},
]
AGE_CRITERION_LABELS: Dict[str, str] = {item["code"]: item["label"] for item in AGE_CRITERION_OPTIONS}
AGE_CRITERION_CODE_ALIASES: Dict[str, List[str]] = {item["code"]: [item["code"]] for item in AGE_CRITERION_OPTIONS}
AGE_CRITERION_CODE_ALIASES["AG6099"].append("AG60XX")
AGE_CRITERION_CANONICAL_BY_ALIAS: Dict[str, str] = {
    alias: canonical
    for canonical, aliases in AGE_CRITERION_CODE_ALIASES.items()
    for alias in aliases
}
AGE_CRITERION_LABELS["AG60XX"] = "60세 이상"
AGE_NON_EXPOSABLE_CANONICAL_CODES = {"AG0013"}

def _normalize_profile_criterion_types(types: Any = None) -> List[str]:
    """Return valid profile Criterion type codes in the supported order."""
    all_types = [tp for tp, _ in PROFILE_CRITERION_TYPE_CANDIDATES]
    if types is None:
        return list(all_types)
    if isinstance(types, str):
        raw = [types]
    else:
        try:
            raw = list(types or [])
        except Exception:
            raw = []
    expanded: List[str] = []
    for item in raw:
        token = str(item or "").strip()
        if not token:
            continue
        low = token.lower()
        if low in PROFILE_CRITERION_CATEGORY_TYPES:
            expanded.extend(PROFILE_CRITERION_CATEGORY_TYPES[low])
        else:
            expanded.append(token.upper())
    valid = set(all_types)
    return _unique_keep_order([tp for tp in expanded if tp in valid])

def _fetch_criterion_entries(api_key: str, secret_key: str, cid: str, owner_id: str, criterion_type: str):
    owner_id = str(owner_id or "").strip()
    criterion_type = str(criterion_type or "").strip().upper()
    if not owner_id or not criterion_type:
        return _make_fake_response(400, "ownerId 또는 criterion type이 없습니다."), []

    attempts: List[str] = []
    request_variants = [
        (f"/ncc/criterion/{owner_id}/{criterion_type}", None),
        (f"/ncc/criterion/{owner_id}", {"type": criterion_type}),
        ("/ncc/criterion", {"ownerId": owner_id, "type": criterion_type}),
        (f"/ncc/criteria/{owner_id}/{criterion_type}", None),
        ("/ncc/criteria", {"ownerId": owner_id, "type": criterion_type}),
    ]
    first_res = None
    for uri, params in request_variants:
        res = _do_req("GET", api_key, secret_key, cid, uri, params=params)
        if first_res is None:
            first_res = res
        attempts.append(f"GET {uri}{'?' + urlencode(params) if params else ''} -> {res.status_code}")
        if res.status_code != 200:
            continue
        try:
            data = res.json() or []
        except Exception:
            data = []
        if isinstance(data, dict):
            for list_key in ("data", "items", "rows", "contents"):
                if isinstance(data.get(list_key), list):
                    data = data.get(list_key)
                    break
            else:
                data = [data]
        rows = [item for item in data if isinstance(item, dict)]
        fake = _make_fake_response(200, "OK")
        setattr(fake, "debug_attempts", attempts)
        return fake, rows
    fallback = first_res or _make_fake_response(404, "criterion 조회 결과 없음")
    try:
        setattr(fallback, "debug_attempts", attempts)
    except Exception:
        pass
    return fallback, []


def _fetch_criterion_dictionary_entries(api_key: str, secret_key: str, cid: str, criterion_type: str):
    criterion_type = str(criterion_type or "").strip().upper()
    if not criterion_type:
        return _make_fake_response(400, "criterion type이 없습니다."), []
    res = _do_req("GET", api_key, secret_key, cid, f"/ncc/criterion-dictionary/{criterion_type}")
    if res.status_code != 200:
        return res, []
    try:
        data = res.json() or []
    except Exception:
        data = []
    if isinstance(data, dict):
        for list_key in ("data", "items", "rows", "contents"):
            if isinstance(data.get(list_key), list):
                data = data.get(list_key)
                break
        else:
            data = [data]
    return res, [item for item in data if isinstance(item, dict)]


def _age_label_key(value: Any) -> str:
    text = str(value or "").strip().lower()
    text = text.replace("만", "")
    return re.sub(r"[\s~\-–—_()/]+", "", text)


def _canonical_age_code_for_dictionary_row(code: str, label: str) -> Optional[str]:
    code = str(code or "").strip().upper()
    label_key = _age_label_key(label)
    if code in AGE_CRITERION_CANONICAL_BY_ALIAS:
        return AGE_CRITERION_CANONICAL_BY_ALIAS[code]
    for item in AGE_CRITERION_OPTIONS:
        if label_key and label_key == _age_label_key(item.get("label")):
            return item["code"]
    if "60" in label_key and ("이상" in label_key or "세이상" in label_key):
        return "AG6099"
    if "알" in label_key and ("없" in label_key or "수없" in label_key):
        return "AGXXXX"
    return None


def _resolve_age_criterion_options(api_key: str, secret_key: str, cid: str) -> Tuple[List[Dict[str, str]], str]:
    res, rows = _fetch_criterion_dictionary_entries(api_key, secret_key, cid, "AG")
    if res.status_code != 200 or not rows:
        return [dict(item, canonical_code=item["code"]) for item in AGE_CRITERION_OPTIONS], (
            f"연령대 사전 조회 실패로 기본 코드를 사용했습니다: {_response_detail_text(res)}"
        )

    actual_by_canonical: Dict[str, str] = {}
    for row in rows:
        code = str(_row_first_present(row, ["dictionaryCode", "code", "criterionCode", "targetCode"], "") or "").strip().upper()
        label = str(_row_first_present(row, ["codeName", "name", "label", "description", "text"], "") or "").strip()
        if not code.startswith("AG"):
            continue
        canonical = _canonical_age_code_for_dictionary_row(code, label)
        if canonical and canonical not in actual_by_canonical:
            actual_by_canonical[canonical] = code

    resolved: List[Dict[str, str]] = []
    missing: List[str] = []
    for item in AGE_CRITERION_OPTIONS:
        canonical = item["code"]
        actual_code = actual_by_canonical.get(canonical)
        if not actual_code:
            for alias in AGE_CRITERION_CODE_ALIASES.get(canonical, [canonical]):
                if alias in actual_by_canonical.values():
                    actual_code = alias
                    break
        if actual_code:
            resolved.append({"code": actual_code, "label": item["label"], "canonical_code": canonical})
        else:
            resolved.append({"code": canonical, "label": item["label"], "canonical_code": canonical})
            missing.append(item["label"])
    warning = ""
    if missing:
        warning = "연령대 사전에서 일부 코드를 찾지 못해 기본 코드를 사용했습니다: " + ", ".join(missing[:4])
    return resolved, warning

