def _verify_unconfirmed_keyword_creates(api_key: str, secret_key: str, cid: str, adg_id: str, classified: List[Dict[str, Any]], chunk: List[Tuple[int, Dict[str, Any]]]) -> List[Dict[str, Any]]:
    unconfirmed_rows = {
        int(item.get("row_no") or 0)
        for item in classified
        if not item.get("ok") and str(item.get("detail") or "").startswith(KEYWORD_CREATE_UNCONFIRMED_DETAIL)
    }
    if not unconfirmed_rows:
        return classified
    payload_by_row = {idx: payload for idx, payload in chunk}
    found_by_keyword: Dict[str, Dict[str, Any]] = {}
    last_lookup_note = ""
    last_lookup_count: Optional[int] = None
    for attempt in range(3):
        if attempt:
            time.sleep(0.35 * attempt)
        rows, lookup_note = _fetch_adgroup_keyword_rows(api_key, secret_key, cid, adg_id)
        last_lookup_note = lookup_note
        if rows is None:
            continue
        last_lookup_count = len(rows)
        found_by_keyword = {_keyword_row_text(row): row for row in rows if _keyword_row_text(row)}
        if all(_normalize_keyword_for_create((payload_by_row.get(row_no) or {}).get("keyword")) in found_by_keyword for row_no in unconfirmed_rows):
            break
    verified: List[Dict[str, Any]] = []
    for item in classified:
        row_no = int(item.get("row_no") or 0)
        if row_no not in unconfirmed_rows:
            verified.append(item)
            continue
        payload = payload_by_row.get(row_no) or {}
        keyword_norm = _normalize_keyword_for_create(payload.get("keyword"))
        found = found_by_keyword.get(keyword_norm)
        if found:
            verified_item = dict(item)
            verified_item["ok"] = True
            verified_item["detail"] = "등록 확인 완료"
            keyword_id = str((found or {}).get("nccKeywordId") or (found or {}).get("keywordId") or (found or {}).get("id") or "").strip()
            if keyword_id:
                verified_item["keyword_id"] = keyword_id
            verified.append(verified_item)
        else:
            failed_item = dict(item)
            count_note = f" 재조회 키워드 수: {last_lookup_count}개." if last_lookup_count is not None else ""
            lookup_note = f" {last_lookup_note}" if last_lookup_note else ""
            failed_item["detail"] = f"키워드 등록 응답에 생성 ID가 없고, 재조회에서도 등록된 키워드를 찾지 못했습니다.{count_note}{lookup_note}"
            verified.append(failed_item)
    return verified

def _retry_unconfirmed_keyword_creates(api_key: str, secret_key: str, cid: str, adg_id: str, classified: List[Dict[str, Any]], chunk: List[Tuple[int, Dict[str, Any]]]) -> List[Dict[str, Any]]:
    payload_by_row = {idx: payload for idx, payload in chunk}
    retried_by_row: Dict[int, Dict[str, Any]] = {}
    for item in classified:
        row_no = int(item.get("row_no") or 0)
        if item.get("ok") or not str(item.get("detail") or "").startswith(KEYWORD_CREATE_UNCONFIRMED_DETAIL):
            continue
        payload = payload_by_row.get(row_no)
        if not payload:
            continue
        single = _do_req("POST", api_key, secret_key, cid, "/ncc/keywords", json_body=[payload])
        if getattr(single, "status_code", 0) in [200, 201]:
            retry_result = _classify_keyword_create_success_response(single, [(row_no, payload)])
            retry_result = _verify_unconfirmed_keyword_creates(api_key, secret_key, cid, adg_id, retry_result, [(row_no, payload)])
            retried_by_row[row_no] = retry_result[0] if retry_result else item
        else:
            retry_result = _verify_unconfirmed_keyword_creates(
                api_key,
                secret_key,
                cid,
                adg_id,
                [_result_item(row_no, False, str(payload.get("keyword")), _keyword_create_unconfirmed_detail(single))],
                [(row_no, payload)],
            )
            retried_by_row[row_no] = retry_result[0] if retry_result else _result_item(row_no, False, str(payload.get("keyword")), _keyword_limit_error_detail(getattr(single, "text", "")))
    return [retried_by_row.get(int(item.get("row_no") or 0), item) for item in classified]

def _bulk_create_keywords(api_key: str, secret_key: str, cid: str, rows: List[Dict[str, Any]]):
    grouped: Dict[str, List[Tuple[int, Dict[str, Any]]]] = defaultdict(list)
    results = []
    success = fail = 0
    for idx, row in enumerate(rows, start=1):
        payload = _prepare_payload_row(row, "keyword", cid)
        adg_id = str(payload.get("nccAdgroupId") or "").strip()
        name = str(payload.get("keyword") or f"{idx}행")
        if not adg_id or not payload.get("keyword"):
            fail += 1
            results.append(_result_item(idx, False, name, "nccAdgroupId / keyword는 필수입니다."))
            continue
        grouped[adg_id].append((idx, payload))
    for adg_id, items in list(grouped.items()):
        existing_rows, _lookup_note = _fetch_adgroup_keyword_rows(api_key, secret_key, cid, adg_id)
        if existing_rows is None:
            continue
        existing_keywords = {_keyword_row_text(row) for row in existing_rows if _keyword_row_text(row)}
        new_keywords = {
            _normalize_keyword_for_create(payload.get("keyword"))
            for _, payload in items
            if _normalize_keyword_for_create(payload.get("keyword")) not in existing_keywords
        }
        if len(existing_rows) + len(new_keywords) > POWERLINK_KEYWORD_LIMIT_PER_ADGROUP:
            detail = (
                f"광고그룹 키워드 등록 한도 초과: 현재 {len(existing_rows):,}개, "
                f"신규 {len(new_keywords):,}개, 최대 {POWERLINK_KEYWORD_LIMIT_PER_ADGROUP:,}개"
            )
            for idx, payload in items:
                fail += 1
                results.append(_result_item(idx, False, str(payload.get("keyword")), detail))
            grouped.pop(adg_id, None)
    batch_size = 30
    for adg_id, items in grouped.items():
        for start_idx in range(0, len(items), batch_size):
            chunk = items[start_idx:start_idx + batch_size]
            payloads = [x[1] for x in chunk]
            res = _do_req("POST", api_key, secret_key, cid, "/ncc/keywords", params={"nccAdgroupId": adg_id}, json_body=payloads)
            if res.status_code in [200, 201]:
                classified = _classify_keyword_create_success_response(res, chunk)
                classified = _verify_unconfirmed_keyword_creates(api_key, secret_key, cid, adg_id, classified, chunk)
                classified = _retry_unconfirmed_keyword_creates(api_key, secret_key, cid, adg_id, classified, chunk)
                for item in classified:
                    if item.get("ok"):
                        success += 1
                    else:
                        fail += 1
                    results.append(item)
                continue
            verified_existing = _verify_unconfirmed_keyword_creates(
                api_key,
                secret_key,
                cid,
                adg_id,
                [_result_item(idx, False, str(payload.get("keyword")), _keyword_create_unconfirmed_detail(res)) for idx, payload in chunk],
                chunk,
            )
            if any(item.get("ok") for item in verified_existing):
                for item in verified_existing:
                    if item.get("ok"):
                        success += 1
                        results.append(item)
                    else:
                        fail += 1
                        row_no = int(item.get("row_no") or 0)
                        payload = next((payload for idx, payload in chunk if idx == row_no), {})
                        results.append(_result_item(row_no, False, str(payload.get("keyword") or item.get("name") or row_no), _keyword_limit_error_detail(res.text)))
                continue
            if _looks_like_keyword_limit_error(getattr(res, "text", "")):
                detail = _keyword_limit_error_detail(res.text)
                for idx, payload in chunk:
                    fail += 1
                    results.append(_result_item(idx, False, str(payload.get("keyword")), detail))
                continue
            with ThreadPoolExecutor(max_workers=min(8, len(chunk))) as ex:
                future_map = {
                    ex.submit(_do_req, "POST", api_key, secret_key, cid, "/ncc/keywords", None, [payload]): (idx, payload)
                    for idx, payload in chunk
                }
                for fut in as_completed(future_map):
                    idx, payload = future_map[fut]
                    try:
                        single = fut.result()
                    except Exception as e:
                        fail += 1
                        results.append(_result_item(idx, False, str(payload.get("keyword")), str(e)))
                        continue
                    if single.status_code in [200, 201]:
                        classified = _classify_keyword_create_success_response(single, [(idx, payload)])
                        classified = _verify_unconfirmed_keyword_creates(api_key, secret_key, cid, adg_id, classified, [(idx, payload)])
                        item = classified[0] if classified else _result_item(idx, True, str(payload.get("keyword")), "생성 완료")
                        if item.get("ok"):
                            success += 1
                        else:
                            fail += 1
                        results.append(item)
                    else:
                        verified_existing = _verify_unconfirmed_keyword_creates(
                            api_key,
                            secret_key,
                            cid,
                            adg_id,
                            [_result_item(idx, False, str(payload.get("keyword")), _keyword_create_unconfirmed_detail(single))],
                            [(idx, payload)],
                        )
                        if verified_existing and verified_existing[0].get("ok"):
                            success += 1
                            results.append(verified_existing[0])
                            continue
                        fail += 1
                        results.append(_result_item(idx, False, str(payload.get("keyword")), _keyword_limit_error_detail(single.text)))
    return success, fail, sorted(results, key=lambda x: x["row_no"])
def _post_one_ad(api_key: str, secret_key: str, cid: str, row_no: int, payload: Dict[str, Any]):
    adg_id = str(payload.get("nccAdgroupId") or "").strip()
    ad_type = str(payload.get("type") or "")
    name = str((payload.get("ad") or {}).get("headline") if isinstance(payload.get("ad"), dict) else payload.get("type") or f"{row_no}행")
    if not adg_id or not ad_type:
        return _result_item(row_no, False, name, "nccAdgroupId / type는 필수입니다.")
    body = copy.deepcopy(payload)
    if ad_type == "TEXT_45":
        ad = body.get("ad") or {}
        if not isinstance(ad, dict):
            return _result_item(row_no, False, name, "TEXT_45 소재는 ad JSON 객체가 필요합니다.")
        if isinstance(ad.get("pc"), dict) and ad["pc"].get("final") and not ad["pc"].get("display"):
            ad["pc"]["display"] = _display_url_from_final(ad["pc"]["final"])
        if isinstance(ad.get("mobile"), dict) and ad["mobile"].get("final") and not ad["mobile"].get("display"):
            ad["mobile"]["display"] = _display_url_from_final(ad["mobile"]["final"])
        missing = []
        if not ad.get("headline"):
            missing.append("headline")
        if not ad.get("description"):
            missing.append("description")
        if not (ad.get("pc") or {}).get("final"):
            missing.append("pc.final")
        if not (ad.get("mobile") or {}).get("final"):
            missing.append("mobile.final")
        if missing:
            return _result_item(row_no, False, name, f"TEXT_45 필수값 누락: {', '.join(missing)}")
        body["ad"] = ad
    if ad_type in SHOPPING_AD_TYPES:
        if "ad" not in body:
            body["ad"] = {}
        res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": adg_id, "isList": "true"}, json_body=[body])
    else:
        res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": adg_id}, json_body=body)
    if res.status_code in [200, 201]:
        item = _created_item_from_response(res)
        ad_id = str(item.get("nccAdId") or item.get("id") or "").strip()
        return _result_item(row_no, True, name, "생성 완료", nccAdId=ad_id, item=item)
    return _result_item(row_no, False, name, res.text)
def _bulk_create_ads(api_key: str, secret_key: str, cid: str, rows: List[Dict[str, Any]]):
    prepared = [(idx, _prepare_payload_row(row, "ad", cid)) for idx, row in enumerate(rows, start=1)]
    results = []
    with ThreadPoolExecutor(max_workers=5) as executor:
        futures = [executor.submit(_post_one_ad, api_key, secret_key, cid, idx, payload) for idx, payload in prepared]
        for future in as_completed(futures):
            results.append(future.result())
    success = sum(1 for x in results if x["ok"])
    fail = sum(1 for x in results if not x["ok"])
    return success, fail, sorted(results, key=lambda x: x["row_no"])
def _bulk_create_extensions(api_key: str, secret_key: str, cid: str, rows: List[Dict[str, Any]]):
    results = []
    success = fail = 0
    for idx, row in enumerate(rows, start=1):
        payload = _prepare_payload_row(row, "ad_extension", cid)
        owner_id = str(payload.get("ownerId") or "").strip()
        ext_type = str(payload.get("type") or "")
        name = str(payload.get("title") or ext_type or f"{idx}행")
        if not owner_id or not ext_type:
            fail += 1
            results.append(_result_item(idx, False, name, "ownerId / type는 필수입니다."))
            continue
        res = _do_req("POST", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": owner_id}, json_body=payload)
        if res.status_code in [200, 201]:
            item = _created_item_from_response(res)
            ext_item = _extract_extension_item(item) or item
            ext_id = str((ext_item or {}).get("adExtensionId") or (ext_item or {}).get("nccAdExtensionId") or (ext_item or {}).get("id") or "").strip()
            success += 1
            results.append(_result_item(idx, True, name, "생성 완료", adExtensionId=ext_id, item=item))
        else:
            fail += 1
            results.append(_result_item(idx, False, name, res.text))
    return success, fail, results
def _merge_restricted_keyword_rows(existing_rows: List[Dict[str, Any]], new_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    merged: List[Dict[str, Any]] = []
    seen = set()
    for item in (existing_rows or []):
        kw = str(item.get("keyword") or "").strip()
        if not kw:
            continue
        tp = _normalize_negative_type(item.get("type") or item.get("matchType") or 1)
        key = (kw.lower(), tp)
        if key not in seen:
            seen.add(key)
            merged.append({"keyword": kw, "type": tp})
    for item in (new_rows or []):
        kw = str(item.get("keyword") or "").strip()
        if not kw:
            continue
        tp = _normalize_negative_type(item.get("type") or item.get("matchType") or 1)
        key = (kw.lower(), tp)
        if key not in seen:
            seen.add(key)
            merged.append({"keyword": kw, "type": tp})
    return merged
def _upsert_shopping_restricted_keywords(api_key: str, secret_key: str, cid: str, adgroup_id: str, rows: List[Dict[str, Any]]):
    res_target, target_obj = _fetch_target_restrict_object(api_key, secret_key, cid, adgroup_id)
    if res_target.status_code != 200:
        return res_target
    if not target_obj or not target_obj.get("nccTargetId"):
        return _make_fake_response(400, "쇼핑 제외키워드 Target 정보를 찾지 못했습니다. 광고센터에서 해당 광고그룹의 제외키워드를 한 번 저장한 뒤 다시 시도해주세요.")
    merged = _merge_restricted_keyword_rows(_extract_restricted_rows_from_target(target_obj), rows)
    payload = {
        "nccTargetId": target_obj.get("nccTargetId"),
        "ownerId": adgroup_id,
        "targetTp": "RESTRICT_KEYWORD_TARGET",
        "target": merged,
        "delFlag": False,
    }
    return _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)

def _normalize_restricted_keyword_delete_match_mode(value: Any) -> str:
    s = str(value or "").strip().lower()
    if s in {"contains", "partial", "include", "included", "부분", "부분일치", "포함"}:
        return "contains"
    return "exact"

def _parse_restricted_keyword_delete_terms(value: Any) -> List[str]:
    if isinstance(value, (list, tuple, set)):
        raw_parts = [str(x or "") for x in value]
    else:
        raw_parts = re.split(r"[\r\n,;|]+", str(value or ""))
    terms: List[str] = []
    seen: set[str] = set()
    for part in raw_parts:
        norm = _normalize_keyword_search_text(part)
        if not norm or norm in seen:
            continue
        seen.add(norm)
        terms.append(norm)
    return terms

def _restricted_keyword_matches_delete_terms(keyword: Any, terms: List[str], match_mode: str = "exact") -> bool:
    keyword_norm = _normalize_keyword_search_text(keyword)
    if not keyword_norm or not terms:
        return False
    if _normalize_restricted_keyword_delete_match_mode(match_mode) == "contains":
        return any(term in keyword_norm for term in terms if term)
    return keyword_norm in set(terms)

def _delete_restricted_keyword(api_key: str, secret_key: str, cid: str, adgroup_id: str, keyword: str):
    adgroup_id = str(adgroup_id or "").strip()
    keyword = str(keyword or "").strip()
    if not adgroup_id or not keyword:
        return _make_fake_response(400, "광고그룹ID / 제외키워드는 필수입니다.")

    detail_res, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, adgroup_id)
    if detail_res.status_code == 200 and _is_shopping_adgroup(adgroup_obj):
        res_target, target_obj = _fetch_target_restrict_object(api_key, secret_key, cid, adgroup_id)
        if res_target.status_code != 200:
            return res_target
        if not target_obj or not target_obj.get("nccTargetId"):
            return _make_fake_response(404, "쇼핑 제외키워드 Target 정보를 찾지 못했습니다.")
        target_rows = target_obj.get("target") or []
        if not isinstance(target_rows, list):
            target_rows = []
        keyword_norm = _normalize_keyword_search_text(keyword)
        remaining = []
        removed = 0
        for item in target_rows:
            if isinstance(item, dict) and _normalize_keyword_search_text(item.get("keyword")) == keyword_norm:
                removed += 1
                continue
            remaining.append(item)
        if removed <= 0:
            return _make_fake_response(404, "삭제할 쇼핑 제외키워드를 찾지 못했습니다.")
        payload = {
            "nccTargetId": target_obj.get("nccTargetId"),
            "ownerId": adgroup_id,
            "targetTp": "RESTRICT_KEYWORD_TARGET",
            "target": remaining,
            "delFlag": False,
        }
        return _do_req("PUT", api_key, secret_key, cid, f"/ncc/targets/{target_obj.get('nccTargetId')}", json_body=payload)

    return _do_req("DELETE", api_key, secret_key, cid, "/ncc/restricted-keywords", params={"nccAdgroupId": adgroup_id, "keyword": keyword})

def _bulk_create_restricted_keywords(api_key: str, secret_key: str, cid: str, rows: List[Dict[str, Any]]):
    grouped: Dict[str, List[Tuple[int, Dict[str, Any]]]] = defaultdict(list)
    results = []
    success = fail = 0
    for idx, row in enumerate(rows, start=1):
        payload = _prepare_payload_row(row, "restricted_keyword", cid)
        adg_id = str(payload.get("nccAdgroupId") or "").strip()
        keyword = str(payload.get("keyword") or "").strip()
        if not adg_id or not keyword:
            fail += 1
            results.append(_result_item(idx, False, keyword or f"{idx}행", "nccAdgroupId / keyword는 필수입니다."))
            continue
        grouped[adg_id].append((idx, payload))
    for adg_id, items in grouped.items():
        _, adgroup_obj = _fetch_adgroup_detail(api_key, secret_key, cid, adg_id)
        is_shopping = _is_shopping_adgroup(adgroup_obj)
        if is_shopping:
            res = _upsert_shopping_restricted_keywords(api_key, secret_key, cid, adg_id, [x[1] for x in items])
            if res.status_code in [200, 201, 204]:
                for idx, payload in items:
                    success += 1
                    results.append(_result_item(idx, True, str(payload.get("keyword")), "등록 완료"))
            else:
                for idx, payload in items:
                    fail += 1
                    results.append(_result_item(idx, False, str(payload.get("keyword")), res.text))
            continue
        payloads = []
        for _, payload in items:
            payloads.append({
                "nccAdgroupId": adg_id,
                "keyword": str(payload.get("keyword") or "").strip(),
                "description": "노출 제한 키워드 추가",
                "type": "KEYWORD_PLUS_RESTRICT",
            })
        res = _do_req("POST", api_key, secret_key, cid, f"/ncc/adgroups/{adg_id}/restricted-keywords", json_body=payloads)
        if res.status_code in [200, 201, 204]:
            for idx, payload in items:
                success += 1
                results.append(_result_item(idx, True, str(payload.get("keyword")), "등록 완료"))
        else:
            for idx, payload in items:
                single = _do_req("POST", api_key, secret_key, cid, f"/ncc/adgroups/{adg_id}/restricted-keywords", json_body=[{
                    "nccAdgroupId": adg_id,
                    "keyword": str(payload.get("keyword") or "").strip(),
                    "description": "노출 제한 키워드 추가",
                    "type": "KEYWORD_PLUS_RESTRICT",
                }])
                if single.status_code in [200, 201, 204]:
                    success += 1
                    results.append(_result_item(idx, True, str(payload.get("keyword")), "등록 완료"))
                else:
                    fail += 1
                    results.append(_result_item(idx, False, str(payload.get("keyword")), single.text))
    return success, fail, sorted(results, key=lambda x: x["row_no"])
def _fetch_entity_detail(api_key: str, secret_key: str, cid: str, entity_type: str, entity_id: str):
    entity_id = str(entity_id or "").strip()
    if not entity_id:
        return _make_fake_response(400, "ID가 없습니다."), None
    uri_map = {
        "ad": f"/ncc/ads/{entity_id}",
        "ad_extension": f"/ncc/ad-extensions/{entity_id}",
    }
    uri = uri_map.get(entity_type)
    if not uri:
        return _make_fake_response(400, f"지원하지 않는 조회 유형: {entity_type}"), None
    res = _do_req("GET", api_key, secret_key, cid, uri)
    if res.status_code == 200:
        try:
            obj = res.json()
            if isinstance(obj, list):
                for one in obj:
                    if isinstance(one, dict):
                        return res, one
            if isinstance(obj, dict):
                return res, obj
        except Exception:
            pass
    return res, None
def _build_copy_name(base_name: str, copy_index: int, total_count: int, suffix: str = "_복사본") -> str:
    base = str(base_name or "").strip()
    if total_count > 1:
        return f"{base}{copy_index}" if copy_index > 1 else base
    return base + str(suffix or "")
def _parse_multiline_names(raw_value: Any) -> List[str]:
    values: List[str] = []
    if isinstance(raw_value, list):
        iterable = raw_value
    else:
        iterable = str(raw_value or "").replace("\r\n", "\n").replace("\r", "\n").split("\n")
    for item in iterable:
        name = str(item or "").strip()
        if name:
            values.append(name)
    return values
def _find_duplicate_names(names: List[str]) -> List[str]:
    seen: set[str] = set()
    dupes: List[str] = []
    for name in names:
        key = str(name or "").strip()
        if not key:
            continue
        if key in seen and key not in dupes:
            dupes.append(key)
            continue
        seen.add(key)
    return dupes
def _resolve_copy_names(source_names: List[str], copy_count: int, suffix: str, custom_names_raw: Any = None) -> List[str]:
    custom_names = _parse_multiline_names(custom_names_raw)
    total_needed = max(0, len(source_names)) * max(1, int(copy_count or 1))
    if custom_names:
        if len(custom_names) != total_needed:
            raise ValueError(f"직접 지정 이름은 총 {total_needed}개가 필요합니다. 현재 {len(custom_names)}개 입력됨")
        return custom_names
    resolved: List[str] = []
    for source_name in source_names:
        for idx in range(1, max(1, int(copy_count or 1)) + 1):
            resolved.append(_build_copy_name(source_name, idx, max(1, int(copy_count or 1)), suffix))
    return resolved
def _validate_name_candidates(candidates: List[str], existing_names: Iterable[str], label: str) -> Optional[str]:
    cleaned = [str(x or "").strip() for x in candidates if str(x or "").strip()]
    dupes = _find_duplicate_names(cleaned)
    if dupes:
        return f"중복된 {label} 이름이 있습니다: {', '.join(dupes[:10])}"
    existing = {str(x or "").strip() for x in existing_names if str(x or "").strip()}
    conflicts = [name for name in cleaned if name in existing]
    if conflicts:
        uniq_conflicts: List[str] = []
        for name in conflicts:
            if name not in uniq_conflicts:
                uniq_conflicts.append(name)
        return f"이미 존재하는 {label} 이름과 겹칩니다: {', '.join(uniq_conflicts[:10])}"
    return None
def _normalize_text_ad_payload(body: Dict[str, Any] | None) -> Dict[str, Any]:
    payload = copy.deepcopy(body) if isinstance(body, dict) else {}
    ad = payload.get("ad") if isinstance(payload.get("ad"), dict) else {}
    headline = str(ad.get("headline") or payload.get("headline") or "").strip()
    description = str(ad.get("description") or payload.get("description") or "").strip()
    pc = ad.get("pc") if isinstance(ad.get("pc"), dict) else {}
    mobile = ad.get("mobile") if isinstance(ad.get("mobile"), dict) else {}
    pc_final = str(pc.get("final") or payload.get("pcFinalUrl") or payload.get("finalUrl") or "").strip()
    mobile_final = str(mobile.get("final") or payload.get("mobileFinalUrl") or payload.get("mobileUrl") or pc_final).strip()
    payload["ad"] = {
        "headline": headline,
        "description": description,
        "pc": {
            "final": pc_final,
            "display": str(pc.get("display") or _display_url_from_final(pc_final)).strip(),
        },
        "mobile": {
            "final": mobile_final,
            "display": str(mobile.get("display") or _display_url_from_final(mobile_final)).strip(),
        },
    }
    return _strip_empty(payload)
def _make_ad_signature(ad_item: Dict[str, Any] | None) -> str:
    ad = ad_item if isinstance(ad_item, dict) else {}
    ad_type = _normalize_ad_type(ad.get("type") or ad.get("adType"))
    if ad_type == "TEXT_45":
        ad_body = ad.get("ad") if isinstance(ad.get("ad"), dict) else {}
        pc = ad_body.get("pc") if isinstance(ad_body.get("pc"), dict) else {}
        mobile = ad_body.get("mobile") if isinstance(ad_body.get("mobile"), dict) else {}
        return "|".join([
            ad_type,
            str(ad_body.get("headline") or "").strip(),
            str(ad_body.get("description") or "").strip(),
            str(pc.get("final") or ad.get("pcFinalUrl") or "").strip(),
            str(mobile.get("final") or ad.get("mobileFinalUrl") or pc.get("final") or "").strip(),
        ])
    if ad_type in SHOPPING_AD_TYPES:
        return "|".join([ad_type, str(ad.get("referenceKey") or _extract_reference_key_from_ad(ad) or "").strip()])
    try:
        return "|".join([ad_type, json.dumps(ad.get("ad") or ad, ensure_ascii=False, sort_keys=True)])
    except Exception:
        return "|".join([ad_type, str(ad)])
def _collect_ad_signatures(api_key: str, secret_key: str, cid: str, adgroup_id: str) -> set[str]:
    res_ads, ads = _fetch_ads(api_key, secret_key, cid, str(adgroup_id))
    if res_ads.status_code != 200:
        return set()
    return {_make_ad_signature(ad) for ad in (ads or []) if isinstance(ad, dict)}
def _retry_missing_ads(api_key: str, secret_key: str, cid: str, new_adg_id: str, payloads: List[Dict[str, Any]], existing_signatures: set[str] | None = None) -> Tuple[int, List[str]]:
    signatures = set(existing_signatures or set())
    success = 0
    errors: List[str] = []
    for payload in payloads or []:
        item = copy.deepcopy(payload) if isinstance(payload, dict) else {}
        if _normalize_ad_type(item.get("type")) == "TEXT_45":
            item = _normalize_text_ad_payload(item)
        sig = _make_ad_signature(item)
        if sig in signatures:
            continue
        ad_type = _normalize_ad_type(item.get("type"))
        if ad_type in SHOPPING_AD_TYPES:
            res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": new_adg_id, "isList": "true"}, json_body=[item])
        else:
            res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": new_adg_id}, json_body=item)
        if res.status_code in [200, 201]:
            success += 1
            signatures.add(sig)
        else:
            ad_name = str(((item.get("ad") or {}).get("headline") if isinstance(item.get("ad"), dict) else "") or item.get("type") or "")
            errors.append(f"소재 재시도 에러({ad_name}): {res.text}")
    return success, errors
def _build_copy_ad_payload(api_key: str, secret_key: str, cid: str, ad_item: Dict[str, Any], new_adg_id: str, force_on: bool = False) -> Dict[str, Any]:
    ad_item = ad_item if isinstance(ad_item, dict) else {}
    ad_id = str(ad_item.get("nccAdId") or ad_item.get("id") or "").strip()
    detail = None
    if ad_id:
        _, detail = _fetch_entity_detail(api_key, secret_key, cid, "ad", ad_id)
    src = detail if isinstance(detail, dict) and detail else copy.deepcopy(ad_item)
    payload = _prepare_payload_row(src, "ad", cid)
    payload["nccAdgroupId"] = str(new_adg_id)
    payload["customerId"] = int(cid)
    ad_type = _normalize_ad_type(payload.get("type") or src.get("type"))
    payload["type"] = ad_type
    ref_data = src.get("referenceData") if isinstance(src.get("referenceData"), dict) else {}
    if ad_type in SHOPPING_AD_TYPES:
        payload["ad"] = payload.get("ad") if isinstance(payload.get("ad"), dict) else {}
        ref_key = (
            payload.get("referenceKey")
            or src.get("referenceKey")
            or ref_data.get("mallProductId")
            or ref_data.get("id")
        )
        if ref_key:
            payload["referenceKey"] = str(ref_key)
    else:
        payload.pop("referenceKey", None)
    payload.pop("nccAdId", None)
    payload.pop("id", None)
    payload.pop("adId", None)
    payload = _copy_payload_preserve_source_state(payload, src, force_on=force_on)
    return _strip_empty(payload)
def _build_copy_extension_payload(api_key: str, secret_key: str, cid: str, ext_item: Dict[str, Any], new_owner_id: str, biz_channel_id: str | None = None, force_on: bool = False) -> Dict[str, Any]:
    ext_item = ext_item if isinstance(ext_item, dict) else {}
    ext_id = _extract_ad_extension_id(ext_item)
    detail = None
    if ext_id:
        _, detail = _fetch_entity_detail(api_key, secret_key, cid, "ad_extension", ext_id)
    src = detail if isinstance(detail, dict) and detail else copy.deepcopy(ext_item)
    payload = _prepare_payload_row(src, "ad_extension", cid)
    payload["ownerId"] = str(new_owner_id)
    payload["customerId"] = int(cid)
    ext_type = _normalize_extension_type(payload.get("type") or src.get("type"))
    payload["type"] = ext_type
    if biz_channel_id and biz_channel_id not in ["keep", "undefined"] and ext_type in ["SUB_LINKS", "POWER_LINK_IMAGE", "WEBSITE_INFO", "IMAGE_SUB_LINKS"]:
        payload["pcChannelId"] = str(biz_channel_id)
        payload["mobileChannelId"] = str(biz_channel_id)
    payload.pop("adExtensionId", None)
    payload.pop("id", None)
    if ext_type == "SHOPPING_EXTRA":
        payload.pop("adExtension", None)
    payload = _copy_payload_preserve_source_state(payload, src, force_on=force_on)
    if (not force_on) and _extract_enabled_from_entity(src) is not False:
        for state_candidate in _fetch_ad_extension_state_candidates(api_key, secret_key, cid, ext_item, ext_id):
            if _extract_enabled_from_entity(state_candidate) is False:
                payload["userLock"] = True
                break
    return _strip_empty(payload)
def _extract_created_ad_id_from_response(res: Any) -> str:
    if res is None:
        return ""
    try:
        data = res.json()
    except Exception:
        return ""
    def _walk(obj: Any) -> str:
        if isinstance(obj, dict):
            for key in ("nccAdId", "adId", "id"):
                value = str(obj.get(key) or "").strip()
                if value and (value.startswith("nad-") or value.startswith("ad-") or value.startswith("ncc") or len(value) >= 10):
                    return value
            for value in obj.values():
                found = _walk(value)
                if found:
                    return found
        elif isinstance(obj, list):
            for item in obj:
                found = _walk(item)
                if found:
                    return found
        return ""
    return _walk(data)
def _extract_reference_key_from_ad(ad_item: Dict[str, Any] | None) -> str:
    ad_item = ad_item if isinstance(ad_item, dict) else {}
    ref_data = ad_item.get("referenceData") if isinstance(ad_item.get("referenceData"), dict) else {}
    candidates = [
        ad_item.get("referenceKey"),
        ref_data.get("mallProductId"),
        ref_data.get("id"),
        ref_data.get("parentId"),
        ref_data.get("productId"),
        ref_data.get("mallProductNo"),
        ref_data.get("channelProductNo"),
        ref_data.get("productNo"),
    ]
    for value in candidates:
        s = str(value or "").strip()
        if s:
            return s
    return ""
def _classify_copy_ad_strategy(ads: List[Dict[str, Any]] | None) -> str:
    ads = [x for x in (ads or []) if isinstance(x, dict)]
    if not ads:
        return "none"
    shopping = 0
    standard = 0
    for ad in ads:
        if _normalize_ad_type(ad.get("type") or ad.get("adType")) in SHOPPING_AD_TYPES:
            shopping += 1
        else:
            standard += 1
    if shopping and standard:
        return "mixed"
    if shopping:
        return "shopping"
    return "standard"
def _find_created_ad_id_by_reference(api_key: str, secret_key: str, cid: str, adgroup_id: str, reference_key: str, before_ids: set[str] | None = None) -> str:
    reference_key = str(reference_key or "").strip()
    res_ads, ads = _fetch_ads(api_key, secret_key, cid, str(adgroup_id))
    if res_ads.status_code != 200:
        return ""
    before_ids = {str(x).strip() for x in (before_ids or set()) if str(x).strip()}
    for ad in (ads or []):
        if not isinstance(ad, dict):
            continue
        ad_id = _extract_ad_id(ad)
        if before_ids and ad_id in before_ids:
            continue
        if _extract_reference_key_from_ad(ad) == reference_key:
            return ad_id
    return ""
def _build_copy_summary(source_adgroup_id: str, target_adgroup_id: str) -> Dict[str, Any]:
    return {
        "source_adgroup_id": str(source_adgroup_id or "").strip(),
        "target_adgroup_id": str(target_adgroup_id or "").strip(),
        "strategy": "none",
        "keywords": {"source": 0, "success": 0, "fail": 0},
        "ads": {"source": 0, "success": 0, "fail": 0, "standard_source": 0, "shopping_source": 0, "skipped_off": 0},
        "group_extensions": {"source": 0, "success": 0, "fail": 0, "skipped_off": 0},
        "ad_extensions": {"source": 0, "success": 0, "fail": 0, "skipped_off": 0},
        "negatives": {"source": 0, "success": 0, "fail": 0},
        "notes": [],
    }
def _format_copy_summary(summary: Dict[str, Any]) -> str:
    if not isinstance(summary, dict):
        return "복사 요약 없음"
    strategy = str(summary.get("strategy") or "none")
    kw = summary.get("keywords") or {}
    ads = summary.get("ads") or {}
    gext = summary.get("group_extensions") or {}
    aext = summary.get("ad_extensions") or {}
    neg = summary.get("negatives") or {}
    notes = [str(x).strip() for x in (summary.get("notes") or []) if str(x).strip()]
    base = (
        f"전략={strategy} | 키워드 {int(kw.get('success') or 0)}/{int(kw.get('source') or 0)}"
        f" | 소재 {int(ads.get('success') or 0)}/{int(ads.get('source') or 0)}"
        f" (일반 {int(ads.get('standard_source') or 0)}, 쇼핑 {int(ads.get('shopping_source') or 0)})"
        f" | 그룹확장 {int(gext.get('success') or 0)}/{int(gext.get('source') or 0)}"
        f" | 소재하위확장 {int(aext.get('success') or 0)}/{int(aext.get('source') or 0)}"
        f" | 제외검색어 {int(neg.get('success') or 0)}/{int(neg.get('source') or 0)}"
    )
    skipped_off_parts = []
    if int((ads or {}).get("skipped_off") or 0):
        skipped_off_parts.append(f"소재 {int((ads or {}).get('skipped_off') or 0)}건")
    if int((gext or {}).get("skipped_off") or 0):
        skipped_off_parts.append(f"그룹확장 {int((gext or {}).get('skipped_off') or 0)}건")
    if int((aext or {}).get("skipped_off") or 0):
        skipped_off_parts.append(f"소재하위확장 {int((aext or {}).get('skipped_off') or 0)}건")
    if skipped_off_parts:
        notes.append("OFF 제외 " + ", ".join(skipped_off_parts))
    if notes:
        base += " | 참고: " + "; ".join(notes[:3])
    return base


_COPY_SUMMARY_SECTIONS = ("keywords", "ads", "group_extensions", "ad_extensions", "negatives")


def _copy_summary_int(summary: Dict[str, Any], section: str, key: str) -> int:
    try:
        return int(((summary or {}).get(section) or {}).get(key) or 0)
    except Exception:
        return 0


def _copy_summary_totals(summary: Dict[str, Any]) -> Dict[str, int]:
    if not isinstance(summary, dict):
        return {"source": 0, "success": 0, "fail": 0, "skipped_off": 0}
    totals = {
        "source": sum(_copy_summary_int(summary, section, "source") for section in _COPY_SUMMARY_SECTIONS),
        "success": sum(_copy_summary_int(summary, section, "success") for section in _COPY_SUMMARY_SECTIONS),
        "fail": sum(_copy_summary_int(summary, section, "fail") for section in _COPY_SUMMARY_SECTIONS),
        "skipped_off": sum(_copy_summary_int(summary, section, "skipped_off") for section in ("ads", "group_extensions", "ad_extensions")),
    }
    return totals


def _copy_summary_skip_reason(summary: Dict[str, Any]) -> str:
    totals = _copy_summary_totals(summary)
    if totals["skipped_off"] > 0 and totals["source"] <= 0:
        return "선택 조건 또는 OFF 제외로 복사할 항목 없음"
    if totals["source"] > 0:
        return "복사 완료 항목 없음"
    return "복사할 항목 없음"


def _normalize_copy_extension_types(values: Any) -> List[str]:
    if values is None:
        return ["ALL"]
    raw_values: List[Any] = []
    if isinstance(values, str):
        raw_values = [x for x in re.split(r"[,;\n]+", values) if str(x or "").strip()]
    elif isinstance(values, (list, tuple, set)):
        raw_values = list(values)
    else:
        raw_values = [values]
    normalized: List[str] = []
    for value in raw_values:
        norm = _normalize_bulk_extension_delete_type(value)
        if not norm:
            continue
        if norm == "ALL":
            return ["ALL"]
        if norm not in normalized:
            normalized.append(norm)
    return normalized or ["ALL"]


def _copy_extension_matches_selected_types(ext_item: Dict[str, Any], extension_types: Any) -> Tuple[bool, str]:
    selected_types = _normalize_copy_extension_types(extension_types)
    if "ALL" in selected_types:
        return True, _infer_extension_delete_type(ext_item)
    resolved_type = ""
    for selected_type in selected_types:
        matched, resolved_type = _extension_item_matches_delete_type(ext_item, selected_type)
        if matched:
            return True, resolved_type
    return False, resolved_type


def _copy_extension_type_filter_note(extension_types: Any) -> str:
    selected_types = _normalize_copy_extension_types(extension_types)
    if "ALL" in selected_types:
        return ""
    labels = [_bulk_extension_type_label(x) for x in selected_types]
    return "확장소재 유형 필터: " + ", ".join(labels)


def _copy_ad_owner_extensions(api_key: str, secret_key: str, cid: str, old_owner_id: str, new_owner_id: str, biz_channel_id: str | None = None, exclude_off_assets: bool = False, force_on: bool = False, extension_types: Any = None) -> Tuple[List[str], Dict[str, int]]:
    errors: List[str] = []
    stats = {"source": 0, "success": 0, "fail": 0, "skipped_off": 0}
    old_owner_id = str(old_owner_id or "").strip()
    new_owner_id = str(new_owner_id or "").strip()
    if not old_owner_id or not new_owner_id:
        return errors, stats
    r_ext = _do_req("GET", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": old_owner_id})
    if r_ext.status_code != 200:
        if r_ext.status_code not in [404]:
            errors.append(f"소재 확장소재 조회 실패({old_owner_id}): {r_ext.text}")
        return errors, stats
    for ext in (r_ext.json() or []):
        if not isinstance(ext, dict):
            continue
        ext = copy.deepcopy(ext)
        ext.setdefault("ownerId", old_owner_id)
        matches_type, _ = _copy_extension_matches_selected_types(ext, extension_types)
        if not matches_type:
            continue
        if _should_skip_off_copy_asset_with_detail(api_key, secret_key, cid, "ad_extension", ext, exclude_off_assets):
            stats["skipped_off"] += 1
            continue
        stats["source"] += 1
        item = _build_copy_extension_payload(api_key, secret_key, cid, ext, new_owner_id, biz_channel_id, force_on=force_on)
        res = _do_req("POST", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": new_owner_id}, json_body=item)
        if res.status_code not in [200, 201] and "4003" not in res.text:
            stats["fail"] += 1
            ext_type = _normalize_extension_type(item.get("type"))
            errors.append(f"소재 확장소재 에러({ext_type}): {res.text}")
        else:
            stats["success"] += 1
    return errors, stats
def _copy_adgroup_children(api_key, secret_key, cid, old_adg_id, new_adg_id, biz_channel_id, include_keywords=True, include_ads=True, include_extensions=True, include_negatives=True, return_summary=False, exclude_off_assets=False, force_on=False, extension_types: Any = None):
    errors: List[str] = []
    summary = _build_copy_summary(str(old_adg_id), str(new_adg_id))
    normalized_extension_types = _normalize_copy_extension_types(extension_types)
    extension_type_note = _copy_extension_type_filter_note(normalized_extension_types)
    if include_extensions and extension_type_note:
        summary["notes"].append(extension_type_note)
    if include_keywords:
        r_kw = _do_req("GET", api_key, secret_key, cid, "/ncc/keywords", params={"nccAdgroupId": old_adg_id})
    else:
        r_kw = None
    if r_kw is not None and r_kw.status_code == 200:
        new_kws = []
        for kw in r_kw.json() or []:
            item = copy.deepcopy(kw)
            for k in ['nccKeywordId', 'regTm', 'editTm', 'status', 'statusReason', 'inspectStatus', 'delFlag', 'managedKeyword', 'referenceKey']:
                item.pop(k, None)
            item.update({"nccAdgroupId": str(new_adg_id), "customerId": int(cid)})
            if force_on:
                item["userLock"] = False
            new_kws.append(item)
        summary["keywords"]["source"] = len(new_kws)
        if new_kws:
            for i in range(0, len(new_kws), 100):
                batch = new_kws[i:i + 100]
                indexed_batch = [(i + offset + 1, item) for offset, item in enumerate(batch)]
                res = _do_req("POST", api_key, secret_key, cid, "/ncc/keywords", params={"nccAdgroupId": new_adg_id}, json_body=batch)
                if res.status_code in [200, 201]:
                    classified = _classify_keyword_create_success_response(res, indexed_batch)
                    for result in classified:
                        if result.get("ok"):
                            summary["keywords"]["success"] += 1
                        else:
                            summary["keywords"]["fail"] += 1
                            errors.append(f"키워드 에러({result.get('name') or ''}): {result.get('detail') or '등록 실패'}")
                    continue

                if _looks_like_keyword_limit_error(getattr(res, "text", "")):
                    detail = _keyword_limit_error_detail(res.text)
                    summary["keywords"]["fail"] += len(batch)
                    errors.append(f"키워드 에러: {detail}")
                    continue

                for item in batch:
                    r_single = _do_req("POST", api_key, secret_key, cid, "/ncc/keywords", params={"nccAdgroupId": new_adg_id}, json_body=item)
                    if r_single.status_code in [200, 201]:
                        classified = _classify_keyword_create_success_response(r_single, [(1, item)])
                        result = classified[0] if classified else _result_item(1, True, str(item.get("keyword") or ""), "생성 완료")
                        if result.get("ok"):
                            summary["keywords"]["success"] += 1
                        else:
                            summary["keywords"]["fail"] += 1
                            errors.append(f"키워드 에러({result.get('name') or ''}): {result.get('detail') or '등록 실패'}")
                    else:
                        summary["keywords"]["fail"] += 1
                        errors.append(f"키워드 에러({item.get('keyword') or ''}): {_keyword_limit_error_detail(r_single.text)}")
    elif r_kw is not None and r_kw.status_code not in [200, 404]:
        errors.append(f"키워드 조회 에러: {r_kw.text}")
        summary["notes"].append("키워드 조회 실패")
    if include_ads:
        r_ad = _do_req("GET", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": old_adg_id})
    else:
        r_ad = None
    copied_ad_owner_pairs: List[Tuple[str, str]] = []
    if r_ad is not None and r_ad.status_code == 200:
        all_ads = [x for x in (r_ad.json() or []) if isinstance(x, dict)]
        skipped_off_ads = []
        ads = []
        for ad in all_ads:
            if _should_skip_off_copy_asset_with_detail(api_key, secret_key, cid, "ad", ad, exclude_off_assets):
                skipped_off_ads.append(ad)
            else:
                ads.append(ad)
        summary["ads"]["skipped_off"] = len(skipped_off_ads)
        summary["strategy"] = _classify_copy_ad_strategy(ads)
        summary["ads"]["source"] = len(ads)
        summary["ads"]["shopping_source"] = sum(1 for ad in ads if _normalize_ad_type(ad.get("type") or ad.get("adType")) in SHOPPING_AD_TYPES)
        summary["ads"]["standard_source"] = int(summary["ads"]["source"] or 0) - int(summary["ads"]["shopping_source"] or 0)
        target_signatures_before = _collect_ad_signatures(api_key, secret_key, cid, str(new_adg_id))
        expected_payloads: List[Dict[str, Any]] = []
        def _post_ad(ad):
            src_ad = ad if isinstance(ad, dict) else {}
            src_ad_id = _extract_ad_id(src_ad)
            item = _build_copy_ad_payload(api_key, secret_key, cid, src_ad, str(new_adg_id), force_on=force_on)
            ad_type = _normalize_ad_type(item.get("type"))
            if force_on:
                item["userLock"] = False
            else:
                item.setdefault("userLock", False)
            expected_payloads.append(copy.deepcopy(item))
            before_ids: set[str] = set()
            ref_key = _extract_reference_key_from_ad(src_ad) or str(item.get("referenceKey") or "").strip()
            if ad_type in SHOPPING_AD_TYPES:
                res_before, before_ads = _fetch_ads(api_key, secret_key, cid, str(new_adg_id))
                if res_before.status_code == 200:
                    before_ids = {_extract_ad_id(x) for x in (before_ads or []) if isinstance(x, dict) and _extract_ad_id(x)}
                res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": new_adg_id, "isList": "true"}, json_body=[item])
            else:
                res = _do_req("POST", api_key, secret_key, cid, "/ncc/ads", params={"nccAdgroupId": new_adg_id}, json_body=item)
            if res.status_code not in [200, 201]:
                ad_name = str(((item.get("ad") or {}).get("headline") if isinstance(item.get("ad"), dict) else "") or item.get("type") or "")
                return {"error": f"소재 에러({ad_name}): {res.text}", "source_ad_id": src_ad_id, "created_ad_id": ""}
            created_ad_id = _extract_created_ad_id_from_response(res)
            if not created_ad_id and ref_key:
                created_ad_id = _find_created_ad_id_by_reference(api_key, secret_key, cid, str(new_adg_id), ref_key, before_ids)
            if ad_type in SHOPPING_AD_TYPES and not created_ad_id:
                ad_name = str(item.get("type") or "쇼핑소재")
                return {"error": f"소재 에러({ad_name}): 생성 후 소재 ID 확인 실패", "source_ad_id": src_ad_id, "created_ad_id": ""}
            return {"error": None, "source_ad_id": src_ad_id, "created_ad_id": created_ad_id}
        with ThreadPoolExecutor(max_workers=5) as executor:
            futures = [executor.submit(_post_ad, ad) for ad in ads]
            for f in as_completed(futures):
                result = f.result() or {}
                err_msg = result.get("error")
                if err_msg:
                    summary["ads"]["fail"] += 1
                    errors.append(err_msg)
                    continue
                summary["ads"]["success"] += 1
                src_ad_id = str(result.get("source_ad_id") or "").strip()
                created_ad_id = str(result.get("created_ad_id") or "").strip()
                if src_ad_id and created_ad_id:
                    copied_ad_owner_pairs.append((src_ad_id, created_ad_id))
        target_signatures_after = _collect_ad_signatures(api_key, secret_key, cid, str(new_adg_id))
        missing_payloads = []
        for payload in expected_payloads:
            sig = _make_ad_signature(payload)
            if sig and sig not in target_signatures_after:
                missing_payloads.append(payload)
        if missing_payloads:
            retry_success, retry_errors = _retry_missing_ads(
                api_key, secret_key, cid, str(new_adg_id), missing_payloads,
                existing_signatures=(target_signatures_after or target_signatures_before),
            )
            summary["ads"]["success"] += int(retry_success or 0)
            summary["ads"]["fail"] += len(retry_errors)
            errors.extend(retry_errors)
            if retry_success:
                summary["notes"].append(f"누락 소재 재시도 성공: {retry_success}건")
    elif r_ad is not None and r_ad.status_code not in [200, 404]:
        errors.append(f"소재 조회 에러: {r_ad.text}")
        summary["notes"].append("소재 조회 실패")
    if include_extensions:
        r_ext = _do_req("GET", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": old_adg_id})
    else:
        r_ext = None
    if r_ext is not None and r_ext.status_code == 200:
        all_group_exts = []
        for x in (r_ext.json() or []):
            if not isinstance(x, dict):
                continue
            item = copy.deepcopy(x)
            item.setdefault("ownerId", old_adg_id)
            all_group_exts.append(item)
        skipped_off_group_exts = []
        group_exts = []
        for ext in all_group_exts:
            matches_type, _ = _copy_extension_matches_selected_types(ext, normalized_extension_types)
            if not matches_type:
                continue
            if _should_skip_off_copy_asset_with_detail(api_key, secret_key, cid, "ad_extension", ext, exclude_off_assets):
                skipped_off_group_exts.append(ext)
            else:
                group_exts.append(ext)
        summary["group_extensions"]["skipped_off"] = len(skipped_off_group_exts)
        summary["group_extensions"]["source"] = len(group_exts)
        for ext in group_exts:
            item = _build_copy_extension_payload(api_key, secret_key, cid, ext, str(new_adg_id), biz_channel_id, force_on=force_on)
            res = _do_req("POST", api_key, secret_key, cid, "/ncc/ad-extensions", params={"ownerId": new_adg_id}, json_body=item)
            if res.status_code not in [200, 201] and "4003" not in res.text:
                summary["group_extensions"]["fail"] += 1
                ext_type = _normalize_extension_type(item.get("type"))
                errors.append(f"확장소재 에러({ext_type}): {res.text}")
            else:
                summary["group_extensions"]["success"] += 1
    elif r_ext is not None and r_ext.status_code not in [200, 404]:
        errors.append(f"광고그룹 확장소재 조회 에러: {r_ext.text}")
        summary["notes"].append("광고그룹 확장소재 조회 실패")
    if include_extensions and copied_ad_owner_pairs:
        seen_owner_pairs = set()
        for old_owner_id, new_owner_id in copied_ad_owner_pairs:
            pair = (str(old_owner_id), str(new_owner_id))
            if not pair[0] or not pair[1] or pair in seen_owner_pairs:
                continue
            seen_owner_pairs.add(pair)
            child_errors, child_stats = _copy_ad_owner_extensions(
                api_key, secret_key, cid, pair[0], pair[1], biz_channel_id,
                exclude_off_assets=exclude_off_assets,
                force_on=force_on,
                extension_types=normalized_extension_types,
            )
            summary["ad_extensions"]["source"] += int(child_stats.get("source") or 0)
            summary["ad_extensions"]["success"] += int(child_stats.get("success") or 0)
            summary["ad_extensions"]["fail"] += int(child_stats.get("fail") or 0)
            summary["ad_extensions"]["skipped_off"] += int(child_stats.get("skipped_off") or 0)
            if child_errors:
                errors.extend(child_errors)
    if summary["ad_extensions"]["source"] < summary["ad_extensions"]["success"]:
        summary["ad_extensions"]["source"] = summary["ad_extensions"]["success"]
    if include_negatives:
        res_rk, rows_rk = _fetch_restricted_keywords(api_key, secret_key, cid, str(old_adg_id))
        if res_rk.status_code == 200 and rows_rk:
            post_rows = []
            for rk in rows_rk:
                if not isinstance(rk, dict):
                    continue
                kw = str(rk.get("keyword") or rk.get("restrictedKeyword") or "").strip()
                if not kw:
                    continue
                post_rows.append({
                    "nccAdgroupId": str(new_adg_id),
                    "customerId": int(cid),
                    "keyword": kw,
                    "type": _normalize_negative_type(rk.get("type") or rk.get("matchType") or 1),
                })
            summary["negatives"]["source"] = len(post_rows)
            if post_rows:
                neg_success, neg_fail, neg_results = _bulk_create_restricted_keywords(api_key, secret_key, cid, post_rows)
                summary["negatives"]["success"] = int(neg_success or 0)
                summary["negatives"]["fail"] = int(neg_fail or 0)
                if neg_fail > 0:
                    fail_msgs = [str(x.get("message") or "") for x in (neg_results or []) if not x.get("success")]
                    if fail_msgs:
                        errors.extend([f"제외검색어 에러: {msg}" for msg in fail_msgs[:10]])
                    else:
                        errors.append("제외검색어 에러: 일부 제외검색어 복사 실패")
        elif res_rk.status_code not in [200, 404]:
            errors.append(f"제외검색어 조회 에러: {res_rk.text}")
            summary["notes"].append("제외검색어 조회 실패")
    dedup_errors = list(dict.fromkeys([str(x) for x in errors if str(x).strip()]))
    if return_summary:
        return dedup_errors, summary
    return dedup_errors
def _extract_adgroup(src, target_camp_id, cid, biz_channel_id, force_on: bool = False):
    res = {
        "nccCampaignId": str(target_camp_id),
        "customerId": int(cid),
        "name": src.get("name"),
        "adgroupType": src.get("adgroupType"),
        "useDailyBudget": src.get("useDailyBudget", False),
        "dailyBudget": src.get("dailyBudget", 0),
        "bidAmt": src.get("bidAmt", 70),
    }
    adgroup_type = src.get("adgroupType", "")
    if biz_channel_id and biz_channel_id not in ["keep", "undefined"] and adgroup_type == "WEB_SITE":
        res["pcChannelId"] = res["mobileChannelId"] = str(biz_channel_id)
    else:
        if src.get("pcChannelId"):
            res["pcChannelId"] = str(src.get("pcChannelId"))
        if src.get("mobileChannelId"):
            res["mobileChannelId"] = str(src.get("mobileChannelId"))
    for k in [
        "useStoreUrl", "nccProductGroupId", "contentsNetworkBidAmt", "keywordPlusFlag",
        "contractId", "adgroupAttrJson", "pcNetworkBidWeight", "mobileNetworkBidWeight",
        "useCntsNetworkBidWeight", "contentsNetworkBidWeight", "useCntsNetworkBidAmt",
    ]:
        if k in src and src.get(k) is not None:
            res[k] = src[k]
    res = _copy_payload_preserve_source_state(res, src, force_on=force_on)
    if str(src.get("adgroupType") or "").upper() == "WEB_SITE":
        # 확장검색/예산비율은 광고그룹 생성 payload에도 최대한 포함하고,
        # 생성 후 _copy_adgroup_search_option_settings에서 한 번 더 검증/보정한다.
        for k in list(_EXPANDED_SEARCH_RESPONSE_KEYS) + list(_EXPANDED_SEARCH_BUDGET_RATIO_KEYS) + ["useKeywordPlus", "keywordPlusWeight", "useCloseVariant"]:
            if k in src and src.get(k) is not None:
                res[k] = src.get(k)
    return res
def _delete_entity_by_id(api_key: str, secret_key: str, cid: str, entity_type: str, entity_id: str):
    entity_id = str(entity_id or "").strip()
    if not entity_id:
        return _make_fake_response(400, "ID가 없습니다.")
    uri_map = {
        "campaign": f"/ncc/campaigns/{entity_id}",
        "adgroup": f"/ncc/adgroups/{entity_id}",
        "keyword": f"/ncc/keywords/{entity_id}",
        "ad": f"/ncc/ads/{entity_id}",
        "ad_extension": f"/ncc/ad-extensions/{entity_id}",
    }
    uri = uri_map.get(entity_type)
    if not uri:
        return _make_fake_response(400, f"지원하지 않는 삭제 유형: {entity_type}")
    return _do_req("DELETE", api_key, secret_key, cid, uri)

def _entity_id_from_row(entity_type: str, row: Dict[str, Any]) -> str:
    key_map = {
        "campaign": ["nccCampaignId", "캠페인ID", "campaign_id", "id"],
        "adgroup": ["nccAdgroupId", "광고그룹ID", "adgroup_id", "id"],
        "keyword": ["nccKeywordId", "키워드ID", "keyword_id", "id"],
        "ad": ["nccAdId", "소재ID", "ad_id", "id"],
        "ad_extension": ["adExtensionId", "nccAdExtensionId", "확장소재ID", "확장소재 ID", "ad_extension_id", "id"],
    }
    for key in key_map.get(entity_type, []):
        value = str((row or {}).get(key) or "").strip()
        if value:
            return value
    return ""

def _entity_detail_uri(entity_type: str, entity_id: str) -> str:
    return {
        "campaign": f"/ncc/campaigns/{entity_id}",
        "adgroup": f"/ncc/adgroups/{entity_id}",
        "keyword": f"/ncc/keywords/{entity_id}",
        "ad": f"/ncc/ads/{entity_id}",
        "ad_extension": f"/ncc/ad-extensions/{entity_id}",
    }.get(entity_type, "")

def _fetch_entity_snapshot(api_key: str, secret_key: str, cid: str, entity_type: str, entity_id: str) -> Dict[str, Any] | None:
    uri = _entity_detail_uri(entity_type, entity_id)
    if not uri:
        return None
    res = _do_req("GET", api_key, secret_key, cid, uri)
    if res.status_code != 200:
        return None
    try:
        obj = res.json()
    except Exception:
        return None
    if isinstance(obj, list):
        obj = next((x for x in obj if isinstance(x, dict)), None)
    return obj if isinstance(obj, dict) else None

def _delete_restore_payload(entity_type: str, snapshot: Dict[str, Any]) -> Dict[str, Any]:
    payload = copy.deepcopy(snapshot or {})
    readonly_keys = {
        "nccCampaignId", "nccAdgroupId", "nccKeywordId", "nccAdId", "adExtensionId", "nccAdExtensionId",
        "id", "regTm", "editTm", "status", "statusReason", "inspectStatus", "delFlag", "managedKeyword",
        "reviewStatus", "reviewStatusReason", "customerId",
    }
    for key in list(payload.keys()):
        if key in readonly_keys or str(key).startswith("_"):
            payload.pop(key, None)
    return payload

def _collect_delete_undo_snapshots(api_key: str, secret_key: str, cid: str, entity_type: str, rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    snapshots = []
    for row in rows or []:
        if entity_type == "restricted_keyword":
            adgroup_id = str((row or {}).get("nccAdgroupId") or (row or {}).get("광고그룹ID") or (row or {}).get("adgroup_id") or "").strip()
            keyword = str((row or {}).get("keyword") or (row or {}).get("제외키워드") or "").strip()
            if adgroup_id and keyword:
                snapshots.append({
                    "entity_type": entity_type,
                    "id": f"{adgroup_id}:{keyword}",
                    "snapshot": {
                        "nccAdgroupId": adgroup_id,
                        "keyword": keyword,
                        "type": (row or {}).get("type") or (row or {}).get("matchType") or "EXACT",
                    },
                })
            continue
        entity_id = _entity_id_from_row(entity_type, row)
        if not entity_id:
            continue
        snapshot = _fetch_entity_snapshot(api_key, secret_key, cid, entity_type, entity_id)
        if snapshot:
            snapshots.append({"entity_type": entity_type, "id": entity_id, "snapshot": snapshot})
    return snapshots

def _make_undo_operation(kind: str, body: Dict[str, Any], label: str) -> Dict[str, Any]:
    return {"kind": kind, "url": f"/{kind}", "body": body, "label": label}

def _delete_undo_operation(api_key: str, secret_key: str, cid: str, snapshots: List[Dict[str, Any]]) -> Dict[str, Any] | None:
    if not snapshots:
        return None
    return _make_undo_operation(
        "restore_deleted",
        {"api_key": api_key, "secret_key": secret_key, "customer_id": cid, "snapshots": snapshots},
        "삭제 전 상태로 재등록",
    )

@app.route("/restore_budget", methods=["POST"])
def restore_budget():
    d = request.json or {}
    api_key, secret_key, cid = d.get("api_key"), d.get("secret_key"), d.get("customer_id")
    items = d.get("items") or []
    if not api_key or not secret_key or not cid:
        return jsonify({"error": "API Key / Secret Key / Customer ID가 필요합니다."}), 400
    success = fail = 0
    results = []
    for idx, item in enumerate(items, start=1):
        entity_type = str((item or {}).get("entity_type") or "").strip().lower()
        entity_id = str((item or {}).get("id") or "").strip()
        use_daily_budget = _normalize_bool_for_api((item or {}).get("use_daily_budget"), False)
        try:
            budget = int(float((item or {}).get("daily_budget") or 0))
        except Exception:
            budget = 0
        uri = f"/ncc/campaigns/{entity_id}" if entity_type == "campaign" else f"/ncc/adgroups/{entity_id}" if entity_type == "adgroup" else ""
        if not uri:
            fail += 1
            results.append(_result_item(idx, False, entity_id or f"{idx}행", "지원하지 않는 예산 복구 대상입니다."))
            continue
        r_get = _do_req("GET", api_key, secret_key, cid, uri)
        if r_get.status_code != 200:
            fail += 1
            results.append(_result_item(idx, False, entity_id, f"조회 실패: {_response_detail_text(r_get)}"))
            continue
        obj = r_get.json() or {}
        obj["useDailyBudget"] = bool(use_daily_budget)
        obj["dailyBudget"] = budget if use_daily_budget else 0
        obj.pop("budget", None)
        r_put = _do_req("PUT", api_key, secret_key, cid, uri, params={"fields": "budget"}, json_body=obj)
        if r_put.status_code in [200, 201, 204]:
            success += 1
            label = "제한없음" if not use_daily_budget else f"{budget:,}원"
            results.append(_result_item(idx, True, entity_id, f"예산 {label} 복구 완료"))
        else:
            fail += 1
            results.append(_result_item(idx, False, entity_id, f"복구 실패: {_response_detail_text(r_put)}"))
    _cache_invalidate(api_key, secret_key, cid)
    return jsonify({"ok": fail == 0 and success > 0, "total": len(items), "success": success, "fail": fail, "results": results, "message": f"예산 되돌리기 완료 (성공 {success} / 실패 {fail})"}), (200 if success > 0 else 400)

@app.route("/restore_deleted", methods=["POST"])
def restore_deleted():
    d = request.json or {}
    api_key, secret_key, cid = d.get("api_key"), d.get("secret_key"), d.get("customer_id")
    snapshots = d.get("snapshots") or []
    if not api_key or not secret_key or not cid:
        return jsonify({"error": "API Key / Secret Key / Customer ID가 필요합니다."}), 400
    success = fail = 0
    results = []
    endpoint_map = {
        "campaign": "/ncc/campaigns",
        "adgroup": "/ncc/adgroups",
        "keyword": "/ncc/keywords",
        "ad": "/ncc/ads",
        "ad_extension": "/ncc/ad-extensions",
    }
    for idx, item in enumerate(snapshots, start=1):
        entity_type = str((item or {}).get("entity_type") or "").strip().lower()
        snapshot = (item or {}).get("snapshot") if isinstance((item or {}).get("snapshot"), dict) else {}
        if entity_type == "restricted_keyword":
            if not snapshot:
                fail += 1
                results.append(_result_item(idx, False, str((item or {}).get("id") or idx), "복구 스냅샷이 없습니다."))
                continue
            rk_success, rk_fail, rk_results = _bulk_create_restricted_keywords(api_key, secret_key, cid, [snapshot])
            if rk_success > 0 and rk_fail == 0:
                success += 1
                results.append(_result_item(idx, True, str((item or {}).get("id") or idx), "재등록 완료"))
            else:
                fail += 1
                detail = "; ".join(str((x or {}).get("detail") or "") for x in (rk_results or []) if (x or {}).get("detail")) or "재등록 실패"
                results.append(_result_item(idx, False, str((item or {}).get("id") or idx), detail))
            continue
        endpoint = endpoint_map.get(entity_type)
        if not endpoint or not snapshot:
            fail += 1
            results.append(_result_item(idx, False, str((item or {}).get("id") or idx), "복구 스냅샷이 없습니다."))
            continue
        payload = _delete_restore_payload(entity_type, snapshot)
        try:
            payload.setdefault("customerId", int(cid))
        except Exception:
            payload.setdefault("customerId", cid)
        params = None
        json_body: Any = payload
        if entity_type in {"keyword", "ad"}:
            adgroup_id = str(snapshot.get("nccAdgroupId") or snapshot.get("adgroupId") or "").strip()
            params = {"nccAdgroupId": adgroup_id} if adgroup_id else None
            if entity_type == "keyword":
                json_body = [payload]
            elif str(payload.get("type") or "").strip() in SHOPPING_AD_TYPES:
                params = {**(params or {}), "isList": "true"}
                json_body = [payload]
        elif entity_type == "ad_extension":
            owner_id = str(snapshot.get("ownerId") or snapshot.get("nccAdgroupId") or snapshot.get("nccAdId") or "").strip()
            params = {"ownerId": owner_id} if owner_id else None
        res = _do_req("POST", api_key, secret_key, cid, endpoint, params=params, json_body=json_body)
        if res.status_code in [200, 201, 204]:
            success += 1
            results.append(_result_item(idx, True, str((item or {}).get("id") or idx), "재등록 완료"))
        else:
            fail += 1
            results.append(_result_item(idx, False, str((item or {}).get("id") or idx), f"재등록 실패: {_response_detail_text(res)}"))
    _cache_invalidate(api_key, secret_key, cid)
    return jsonify({"ok": fail == 0 and success > 0, "total": len(snapshots), "success": success, "fail": fail, "results": results, "message": f"삭제 되돌리기 완료 (재등록 성공 {success} / 실패 {fail})"}), (200 if success > 0 else 400)
def _delete_failure_detail(res, entity_type: str = "") -> str:
    status = getattr(res, "status_code", None)
    raw = str(getattr(res, "text", "") or "").strip()
    if not raw:
        raw = "삭제 실패"
    try:
        status_int = int(status)
    except Exception:
        status_int = 0
    prefix = f"HTTP {status_int} | " if status_int >= 400 else ""
    label = {
        "campaign": "캠페인",
        "adgroup": "광고그룹",
        "keyword": "키워드",
        "ad": "소재",
        "ad_extension": "확장소재",
        "restricted_keyword": "제외키워드",
    }.get(str(entity_type or "").strip(), "대상")
    if "네트워크 통신 실패" in raw:
        # 기존에는 '알 수 없는 오류'만 노출되어 원인 판단이 어려웠다.
        # 재시도 후에도 통신 계층에서 실패한 경우임을 명확히 알려준다.
        return (
            f"{prefix}{raw} | 네이버 삭제 API 재시도 후에도 응답을 받지 못했습니다. "
            f"같은 ID로 다시 실행해도 반복되면 API Key/Secret/Customer ID가 해당 {label}의 광고계정과 일치하는지 확인해주세요."
        )
    if status_int == 404:
        return f"{prefix}{raw} | {label}이 이미 삭제되었거나 현재 Customer ID에서 조회되지 않는 ID일 수 있습니다."
    if status_int == 403:
        return f"{prefix}{raw} | 현재 API 권한으로 삭제할 수 없는 {label}일 수 있습니다."
    return f"{prefix}{raw}"
@app.route("/")
def index():
    accounts = []
    csv_path = os.path.join(BASE_DIR, "accounts.csv")
    if os.path.exists(csv_path):
        try:
            df = pd.read_csv(csv_path, encoding="utf-8-sig")
        except Exception:
            df = pd.read_csv(csv_path, encoding="cp949")
        cols = {c.lower().strip(): c for c in df.columns}
        cid_col = cols.get("customer_id") or cols.get("customerid") or df.columns[0]
        name_col = cols.get("account_name") or cols.get("name") or (df.columns[1] if len(df.columns) > 1 else df.columns[0])
        df2 = df[[cid_col, name_col]].copy()
        df2.columns = ["customer_id", "account_name"]
        df2["customer_id"] = df2["customer_id"].apply(normalize_customer_id)
        df2["account_name"] = df2["account_name"].astype(str).str.strip()
        accounts = df2.to_dict(orient="records")
    favicon_path = os.path.join(app.static_folder or os.path.join(BASE_DIR, "static"), "favicon", "favicon.ico")
    favicon_version = int(os.path.getmtime(favicon_path)) if os.path.exists(favicon_path) else 0
    auth_defaults = {
        "api_key": normalize_openapi_credential(os.getenv("NAVER_API_KEY", "")),
        "secret_key": normalize_openapi_credential(os.getenv("NAVER_SECRET_KEY", "")),
        "customer_id": normalize_customer_id(os.getenv("NAVER_CUSTOMER_ID", "")),
    }
    return render_template("index.html", accounts=accounts, favicon_version=favicon_version, auth_defaults=auth_defaults)

